    public class PowerBeam : StoneAbility, Messages.IUse
    {
        AudioSource Source;
        bool Lasering;

        RaycastHit2D hit;

        public LineRenderer line;
        public TrailRenderer trail;
        public GameObject RaycastPoint;
        public GameObject RaycastPoint2;
        public float blastRadius = 25f;
        public float maxForce = 15f;
        public float crushRadius = 50f;

        Vector3 offset;

        public void Start()
        {
            line = gameObject.AddComponent<LineRenderer>();
            line.startColor = new Color(0.5f, 0.1f, 0.7f, 0.5f);
            line.endColor = new Color(0.5f, 0.1f, 0.7f, 0.5f);
            line.startWidth = 0.2f;
            line.endWidth = 0.2f;
            line.material = UnityEngine.Object.Instantiate<Material>(ModAPI.FindMaterial("VeryBright"));
            line.material.SetFloat("_GlowIntensity", 0.05f);
            line.material.mainTexture = ModAPI.FindMaterial("Sprites-Default").mainTexture;
            line.sortingOrder = gameObject.GetComponent<SpriteRenderer>().sortingOrder + 1;
            line.sortingLayerID = gameObject.GetComponent<SpriteRenderer>().sortingLayerID;
            line.positionCount = 2;
            line.enabled = false;

            trail = new GameObject("trail").AddComponent<TrailRenderer>();
            trail.transform.parent = transform;
            trail.transform.localPosition = (new Vector3(0, -8f, 0) * ModAPI.PixelSize) + offset;
            trail.transform.localRotation = Quaternion.identity;
            trail.transform.localScale = Vector3.one;
            trail.gameObject.layer = gameObject.layer;
            trail.time = 0.1f;
            trail.startWidth = 0.02f;
            trail.endWidth = 0.005f;
            trail.material = UnityEngine.Object.Instantiate<Material>(ModAPI.FindMaterial("VeryBright"));
            trail.startColor = new Color(0.5f, 0.1f, 0.8f, 0.2f);
            trail.endColor = new Color(0, 0, 0, 0);
            trail.sortingLayerName = gameObject.GetComponent<SpriteRenderer>().sortingLayerName;
            trail.sortingOrder = gameObject.GetComponent<SpriteRenderer>().sortingOrder - 1;
            trail.enabled = false;

            Source = gameObject.AddComponent<AudioSource>();
            Source.loop = true;
            Source.clip = Mod.Laser;

            if (!gameObject.GetComponent<AudioSourceTimeScaleBehaviour>())
            {
                gameObject.AddComponent<AudioSourceTimeScaleBehaviour>();
            }else
            {
                Destroy(gameObject.GetComponent<AudioSourceTimeScaleBehaviour>());
                gameObject.AddComponent<AudioSourceTimeScaleBehaviour>();
            }

                RaycastPoint = new GameObject("RaycastPoint");
            RaycastPoint.transform.parent = transform;
            RaycastPoint.transform.localPosition = (new Vector2(0, -8) * ModAPI.PixelSize) + (Vector2)offset;
            RaycastPoint.transform.localRotation = Quaternion.identity;
            RaycastPoint2 = new GameObject("RaycastPoint2");
            RaycastPoint2.transform.parent = transform;
            RaycastPoint2.transform.localPosition = (new Vector2(0, -8) * ModAPI.PixelSize) + (Vector2)offset;
            RaycastPoint2.transform.localRotation = Quaternion.identity;
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            line.endWidth = 0.025f;

            if (!Lasering)
            {
                line.enabled = true;
                StartCoroutine(RendererColorTransition(line, new Color(0.5f, 0f, 0.8f, 1f), Color.clear, 0.1f));
                Source.Play();
                Lasering = true;
                trail.enabled = true;
                StartCoroutine(PlaySound(Mod.LaserStart));
            }
            else
            {
                Source.Stop();

                StartCoroutine(RendererColorTransition(line, Color.clear, new Color(0.5f, 0f, 0.8f, 1f), 0.25f));

                line.enabled = false;
                Lasering = false;
                trail.enabled = false;
                StartCoroutine(PlaySound(Mod.LaserEnd));
            }
        }

        public override void DisablePower()
        {
            Source.Stop();
            if (Lasering)
            {
                Source.Stop();

                StartCoroutine(RendererColorTransition(line, Color.clear, new Color(0.5f, 0f, 0.8f, 1f), 0.25f));

                line.enabled = false;
                Lasering = false;
                trail.enabled = false;
                StartCoroutine(PlaySound(Mod.LaserEnd));
            }

            base.DisablePower();
        }

        public IEnumerator RendererColorTransition(Renderer renderer, Color newColor, Color OriginalColor, float duration = 0.5f)
        {
            if (renderer.GetType() == typeof(SpriteRenderer))
            {
                var sr = renderer as SpriteRenderer;

                float elapsedTime = 0;
                while (elapsedTime < duration)
                {
                    sr.color = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    elapsedTime += Time.deltaTime;
                    yield return null;
                }
                sr.color = newColor;
            }
            else if (renderer.GetType() == typeof(LineRenderer))
            {
                var l = renderer as LineRenderer;

                float elapsedTime = 0;
                while (elapsedTime < duration)
                {
                    l.startColor = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    l.endColor = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    elapsedTime += Time.deltaTime;
                    yield return null;
                }
                l.startColor = newColor;
                l.endColor = newColor;

            }
        }

        private IEnumerator PlaySound(AudioClip SoundToPlay)
        {
            var sound = new GameObject();
            sound.name = "SFX";
            sound.transform.position = gameObject.transform.position;
            sound.AddComponent<AudioSource>();
            sound.GetComponent<AudioSource>().playOnAwake = false;
            sound.GetComponent<AudioSource>().clip = SoundToPlay;
            sound.GetComponent<AudioSource>().spatialBlend = 1;
            sound.GetComponent<AudioSource>().volume = 5f;
            sound.AddComponent<AudioDistortionFilter>().distortionLevel = 0.85f;
            sound.AddComponent<AudioSourceTimeScaleBehaviour>();
            sound.GetComponent<AudioSource>().Play();
            sound.AddComponent<OBJDestroyer>();
            yield return new WaitForSeconds(SoundToPlay.length);

            Destroy(sound);
        }

        public void Update()
        {
            if (!Enabled || !Lasering)
                return;

            var hits = Physics2D.RaycastAll(RaycastPoint2.transform.position, -RaycastPoint.transform.up, 200000, LayerMask.GetMask(new string[] { "Objects", "Bounds" }));

            foreach (var hitt in hits)
            {
                if (hitt.collider != null && hitt.collider.transform.root != transform.root)
                {
                    hit = hitt;
                    break;
                }
            }

            if (Lasering)
            {
                line.SetPosition(0, RaycastPoint.transform.position);
                line.SetPosition(1, hit.point);
            }
        }

        public void FixedUpdate()
        {
            if (!Enabled)
                return;

            Vector2 hitPoint = hit.point;

            if (Lasering)
            {
                line.startWidth = UnityEngine.Random.Range(0.15f, 0.25f);
                line.endWidth = UnityEngine.Random.Range(0.15f, 0.25f);

                if (hit.collider != null)
                {
                    if (hit.collider != null && hit.collider.transform.root != transform.root)
                    {
                        hit.rigidbody.AddForce(-transform.up * 150, ForceMode2D.Force);

                        if (hit.collider.TryGetComponent<PhysicalBehaviour>(out var ph))
                            ph.charge += 0.01f;

                        if (hit.collider.TryGetComponent<LimbBehaviour>(out var limb))
                        {
                            if (limb.ImpactDamageMultiplier < 2 && !limb.ImmuneToDamage && limb.PhysicalBehaviour.rigidbody.mass > 0.1f && limb.Health < limb.InitialHealth / 20)
                                limb.Crush();

                            limb.Damage(limb.InitialHealth / 20);
                            
                            foreach (var limbb in limb.SkinMaterialHandler.adjacentLimbs)
                            {
                                limbb.limb.Damage(limb.InitialHealth / 40);
                            }

                            limb.SkinMaterialHandler.AddDamagePoint(DamageType.Bullet, hit.point, UnityEngine.Random.Range(1, 50));
                        }

                        if (hit.collider.TryGetComponent<DestroyableBehaviour>(out var des))
                            des.Break();
                    }
                }

                CameraShakeBehaviour.main.Shake(0.4f, transform.position);
            }
        }
    }

    public class FakeoutDeath : StoneAbility
    {
        bool FakingIt = false;

        bool diddead;

        PersonBehaviour person;

        public void Use(ActivationPropagation activation)
        {
            person = transform.root.GetComponent<PersonBehaviour>();

            if (!Enabled || !person || !person.IsAlive() || person.Braindead)
                return;

            FakingIt = true;

            if (transform.root.TryGetComponent<SpeedHealing>(out var heal))
                heal.DisablePower();
            else if (transform.root.TryGetComponent<SpeedHealing>(out var sheal))
                sheal.DisablePower();

            foreach (var limb in transform.parent.parent.GetComponentsInChildren<LimbBehaviour>())
            {
                limb.SkinMaterialHandler.AcidProgress += GetComponent<InfinityGauntlet>().Nanotech ? .7f : .6f;
            }

            transform.root.GetComponent<PersonBehaviour>().Limbs[1].SkinMaterialHandler.AcidProgress += GetComponent<InfinityGauntlet>().Nanotech ? .85f : .7f;

            foreach (var limb in person.Limbs)
            {
                var f = ModAPI.CreateParticleEffect("Flash", limb.transform.position).GetComponent<ParticleSystem>();

                var main = f.main;
                main.startColor = Color.red;
                f.startColor = Color.red;
                foreach (var pf in f.GetComponentsInChildren<ParticleSystem>())
                {
                    pf.startColor = Color.red;
                    var mainpf = pf.main;
                    mainpf.startColor = Color.red;
                }
            }
        }

        public void Start()
        {
            person = GetComponent<PersonBehaviour>();
        }

        public void FixedUpdate()
        {
            if (!person.IsAlive())
            {
                if (!diddead)
                {
                    diddead = true;
                    if (FakingIt)
                    {
                        foreach (var limb in person.Limbs)
                        {
                            var f = ModAPI.CreateParticleEffect("Flash", limb.transform.position).GetComponent<ParticleSystem>();

                            var main = f.main;
                            main.startColor = Color.red;
                            f.startColor = Color.red;
                            foreach (var pf in f.GetComponentsInChildren<ParticleSystem>())
                            {
                                pf.startColor = Color.red;
                                var mainpf = pf.main;
                                mainpf.startColor = Color.red;
                            }

                            limb.CirculationBehaviour.AddLiquid(Liquid.GetLiquid(LifeSyringe.LifeSerumLiquid.ID), 1);
                        }
                    }
                }
            }
            else
            {
                diddead = false;
            }
        }

    }

    public class PowerPunch : StoneAbility
    {
        void OnCollisionEnter2D(Collision2D collision)
        {
            if (!Enabled || !transform.root.GetComponent<PersonBehaviour>())
                return;

            Vector2 relativeVelocity = collision.relativeVelocity;

            float impactStrength = relativeVelocity.magnitude * 2;

            if (collision.gameObject.GetComponent<Rigidbody2D>() && collision.relativeVelocity.magnitude > 3)
            {
                Vector2 directionToThisObject = (GetComponent<Rigidbody2D>().position - collision.rigidbody.position).normalized;

                float dotProduct = Vector2.Dot(relativeVelocity, directionToThisObject);

                if (dotProduct > 0)
                {
                    collision.gameObject.GetComponent<Rigidbody2D>().velocity += -relativeVelocity.normalized * impactStrength;
                    var emp = Instantiate(ModAPI.FindSpawnable("EMP Generator").Prefab.GetComponent<EMPBehaviour>().Effect);
                    ModAPI.CreateParticleEffect("Explosion", collision.contacts[0].point);
                    emp.transform.position = transform.position;
                    emp.transform.localScale = Vector3.one * (0.1f);
                    var main = emp.GetComponent<ParticleSystem>().main;
                    //main.startColor = color;
                    var n = main.startLifetime;
                    n.constantMax *= 0.5f;
                    main.simulationSpeed *= 1.5f;
                    foreach (var childPFX in emp.GetComponentsInChildren<ParticleSystem>())
                        if (childPFX != emp.GetComponent<ParticleSystem>())
                            childPFX.startColor = Mod.ColorPlus.Purple;

                    if (collision.gameObject.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        limb.Damage(collision.relativeVelocity.magnitude);
                        if (limb.Health < 0.075f && !limb.ImmuneToDamage)
                            limb.Crush();
                    }
                }

            }
        }
    }

    public class SpaceTeleport : StoneAbility, Messages.IUse
    {
        public Teleportation teleportation;

        public void Start()
        {
            var teleportthing = new GameObject("teleportHandler" + UnityEngine.Random.Range(0, 200000));
            teleportthing.AddComponent<Teleportation>().person = transform.root.GetComponent<PersonBehaviour>();
            teleportthing.GetComponent<Teleportation>().obj = transform.root.gameObject;

            teleportation = teleportthing.GetComponent<Teleportation>();
        }

        public void Use(ActivationPropagation activation)
        {
            teleportation.person = transform.root.GetComponent<PersonBehaviour>();

            if (Enabled)
                teleportation.Use();
        }

        public class Teleportation : MonoBehaviour
        {
            public bool teleporting;
            public PersonBehaviour person;
            public GameObject obj;
            public GameObject Smoke;

            public void Start()
            {
                Smoke = Instantiate(ModAPI.FindSpawnable("Particle Projector").Prefab.transform.GetChild(0).gameObject);
                var pfx = Smoke.GetComponent<ParticleSystem>();
                pfx.playOnAwake = false;
                pfx.Stop();
                pfx.gravityModifier = 0;
                pfx.startSpeed = 0;
                pfx.startColor = new Color(0.7f, 0.7f, 1f, 0.102f);
            }

            public void Use()
            {
                var tp = Instantiate(ABloader.LoadFromAB<GameObject>(ABloader.LoadFromFile("AssetBundles/portal"), "Teleport"));
                tp.gameObject.AddComponent<DeleteAfterTime>().Life = 10;

                tp.transform.position = person ? person.Limbs[2].transform.position : obj.transform.position;

                CameraShakeBehaviour.main.Shake(1, person ? person.Limbs[0].transform.position : obj.transform.position);

                Smoke.GetComponent<ParticleSystem>().Play();
                
                if (person)
                {
                    foreach (var limb in person.Limbs)
                    {
                        if (limb.Joint)
                            limb.Joint.autoConfigureConnectedAnchor = false;
                    }

                    person.gameObject.SetActive(false);

                    var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Clone)");

                    foreach (var status in limbStatusObjects)
                    {
                        foreach (var limb in person.Limbs)
                        {
                            if (status.GetComponent<LimbStatusBehaviour>().limb == limb)
                            {
                                status.GetComponent<LimbStatusBehaviour>().enabled = false;
                                var color = status.GetComponent<SpriteRenderer>().color;
                                status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 0);
                                var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                                status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 0);
                            }
                        }
                    }
                }
                else
                {
                    obj.SetActive(false);
                }

                teleporting = true;
            }

            public void Update()
            {
                Vector3 mouseScreenPosition = Input.mousePosition;
                Smoke.transform.position = Camera.main.ScreenToWorldPoint(new Vector3(mouseScreenPosition.x, mouseScreenPosition.y, Camera.main.nearClipPlane));

                if (Input.GetKey(KeyCode.Mouse0) && teleporting)
                {
                    teleporting = false;
                    Smoke.GetComponent<ParticleSystem>().Stop();
                    CameraShakeBehaviour.main.Shake(1, person ? person.Limbs[0].transform.position : obj.transform.position);
                    Vector3 mouseWorldPosition = Camera.main.ScreenToWorldPoint(new Vector3(mouseScreenPosition.x, mouseScreenPosition.y, Camera.main.nearClipPlane));

                    var tp = Instantiate(ABloader.LoadFromAB<GameObject>(ABloader.LoadFromFile("AssetBundles/portal"), "Teleport"));
                    tp.gameObject.AddComponent<DeleteAfterTime>().Life = 10;

                    tp.transform.position = mouseWorldPosition;

                    if (person)
                    {
                        foreach (var limb in person.Limbs)
                        {
                            Vector3 newPosition = new Vector3(mouseWorldPosition.x, mouseWorldPosition.y, limb.transform.position.z);
                            limb.transform.position = newPosition;

                            if (limb.TryGetComponent<HatBehaviour.HasHat>(out var hatt))
                            {
                                var hat = hatt.hat;
                                Destroy(hatt);
                                hat.Wear(limb);
                            }
                        }

                        person.gameObject.SetActive(true);

                        foreach (var limb in person.GetComponentsInChildren<Collider2D>())
                        {
                            foreach (var limb2 in person.GetComponentsInChildren<Collider2D>())
                            {
                                foreach (AudioSource aud in limb.GetComponents<AudioSource>())
                                    aud.Stop();
                                Physics2D.IgnoreCollision(limb.GetComponent<Collider2D>(), limb2.GetComponent<Collider2D>());
                            }
                        }

                        var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Clone)");

                        foreach (var status in limbStatusObjects)
                        {
                            foreach (var limb in person.Limbs)
                            {
                                if (status.GetComponent<LimbStatusBehaviour>().limb == limb)
                                {
                                    status.GetComponent<LimbStatusBehaviour>().enabled = true;
                                    var color = status.GetComponent<SpriteRenderer>().color;
                                    status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 1);
                                    var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                                    status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 1);
                                }
                            }
                        }
                    }
                    else
                    {
                        obj.transform.position = mouseWorldPosition;
                        obj.SetActive(true);
                    }
                }
            }

        }
    }

    public class InfinityGauntlet : MonoBehaviour, Mod.ModAPIPlus.ISwap
    {
        public enum StoneAbilityEnum
        {
            Space,
            Mind,
            Reality,
            Power,
            Time,
            Soul,
            All
        }

        public static GameObject MenuPrefab;

        public GameObject Menu;

        PhysicalBehaviour _physicalBehaviour;

        GameObject contextMenu;

        public Collider2D triggerCol;
        public FixedJoint2D Joint;

        private bool _cooldownActive;
        private float _cooldownEndTime;

        public bool HasSpace;
        public bool HasMind;
        public bool HasReality;
        public bool HasPower;
        public bool HasTime;
        public bool HasSoul;

        public SpriteRenderer GlowSpace;
        public SpriteRenderer GlowMind;
        public SpriteRenderer GlowReality;
        public SpriteRenderer GlowPower;
        public SpriteRenderer GlowTime;
        public SpriteRenderer GlowSoul;

        public bool Nanotech = false;

        public void Awake()
        {
            Menu = Instantiate(MenuPrefab);

            Menu.SetActive(false);
            Menu.transform.SetParent(GameObject.Find("Canvas").transform, false);
            Menu.transform.localScale = Vector3.one;

            Menu.transform.FindChild("SV").GetComponent<ScrollRect>().vertical = true;
            Menu.transform.FindChild("SV").GetComponent<ScrollRect>().verticalScrollbarVisibility = ScrollRect.ScrollbarVisibility.Permanent;

            Menu.transform.FindChild("SV/Close (1)").GetComponent<Button>().onClick.AddListener(() =>
            {
                Menu.transform.FindChild("SV").gameObject.SetActive(false);
            });

            Menu.transform.FindChild("Close").GetComponent<Button>().onClick.AddListener(() =>
            {
                Menu.SetActive(false);
            });

            foreach (var but in Menu.transform.FindChild("Stones").GetComponentsInChildren<Button>())
            {
                but.interactable = false;

                but.onClick.AddListener(() => 
                {
                    Menu.transform.FindChild("SV").gameObject.SetActive(true);
                    
                    for (int i = 0; i < Menu.transform.FindChild("SV/VP/Content").childCount; i++)
                    {
                        var child = Menu.transform.FindChild("SV/VP/Content").GetChild(i);
                        
                        if (child.name.Contains(but.name))
                            child.gameObject.SetActive(true);
                        else
                            child.gameObject.SetActive(false);
                    }
                });
            }

            _physicalBehaviour = GetComponent<PhysicalBehaviour>();
            var rb = GetComponent<Rigidbody2D>();
            rb.mass = 1f;

            var col = GetComponent<Collider2D>();
            if (col) Destroy(col);
            gameObject.GetOrAddComponent<PolygonCollider2D>();
            Timtam.CreateCollider(GetComponent<SpriteRenderer>());

            _physicalBehaviour.ContextMenuOptions.Buttons.Add(new ContextMenuButton(() => !ColorpickerDialogBehaviour.IsOpen, "StoneMenu", "<color=\"yellow\">Gauntlet Menu", "<color=\"blue\">Gauntlet Menu", delegate
            {
                EnableMenu();
            }));

        }

        public void EnableMenu()
        {
            Menu.SetActive(true);
        }

        public void Swap()
        {
            if (Joint)
            {
                foreach (var col in Joint.connectedBody.transform.root.GetComponentsInChildren<Collider2D>())
                {
                    foreach (var ocol in GetComponents<Collider2D>())
                    {
                        Physics2D.IgnoreCollision(col, ocol, false);
                    }
                }

                Destroy(Joint);
            }

            transform.parent = null;
            var rb = GetComponent<Rigidbody2D>();
            rb.mass = 0.1f;

            // Start 2 second cooldown before it can be worn again
            _cooldownActive = true;
            _cooldownEndTime = Time.time + 2f;
        }

        public void AddAbility(Type ability, StoneAbilityEnum abilityEnum, string AbilityName, string AbilityDescription, Sprite thumbnail = null)
        {
            var buttonObj = Instantiate(Menu.transform.GetChild(3).GetChild(0).GetChild(0).GetChild(0).gameObject);
            buttonObj.name = AbilityName + abilityEnum.ToString();
            buttonObj.transform.SetParent(Menu.transform.GetChild(3).GetChild(0).GetChild(0), false);
            buttonObj.transform.FindChild("Thumb").GetComponentInChildren<Image>().sprite = thumbnail;
            buttonObj.transform.FindChild("Info/Title").GetComponentInChildren<TextMeshProUGUI>().text = AbilityName;
            buttonObj.transform.FindChild("Info/Description").GetComponentInChildren<TextMeshProUGUI>().text = AbilityDescription;

            foreach (var but in buttonObj.GetComponentsInChildren<Button>(true))
            {
                but.onClick.AddListener(() =>
                {
                    SetAbility(ability, abilityEnum);
                });
            }
        }

        public void SetAbility(Type ability, StoneAbilityEnum typ)
        {
            if (Menu != null)
            {
                Menu.SetActive(false);
            }

            Color glowColor = new Color(1f, 1f, 1f, 0.1f);
            Color clearColor = Color.clear;

            if (GlowSpace != null) GlowSpace.color = clearColor;
            if (GlowMind != null) GlowMind.color = clearColor;
            if (GlowReality != null) GlowReality.color = clearColor;
            if (GlowPower != null) GlowPower.color = clearColor;
            if (GlowTime != null) GlowTime.color = clearColor;
            if (GlowSoul != null) GlowSoul.color = clearColor;

            switch (typ)
            {
                case StoneAbilityEnum.Space:
                    if (GlowSpace != null) GlowSpace.color = glowColor;
                    break;
                case StoneAbilityEnum.Mind:
                    if (GlowMind != null) GlowMind.color = glowColor;
                    break;
                case StoneAbilityEnum.Reality:
                    if (GlowReality != null) GlowReality.color = glowColor;
                    break;
                case StoneAbilityEnum.Power:
                    if (GlowPower != null) GlowPower.color = glowColor;
                    break;
                case StoneAbilityEnum.Time:
                    if (GlowTime != null) GlowTime.color = glowColor;
                    break;
                case StoneAbilityEnum.Soul:
                    if (GlowSoul != null) GlowSoul.color = glowColor;
                    break;
                case StoneAbilityEnum.All:
                    if (GlowSpace != null) GlowSpace.color = glowColor;
                    if (GlowMind != null) GlowMind.color = glowColor;
                    if (GlowReality != null) GlowReality.color = glowColor;
                    if (GlowPower != null) GlowPower.color = glowColor;
                    if (GlowTime != null) GlowTime.color = glowColor;
                    if (GlowSoul != null) GlowSoul.color = glowColor;
                    break;
            }

            foreach (var a in GetComponents<StoneAbility>())
            {
                a.DisablePower();
            }

            StoneAbility selectedAbility;
            if (TryGetComponent(ability, out var existing))
            {
                selectedAbility = existing as StoneAbility;
            }
            else
            {
                selectedAbility = gameObject.AddComponent(ability) as StoneAbility;
            }

            if (selectedAbility != null)
            {
                selectedAbility.EnablePower();
            }

            if (transform.parent != null)
            {
                foreach (var limb in transform.parent.parent.GetComponentsInChildren<LimbBehaviour>())
                {
                    limb.SkinMaterialHandler.AcidProgress += Nanotech ? .1f : .02f;
                }

                transform.root.GetComponent<PersonBehaviour>().Limbs[1].SkinMaterialHandler.AcidProgress += Nanotech ? .07f : .01f;
            }
        }

        private SpriteRenderer CreateStone(string rootName, string glowName, Sprite sprite)
        {
            if (sprite == null)
            {
                Debug.LogWarning("[InfinityGauntlet] Missing sprite for stone: " + rootName);
            }

            var root = new GameObject(rootName);
            root.transform.parent = transform;
            root.transform.localPosition = Vector3.zero;
            root.transform.localScale = Vector3.one;
            root.transform.localRotation = Quaternion.identity;

            var baseSr = root.AddComponent<SpriteRenderer>();
            var ownerSr = GetComponent<SpriteRenderer>();
            if (ownerSr != null)
            {
                baseSr.sortingLayerName = ownerSr.sortingLayerName;
                baseSr.sortingOrder = ownerSr.sortingOrder + 1;
            }
            baseSr.sprite = sprite;

            var glow = new GameObject(glowName);
            glow.transform.parent = root.transform;
            glow.transform.localPosition = Vector3.zero;
            glow.transform.localScale = Vector3.one;
            glow.transform.localRotation = Quaternion.identity;

            var glowSr = glow.AddComponent<SpriteRenderer>();
            if (ownerSr != null)
            {
                glowSr.sortingLayerName = ownerSr.sortingLayerName;
                glowSr.sortingOrder = ownerSr.sortingOrder + 2;
            }
            glowSr.sprite = sprite;

            var mat = ModAPI.FindMaterial("VeryBright");
            if (mat != null)
            {
                glowSr.material = UnityEngine.Object.Instantiate<Material>(mat);
            }
            else
            {
                Debug.LogWarning("[InfinityGauntlet] VeryBright material not found.");
            }

            glowSr.color = Color.clear;
            return glowSr;
        }

        private void SetMenuInteractable(string stoneName, bool value)
        {
            if (Menu == null)
            {
                Debug.LogWarning("[InfinityGauntlet] Menu is null while setting interactable for " + stoneName);
                return;
            }

            var buttonTf = Menu.transform.FindChild("Stones/" + stoneName);
            if (buttonTf == null)
            {
                Debug.LogWarning("[InfinityGauntlet] Button not found: Stones/" + stoneName);
                return;
            }

            var button = buttonTf.GetComponent<Button>();
            if (button == null)
            {
                Debug.LogWarning("[InfinityGauntlet] Button component missing for Stones/" + stoneName);
                return;
            }

            button.interactable = value;
        }

        public void AddStone(StoneAbilityEnum ability)
        {
            switch (ability)
            {
                case StoneAbilityEnum.Space:
                    HasSpace = true;
                    GlowSpace = CreateStone("SpaceObject", "SpaceGObject", Mod.SpaceOn);
                    SetMenuInteractable("Space", true);
                    break;
                case StoneAbilityEnum.Mind:
                    HasMind = true;
                    GlowMind = CreateStone("MindObject", "MindGObject", Mod.MindOn);
                    SetMenuInteractable("Mind", true);
                    break;
                case StoneAbilityEnum.Reality:
                    HasReality = true;
                    GlowReality = CreateStone("RealityObject", "RealityGObject", Mod.RealityOn);
                    SetMenuInteractable("Reality", true);
                    break;
                case StoneAbilityEnum.Power:
                    HasPower = true;
                    GlowPower = CreateStone("PowerObject", "PowerGObject", Mod.PowerOn);
                    SetMenuInteractable("Power", true);
                    break;
                case StoneAbilityEnum.Time:
                    HasTime = true;
                    GlowTime = CreateStone("TimeObject", "TimeGObject", Mod.TimeOn);
                    SetMenuInteractable("Time", true);
                    break;
                case StoneAbilityEnum.Soul:
                    HasSoul = true;
                    GlowSoul = CreateStone("SoulObject", "SoulGObject", Mod.SoulOn);
                    SetMenuInteractable("Soul", true);
                    break;
            }

            foreach (var layerchid in gameObject.GetComponentsInChildren<SpriteRenderer>())
            {
                if(layerchid.gameObject.name.Contains("Object"))
                {
                    layerchid.gameObject.GetOrAddComponent<SortingLayerChild>().Behaviour = SortingLayerChild.SortBehaviour.Above;
                }
            }

            if (HasMind && HasPower && HasTime && HasReality && HasSoul && HasSpace)
            {
                _physicalBehaviour.ContextMenuOptions.Buttons.Add(new ContextMenuButton(() => !ColorpickerDialogBehaviour.IsOpen, "AllStoneMenu", "<color=#FFDC7D>All Stones Menu", "<color=#FFDC7D>All Stones Menu", delegate
                {
                    Menu.transform.FindChild("SV").gameObject.SetActive(true);

                    for (int i = 0; i < Menu.transform.FindChild("SV/VP/Content").childCount; i++)
                    {
                        var child = Menu.transform.FindChild("SV/VP/Content").GetChild(i);
                        Debug.Log(child.name);
                        if (child.name.Contains("All"))
                            child.gameObject.SetActive(true);
                        else
                            child.gameObject.SetActive(false);
                    }
                    EnableMenu();
                }));
            }
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            if (col.collider.name.Contains("Stone"))
            {
                if (col.collider.name.Contains("Mind") && !HasMind)
                {
                    AddStone(StoneAbilityEnum.Mind);
                    Destroy(col.collider.gameObject);
                }
                else if (col.collider.name.Contains("Power") && !HasPower)
                {
                    AddStone(StoneAbilityEnum.Power);
                    Destroy(col.collider.gameObject);
                }
                else if (col.collider.name.Contains("Reality") && !HasReality)
                {
                    AddStone(StoneAbilityEnum.Reality);
                    Destroy(col.collider.gameObject);
                }
                else if (col.collider.name.Contains("Space") && !HasSpace)
                {
                    AddStone(StoneAbilityEnum.Space);
                    Destroy(col.collider.gameObject);
                }
                else if (col.collider.name.Contains("Time") && !HasTime)
                {
                    AddStone(StoneAbilityEnum.Time);
                    Destroy(col.collider.gameObject);
                }
                else if (col.collider.name.Contains("Soul") && !HasSoul)
                {
                    AddStone(StoneAbilityEnum.Soul);
                    Destroy(col.collider.gameObject);
                }
            }

            if (_cooldownActive && Time.time < _cooldownEndTime)
            {
                return;
            }

            if (Joint)
            {
                return;
            }

            if (col.collider.TryGetComponent<LimbBehaviour>(out var limb) &&
                col.collider.gameObject.name.Contains("LowerArmFront") &&
                !col.collider.GetComponentInChildren<WidowGauntlet>() && !col.collider.GetComponentInChildren<InfinityGauntlet>())
            {
                Connect(limb);
            }

        }

        public void Connect(LimbBehaviour connected)
        {
            if (_cooldownActive && Time.time < _cooldownEndTime)
            {
                return;
            }

            StartCoroutine(fuckyouunitykys(connected));
        }

        public IEnumerator fuckyouunitykys(LimbBehaviour connected)
        {
            // Wait until physics step to avoid attaching in same frame as Rigidbody2D update
            yield return new WaitForFixedUpdate();

            if (Joint)
            {
                transform.parent = null;
                Destroy(Joint);
            }

            var rb = GetComponent<Rigidbody2D>();
            rb.mass = connected.PhysicalBehaviour.rigidbody.mass;

            var sr = GetComponent<SpriteRenderer>();
            var limbSr = connected.GetComponent<SpriteRenderer>();
            sr.sortingLayerName = limbSr.sortingLayerName;
            sr.sortingOrder = limbSr.sortingOrder + 1;

            transform.parent = connected.transform;
            transform.localPosition = Vector3.zero;
            transform.localRotation = Quaternion.identity;
            transform.localScale = Vector3.one;

            rb.position = connected.transform.position;
            rb.rotation = 0f; // Ensure overlay has zero local rotation
            rb.angularVelocity = 0f;

            Joint = gameObject.AddComponent<FixedJoint2D>();
            Joint.connectedBody = connected.PhysicalBehaviour.rigidbody;
            Joint.autoConfigureConnectedAnchor = false;
            Joint.anchor = Vector2.zero;
            Joint.connectedAnchor = Vector2.zero;

            foreach (var col in Joint.connectedBody.transform.root.GetComponentsInChildren<Collider2D>())
            {
                foreach (var ocol in GetComponents<Collider2D>())
                {
                    Physics2D.IgnoreCollision(col, ocol, true);
                }
            }

            // Clear cooldown when successfully attached
            _cooldownActive = false;
        }

        public void FixedUpdate()
        {
            _physicalBehaviour.ObjectArea = 0.001f;

            if (!contextMenu)
                contextMenu = GameObject.Find("Scrolling context menu");

            if (contextMenu)
                if (contextMenu.activeInHierarchy)
                    foreach (var text in contextMenu.transform.GetChild(0).GetChild(0).GetComponentsInChildren<TextMeshProUGUI>())
                    {
                        if (text.text == "<color=\"yellow\">Gauntlet Menu")
                            text.transform.parent.SetSiblingIndex(0);
                        if (text.text == "<color=#FFDC7D>All Stones Menu")
                            text.transform.parent.SetSiblingIndex(1);
                    }

            if (!Joint && _cooldownActive && Time.time >= _cooldownEndTime)
            {
                _cooldownActive = false;
            }
        }
    }

    public class Snap : StoneAbility, Messages.IUse
    {
        private List<GameObject> removedPeople = new List<GameObject>();
        private List<Vector3> savedPositions = new List<Vector3>();
        private List<Quaternion> savedRotations = new List<Quaternion>();

        private bool isSnapped = false;

        private AudioSource audioSource;

        void Awake()
        {
            audioSource = gameObject.AddComponent<AudioSource>();
            audioSource.playOnAwake = false;
            audioSource.spatialBlend = 1f;
            audioSource.volume = 1.5f;
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            if (isSnapped)
                StartFadeIn();
            else
                StartFadeOut();

            if (transform.parent != null)
            {
                if (transform.root.TryGetComponent<SpeedHealing>(out var heal))
                    heal.DisablePower();
                else if (transform.root.TryGetComponent<SpeedHealing>(out var sheal))
                    sheal.DisablePower();

                foreach (var limb in transform.parent.parent.GetComponentsInChildren<LimbBehaviour>())
                {
                    limb.SkinMaterialHandler.AcidProgress += GetComponent<InfinityGauntlet>().Nanotech ? .7f : .6f;
                }

                transform.root.GetComponent<PersonBehaviour>().Limbs[1].SkinMaterialHandler.AcidProgress += GetComponent<InfinityGauntlet>().Nanotech ? .85f : .7f;
            }
        }

        public void StartFadeOut()
        {
            audioSource.PlayOneShot(Mod.Snap);
            SnapAway();
        }

        public void StartFadeIn()
        {
            audioSource.PlayOneShot(Mod.Snap);
            SnapBack();
        }

        public void SnapAway()
        {
            if (isSnapped || !Enabled) return;


            PersonBehaviour gauntletHolder = null;
            var gauntletRoot = transform.root;
            if (gauntletRoot != null)
                gauntletHolder = gauntletRoot.GetComponent<PersonBehaviour>();

            PersonBehaviour[] allPeople = FindObjectsOfType<PersonBehaviour>();


            List<PersonBehaviour> filtered = new List<PersonBehaviour>();
            foreach (var person in allPeople)
            {
                if (person != null && person != gauntletHolder)
                    filtered.Add(person);
            }

            int halfCount = filtered.Count / 2;
            Shuffle(filtered);

            for (int i = 0; i < halfCount; i++)
            {
                StartCoroutine(FadeAndFreeze(filtered[i]));
            }

            isSnapped = true;
        }


        public void SnapBack()
        {
            if (!isSnapped || !Enabled) return;

            for (int i = 0; i < removedPeople.Count; i++)
            {
                GameObject person = removedPeople[i];
                if (person == null)
                    continue;
                person.SetActive(true);
                person.transform.position = savedPositions[i];
                person.transform.rotation = savedRotations[i];

                var limbs = person.GetComponentsInChildren<LimbBehaviour>();
                var colliders = person.GetComponentsInChildren<Collider2D>();

                foreach (var limb in limbs)
                {
                    var snapEffect = limb.gameObject.GetComponent<SnapEffect>();
                    snapEffect.StartFadeIn();

                    var freeze = limb.GetComponent<FreezeBehaviour>();
                    if (freeze != null) Destroy(freeze);
                }

                var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Clone)");

                foreach (var status in limbStatusObjects)
                {
                    if (status.GetComponent<LimbStatusBehaviour>().limb.Person == removedPeople[i])
                    {
                        status.GetComponent<LimbStatusBehaviour>().enabled = true;
                        var color = status.GetComponent<SpriteRenderer>().color;
                        status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 1);
                        var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                        status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 1);
                    }
                }

                for (int a = 0; a < colliders.Length; a++)
                {
                    for (int b = a + 1; b < colliders.Length; b++)
                    {
                        Physics2D.IgnoreCollision(colliders[a], colliders[b], true);
                    }
                }
            }

            removedPeople.Clear();
            savedPositions.Clear();
            savedRotations.Clear();
        }

        private IEnumerator FadeAndFreeze(PersonBehaviour person)
        {
            GameObject personObj = person.gameObject;

            removedPeople.Add(personObj);
            savedPositions.Add(personObj.transform.position);
            savedRotations.Add(personObj.transform.rotation);

            LimbBehaviour[] limbs = person.GetComponentsInChildren<LimbBehaviour>();

            foreach (LimbBehaviour limb in limbs)
            {
                if (!limb.GetComponent<FreezeBehaviour>())
                    limb.gameObject.AddComponent<FreezeBehaviour>();
            }

            foreach (var limb in limbs)
            {
                var sr = limb.GetComponent<SpriteRenderer>();
                sr.sprite = Timtam.MergeSpritesWithShaderHandling(
                    sr.sprite,
                    Mod.Dot,
                    sr.material,
                    true,
                    false
                );
                SnapEffect snapEffect;
                if (limb.gameObject.GetComponent<SnapEffect>() == null)
                {
                    snapEffect = limb.gameObject.AddComponent<SnapEffect>();
                }
                else
                {
                    snapEffect = limb.gameObject.GetComponent<SnapEffect>();
                }
                snapEffect.StartFadeOut();
            }

            yield return new WaitForSeconds(3);

            var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Clone)");

            foreach (var status in limbStatusObjects)
            {
                if (status.GetComponent<LimbStatusBehaviour>().limb.Person == person)
                {
                    status.GetComponent<LimbStatusBehaviour>().enabled = false;
                    var color = status.GetComponent<SpriteRenderer>().color;
                    status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 0);
                    var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                    status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 0);
                }
            }

            person.gameObject.SetActive(false);
        }

        private void Shuffle<T>(List<T> list)
        {
            int n = list.Count;
            for (int i = 0; i < n - 1; i++)
            {
                int j = UnityEngine.Random.Range(i, n);
                (list[i], list[j]) = (list[j], list[i]);
            }
        }
    }

    public class SnapEffect : MonoBehaviour
    {
        public SpriteRenderer spriteRenderer;
        public ParticleSystem pixelParticleSystem;
        public float animationDuration = 3f;

        private bool isInitialized = false;

        public void StartFadeOut()
        {
            StartCoroutine(EnsureInitializedAndFade(FadeOutSequence));
        }

        public void StartFadeIn()
        {
            StartCoroutine(EnsureInitializedAndFade(FadeInSequence));
        }

        private Texture2D bufferTexture;
        private Color[] pixelData;
        private int texWidth;
        private int texHeight;
        private float pixelsPerUnit;

        void Awake()
        {
            spriteRenderer = spriteRenderer != null ? spriteRenderer : GetComponent<SpriteRenderer>();
            if (pixelParticleSystem == null)
            {
                pixelParticleSystem = gameObject.AddComponent<ParticleSystem>();
                SetupParticleSystem(pixelParticleSystem);
            }
        }

        void Start()
        {
            Initialize();
        }

        private void Initialize()
        {
            if (spriteRenderer == null) spriteRenderer = GetComponent<SpriteRenderer>();
            if (spriteRenderer == null || spriteRenderer.sprite == null || spriteRenderer.sprite.texture == null)
            {
                isInitialized = false;
                return;
            }
            Sprite current = spriteRenderer.sprite;
            bufferTexture = current.texture;
            texWidth = bufferTexture.width;
            texHeight = bufferTexture.height;
            if (texWidth == 0 || texHeight == 0)
            {
                isInitialized = false;
                return;
            }
            pixelData = bufferTexture.GetPixels();
            pixelsPerUnit = current.pixelsPerUnit;
            isInitialized = true;
        }

        private IEnumerator EnsureInitializedAndFade(Func<IEnumerator> fadeRoutine)
        {

            int tries = 0;
            while ((!isInitialized || spriteRenderer == null || spriteRenderer.sprite == null || spriteRenderer.sprite.texture == null || spriteRenderer.sprite.texture.width == 0 || spriteRenderer.sprite.texture.height == 0) && tries < 10)
            {
                Initialize();
                tries++;
                yield return null;
            }
            if (isInitialized)
            {
                yield return StartCoroutine(fadeRoutine());
            }
        }

        void RefreshSprite()
        {
            spriteRenderer.sprite = Sprite.Create(
                bufferTexture,
                spriteRenderer.sprite.rect,
                new Vector2(0.5f, 0.5f),
                pixelsPerUnit
            );
        }

        IEnumerator FadeOutSequence()
        {
            Texture2D tempTex = new Texture2D(texWidth, texHeight, TextureFormat.RGBA32, false);
            tempTex.filterMode = FilterMode.Point;
            tempTex.SetPixels(pixelData);
            tempTex.Apply();

            spriteRenderer.sprite = Sprite.Create(
                tempTex,
                spriteRenderer.sprite.rect,
                new Vector2(0.5f, 0.5f),
                pixelsPerUnit
            );

            List<int> indices = CreateRandomList();
            int totalPixels = indices.Count;
            int steps = texWidth;
            int batch = Mathf.CeilToInt((float)totalPixels / steps);
            float interval = animationDuration / steps;

            for (int i = 0; i < steps; i++)
            {
                int start = i * batch;
                int end = Mathf.Min(start + batch, totalPixels);
                for (int j = start; j < end; j++)
                {
                    int idx = indices[j];
                    int x = idx % texWidth;
                    int y = idx / texWidth;
                    Color c = pixelData[idx];
                    if (c.a <= 0f) continue;

                    tempTex.SetPixel(x, y, new Color(0, 0, 0, 0));
                    SpawnParticle(x, y, c, false);
                }
                tempTex.Apply();
                spriteRenderer.sprite = Sprite.Create(tempTex, spriteRenderer.sprite.rect, new Vector2(0.5f, 0.5f), spriteRenderer.sprite.pixelsPerUnit);
                yield return new WaitForSeconds(interval);
            }
        }

        IEnumerator FadeInSequence()
        {
            Texture2D tempTex = new Texture2D(texWidth, texHeight, TextureFormat.RGBA32, false);
            tempTex.filterMode = FilterMode.Point;
            Color[] blank = new Color[texWidth * texHeight];
            for (int i = 0; i < blank.Length; i++) blank[i] = new Color(0, 0, 0, 0);
            tempTex.SetPixels(blank);
            tempTex.Apply();

            spriteRenderer.sprite = Sprite.Create(
                tempTex,
                spriteRenderer.sprite.rect,
                new Vector2(0.5f, 0.5f),
                pixelsPerUnit
            );

            List<int> indices = CreateRandomList();
            int totalPixels = indices.Count;
            int steps = texWidth;
            int batch = Mathf.CeilToInt((float)totalPixels / steps);
            float interval = animationDuration / steps;

            for (int i = 0; i < steps; i++)
            {
                int start = i * batch;
                int end = Mathf.Min(start + batch, totalPixels);
                for (int j = start; j < end; j++)
                {
                    int idx = indices[j];
                    int x = idx % texWidth;
                    int y = idx / texWidth;
                    Color c = pixelData[idx];
                    if (c.a <= 0f) continue;

                    tempTex.SetPixel(x, y, c);
                    SpawnParticle(x, y, c, true);
                }
                tempTex.Apply();
                spriteRenderer.sprite = Sprite.Create(tempTex, spriteRenderer.sprite.rect, new Vector2(0.5f, 0.5f), spriteRenderer.sprite.pixelsPerUnit);
                yield return new WaitForSeconds(interval);
            }
        }

        List<int> CreateRandomList()
        {
            List<int> list = new List<int>(texWidth * texHeight);
            for (int i = 0; i < texWidth * texHeight; i++) list.Add(i);
            for (int i = list.Count - 1; i > 0; i--)
            {
                int r = UnityEngine.Random.Range(0, i + 1);
                int tmp = list[i]; list[i] = list[r]; list[r] = tmp;
            }
            return list;
        }

        void SpawnParticle(int px, int py, Color col, bool descending)
        {
            var e = new ParticleSystem.EmitParams();
            Vector3 pos = new Vector3(
                (px - texWidth * 0.5f) / pixelsPerUnit,
                (py - texHeight * 0.5f) / pixelsPerUnit,
                0f
            );

            float scale = 1f;
            if (transform.root != null)
            {
                Vector3 rootScale = transform.root.localScale;
                scale = (1f / pixelsPerUnit) * Mathf.Max(Mathf.Abs(rootScale.x), Mathf.Abs(rootScale.y));
            }
            else
            {
                scale = 1f / pixelsPerUnit;
            }
            if (descending)
            {

                pos.y += 10.5f * scale;
                Vector3 worldPos = transform.TransformPoint(pos);
                e.position = worldPos;
                pixelParticleSystem.gravityModifier = 0.1f;
                e.velocity = new Vector3(
                    UnityEngine.Random.Range(-0.1f, 0.1f) * scale,
                    UnityEngine.Random.Range(-1.2f, -0.5f) * scale,
                    0f
                );
            }
            else
            {
                Vector3 worldPos = transform.TransformPoint(pos);
                e.position = worldPos;
                pixelParticleSystem.gravityModifier = -0.1f;

                e.velocity = new Vector3(
                    UnityEngine.Random.Range(-0.1f, 0.1f) * scale,
                    UnityEngine.Random.Range(0.5f, 1.2f) * scale,
                    0f
                );
            }
            e.startColor = col;
            e.startSize = scale;
            pixelParticleSystem.Emit(e, 1);
        }

        void SetupParticleSystem(ParticleSystem sys)
        {
            var m = sys.main;
            m.loop = false;
            m.playOnAwake = false;
            m.simulationSpace = ParticleSystemSimulationSpace.World;
            m.startLifetime = 1.5f;
            m.startSpeed = 0;

            var em = sys.emission;
            em.enabled = false;

            var sh = sys.shape;
            sh.enabled = false;

            var cl = sys.colorOverLifetime;
            cl.enabled = true;
            Gradient g = new Gradient();
            g.SetKeys(
                new GradientColorKey[] { new GradientColorKey(Color.white, 0f), new GradientColorKey(Color.white, 1f) },
                new GradientAlphaKey[] { new GradientAlphaKey(1f, 0f), new GradientAlphaKey(0f, 1f) }
            );
            cl.color = new ParticleSystem.MinMaxGradient(g);

            var rend = sys.GetComponent<ParticleSystemRenderer>();
            rend.renderMode = ParticleSystemRenderMode.Billboard;
            rend.material = new Material(Shader.Find("Sprites/Default"));
        }
    }

    public class SpacePortals : StoneAbility, Messages.IUse, Mod.ModAPIPlus.IUse2
    {
        public static GameObject PortalPrefab;

        public GameObject Portal1;
        public GameObject Portal2;

        bool OnFirstPortal = true;

        public List<Transform> cooldowned = new List<Transform>();

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            if (Portal1 == null)
            {
                Portal1 = Instantiate(PortalPrefab);
                Portal1.AddComponent<Portal>().parentPower = this;
                Portal1.transform.position = transform.position + -transform.up * 1.5f;
                Portal1.transform.localScale = Vector3.one * 0.75f;
                Portal1.transform.GetChild(0).transform.localScale = Vector3.one;
                Portal1.transform.GetChild(1).transform.localScale = Vector3.one;
            }
            else if (Portal2 == null)
            {
                Portal2 = Instantiate(PortalPrefab);
                Portal2.AddComponent<Portal>().parentPower = this;
                Portal2.transform.position = transform.position + -transform.up * 1.5f;
                Portal2.transform.localScale = Vector3.one * 0.75f;
                Portal2.transform.GetChild(0).transform.localScale = Vector3.one;
                Portal2.transform.GetChild(1).transform.localScale = Vector3.one;
            }
            else
            {
                if (OnFirstPortal)
                {
                    Portal1.SetActive(false);
                    Portal1.transform.position = transform.position + -transform.up * 1.5f;
                    Portal1.SetActive(true);
                    OnFirstPortal = false;
                }
                else
                {
                    Portal2.SetActive(false);
                    Portal2.transform.position = transform.position + -transform.up * 1.5f;
                    Portal2.SetActive(true);
                    OnFirstPortal = true;
                }
            }
        }

        public void Use2()
        {
            Destroy(Portal1);
            Destroy(Portal2);
        }

        public override void DisablePower()
        {
            base.DisablePower();

            Destroy(Portal1);
            Destroy(Portal2);
        }

        public class Portal : MonoBehaviour
        {
            public SpacePortals parentPower;

            public void Start()
            {
                gameObject.layer = Layers.Objects;
                gameObject.AddComponent<DebrisComponent>();
                var col = gameObject.AddComponent<BoxCollider2D>();
                col.size = new Vector2(2, 2);
                col.isTrigger = true;
            }

            public void OnTriggerEnter2D(Collider2D collision)
            {
                var otherPortal = parentPower.Portal1 == gameObject ? parentPower.Portal2 : parentPower.Portal1;
                if (otherPortal == null) return;

                var root = collision.transform.root;
                if (root == null) return;

                if (parentPower.cooldowned.Contains(root)) return;

                if (root == otherPortal.transform.root) return;

                StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Teleport));

                foreach (var ph in root.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    ModAPI.CreateParticleEffect("Flash", ph.transform.position);
                }

                Vector3 offsetFromPortal = root.position - transform.position;

                Quaternion originalRotation = root.rotation;

                CameraShakeBehaviour.main.Shake(1, transform.position, 0.5f);

                root.position = otherPortal.transform.position + offsetFromPortal;
                root.rotation = originalRotation;

                foreach (var ph in root.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    ModAPI.CreateParticleEffect("Flash", ph.transform.position);
                }

                StartCoroutine(TempCooldown(root));
            }

            private IEnumerator TempCooldown(Transform target)
            {
                parentPower.cooldowned.Add(target);
                yield return new WaitForSeconds(0.5f);
                parentPower.cooldowned.Remove(target);
            }
        }
    }

    public class StoneAbility : MonoBehaviour
    {
        InfinityGauntlet gauntlet;

        public bool Enabled = false;
        public GameObject button = null;
        public TargettedLimb targetLimb;

        public virtual void EnablePower()
        {
            Enabled = true;
            button?.transform.GetChild(0)?.gameObject.SetActive(false);

            if (targetLimb != TargettedLimb.Internal)
            {
                foreach (StoneAbility power2 in transform.root.GetComponentsInChildren<StoneAbility>())
                {
                    if (power2 != this && power2.targetLimb == targetLimb && power2.Enabled)
                        power2.DisablePower();
                }

                foreach (var abilityCycler in transform.root.GetComponentsInChildren<AbilityCycler>())
                {
                    abilityCycler.UpdateText();
                }
            }
        }

        public virtual void DisablePower()
        {
            Enabled = false;
            button?.transform.GetChild(0)?.gameObject.SetActive(true);

            foreach (var abilityCycler in transform.root.GetComponentsInChildren<AbilityCycler>())
            {
                abilityCycler.UpdateText();
            }
        }
    }

    public class WandaProjectile : Power, Messages.IUse
    {
        public static GameObject ProjectilePrefab;

        public static WandaProjectile SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<WandaProjectile>();
            power.Name = "Magic Projectile";
            power.Description = "Create a projectile that can be launched at anything to damage it.";
            power.icon = icon;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            return power;
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.MagicShootWanda));

            var bullet = Instantiate(ProjectilePrefab);
            bullet.AddComponent<WandaProjectile.MagicProj>().projectile = this;
            bullet.transform.position = transform.position + -transform.up;
            bullet.transform.rotation = transform.rotation;
        }

        public class MagicProj : MonoBehaviour
        {
            public WandaProjectile projectile;
            public float speed = 45;

            private bool _shooting;
            private float _hoverOffset = 0.75f;
            private float _hoverLerpDuration = 0.5f;
            private float _hoverTime = 0.5f;

            private void Start()
            {
                StartCoroutine(PrepareAndShoot());
            }

            private IEnumerator PrepareAndShoot()
            {
                float t = 0f;
                while (t < _hoverLerpDuration)
                {
                    t += Time.deltaTime;

                    Transform projTr = projectile.transform;
                    Vector3 targetPos = projTr.position + (-projTr.up * _hoverOffset);
                    Quaternion targetRot = projTr.rotation;

                    transform.position = Vector3.Slerp(transform.position, targetPos, Time.deltaTime * 5);
                    transform.rotation = Quaternion.Slerp(transform.rotation, targetRot, Time.deltaTime * 5);

                    yield return null;
                }

                _shooting = true;
            }

            public void Update()
            {
                if (_shooting)
                {
                    Vector3 dir = -transform.up;
                    transform.position += dir * speed * Time.deltaTime;

                    RaycastHit2D hit = Physics2D.Raycast(transform.position, dir, 0.1f);
                    if (hit.collider != null && hit.transform.root != projectile.transform.root)
                    {
                        Hit();
                    }
                }
            }

            public void Hit()
            {
                ExplosionCreator.Explode(transform.position, 9);
                Destroy(gameObject);
            }
        }
    }

    public class WandaAreaBlast : Power, Messages.IUse
    {
        public static GameObject BlastPrefab;

        private ParticleSystem _pfxPs;
        public GameObject PFX;

        private PersonBehaviour _person;

        public bool busting = false;

        public static WandaAreaBlast SetPower(PersonBehaviour person, LimbBehaviour limb, Sprite icon)
        {
            var power = limb.gameObject.AddComponent<WandaAreaBlast>();
            power.Name = "Spacial Torture Field";
            power.Description = "Press the activation key (typically F) target anyone in a large diameter to float and be damaged!";
            power.icon = icon;
            power.targetLimb = TargettedLimb.Head;
            power._person = person;

            if (BlastPrefab != null)
            {
                power.PFX = UnityEngine.Object.Instantiate(BlastPrefab);
                power._pfxPs = power.PFX.GetComponent<ParticleSystem>();
                if (power._pfxPs != null)
                {
                    power._pfxPs.Stop();
                }

                power.PFX.transform.SetParent(limb.transform, false);
                power.PFX.transform.position = limb.transform.position;
            }

            return power;
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
            {
                return;
            }

            busting = !busting;

            if (_pfxPs != null)
            {
                if (busting)
                {
                    _pfxPs.Play();
                }
                else
                {
                    _pfxPs.Stop();
                }
            }
        }

        private void FixedUpdate()
        {
            if (!Enabled || !busting)
            {
                return;
            }

            var hits = Physics2D.OverlapCircleAll(transform.position, 8f, LayerMask.GetMask("Objects"));
            if (hits == null || hits.Length == 0)
            {
                return;
            }

            foreach (var c in hits)
            {
                if (c == null)
                {
                    continue;
                }

                if (!Global.main.PhysicalObjectsInWorldByTransform.TryGetValue(c.transform, out var phys))
                {
                    continue;
                }

                if (phys == null || phys.transform == null || phys.transform.root == transform.root)
                {
                    continue;
                }

                if (phys.gameObject.GetComponent<DamageVictim>() != null)
                {
                    continue;
                }

                var victim = phys.gameObject.AddComponent<DamageVictim>();
                victim.mommy = this;
            }
        }

        public class DamageVictim : MonoBehaviour
        {
            public WandaAreaBlast mommy;

            public static GameObject PFXPrefab;
            public GameObject pfx;

            public float cooldown = 2.5f;
            private float _cooldownTimer;

            private LimbBehaviour _limb;
            private PhysicalBehaviour _phys;

            private float _ogGrav;
            private float _ogDrag;

            public void Start()
            {
                if (PFXPrefab != null)
                {
                    var pf = UnityEngine.Object.Instantiate(PFXPrefab);
                    pfx = pf;
                    pf.transform.SetParent(transform, false);

                    var childPs = pf.transform.childCount > 0 ? pf.transform.GetChild(0).GetComponent<ParticleSystem>() : pf.GetComponent<ParticleSystem>();
                    if (childPs != null)
                    {
                        var shape = childPs.shape;
                        var sr = GetComponent<SpriteRenderer>();
                        if (sr != null)
                        {
                            shape.spriteRenderer = sr;
                        }
                    }
                }

                TryGetComponent(out _limb);
                TryGetComponent(out _phys);

                if (_phys != null && _phys.rigidbody != null)
                {
                    _ogGrav = _phys.rigidbody.gravityScale;
                    _ogDrag = _phys.rigidbody.drag;

                    _phys.rigidbody.gravityScale = 0f;
                    _phys.rigidbody.drag = 1f;
                }

                if (_limb != null && _limb.Person != null)
                {
                    _limb.Person.OverridePoseIndex = 5;
                }
            }

            private void Update()
            {
                if (mommy == null || !mommy.busting || Vector2.Distance(transform.position, mommy.transform.position) > 8f)
                {
                    RestoreAndDestroy();
                    return;
                }

                if (_cooldownTimer > 0f)
                {
                    _cooldownTimer -= Time.deltaTime;
                    return;
                }

                _cooldownTimer = cooldown * UnityEngine.Random.Range(0.8f, 2.5f);

                if (_phys != null && _phys.rigidbody != null)
                {
                    _phys.rigidbody.gravityScale = 0f;

                    var impulseDir = new Vector2(
                        UnityEngine.Random.Range(-1f, 1f),
                        UnityEngine.Random.Range(-1f, 1f)
                    );
                    if (impulseDir.sqrMagnitude > 0.0001f)
                    {
                        _phys.rigidbody.AddForce(impulseDir.normalized, ForceMode2D.Impulse);
                    }
                }

                if (_limb != null)
                {
                    _limb.Health -= _limb.InitialHealth * 0.1f;
                    _limb.Person.OverridePoseIndex = 5;
                    if (_limb.PhysicalBehaviour != null && _limb.Person != null && _limb.Person.DismembermentClips != null)
                    {
                        var clip = _limb.Person.DismembermentClips.PickRandom();
                        if (clip != null)
                        {
                            _limb.PhysicalBehaviour.PlayClipOnce(clip);
                        }
                    }

                    if (_limb.SkinMaterialHandler != null)
                    {
                        _limb.SkinMaterialHandler.AddDamagePoint(
                            DamageType.Stab,
                            new Vector2(
                                _limb.transform.position.x + UnityEngine.Random.Range(-0.1f, 0.1f),
                                _limb.transform.position.y + UnityEngine.Random.Range(-0.1f, 0.1f)
                            ), UnityEngine.Random.Range(10f, 25)
                        );
                    }
                }
            }

            private void RestoreAndDestroy()
            {
                if (_phys != null && _phys.rigidbody != null)
                {
                    _phys.rigidbody.gravityScale = _ogGrav;
                    _phys.rigidbody.drag = _ogDrag;
                }

                if (_limb != null && _limb.Person != null)
                {
                    _limb.Person.OverridePoseIndex = 11;
                }
                Destroy(pfx);
                UnityEngine.Object.Destroy(this);
            }
        }
    }

    public class Forcefield : Power, Messages.IUse//directly from code I made in a separate mod
    {
        float Transparency = 0.01f;
        public GameObject ForcefieldOBJ = null;
        public bool CanSwitch = true;

        public static Power SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<Forcefield>();
            power.Name = "Forcefield";
            power.icon = icon;

            power.targetLimb = TargettedLimb.Body;

            return power;
        }

        public void Use(ActivationPropagation activation)
        {
            if (Enabled)
            {
                if (this.ForcefieldOBJ == null)
                {
                    ForcefieldOBJ = new GameObject("Forcefield");
                    ForcefieldOBJ.transform.position = transform.position;
                    ForcefieldOBJ.AddComponent<SpriteRenderer>().sprite = Mod.ForcefieldSprite;
                    ForcefieldOBJ.AddComponent<CircleCollider2D>();
                    ForcefieldOBJ.GetComponent<SpriteRenderer>().sortingLayerName = "Decals";
                    ForcefieldOBJ.layer = 9;
                    Collider2D[] cols = Physics2D.OverlapCircleAll(ForcefieldOBJ.transform.position, ForcefieldOBJ.GetComponent<CircleCollider2D>().radius);
                    StartCoroutine(ColorOverTime(ForcefieldOBJ, Color.white, new Color(1, 1, 1, 0)));
                    foreach (var col in cols)
                    {
                        foreach (var collider in col.transform.root.gameObject.GetComponentsInChildren<Collider2D>())
                        {
                            Physics2D.IgnoreCollision(collider, ForcefieldOBJ.GetComponent<CircleCollider2D>());
                        }
                    }
                }
                else
                {
                    StartCoroutine(DestroyForcefield());
                }
            }
        }

        public IEnumerator DestroyForcefield()
        {
            ForcefieldOBJ.GetComponent<CircleCollider2D>().radius = 0;
            StartCoroutine(ColorOverTime(ForcefieldOBJ, new Color(1, 1, 1, 0), Color.white));
            yield return new WaitForSeconds(1);
            Destroy(ForcefieldOBJ);
        }

        public override void DisablePower()
        {
            if (this.ForcefieldOBJ != null)
            {
                Destroy(ForcefieldOBJ);
            }
            base.DisablePower();
        }

        public void OnDestroy()
        {
            if (this.ForcefieldOBJ != null)
            {
                Destroy(ForcefieldOBJ);
            }
        }

        IEnumerator ColorOverTime(GameObject AffectedObject, Color newColor, Color OriginalColor)
        {
            CanSwitch = false;
            var duration = 1f;
            float elapsedTime = 0;

            while (elapsedTime < duration)
            {
                AffectedObject.GetComponent<SpriteRenderer>().color = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                elapsedTime += Time.deltaTime;
                yield return null;
            }
            AffectedObject.GetComponent<SpriteRenderer>().color = newColor;
            CanSwitch = true;
        }
    }

    public class LifeDrain : Power, Mod.ModAPIPlus.IUse2
    {
        public static GameObject RunePrefab;
        public static GameObject ExplodePrefab;

        public PersonBehaviour Person;

        public float rayDistance = 10f;
        public float forceMagnitude = 10f;
        public LayerMask layerMask;
        public float holdDistance = 4f;
        public float closeDistanceThreshold = 0.1f;
        bool doing;
        private LimbBehaviour limb;
        GameObject target;

        PhysicalBehaviour physicalBehaviour;

        GameObject PFX;

        public static LifeDrain SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<LifeDrain>();
            power.Name = "Life Drain";
            power.Description = "Hold the activation key (typically F) to syphon the life force of nearby objects\n<color =\"yellow\">This power can also swap inflicted damage with another person using the custom activation key (typically H) (Switches all bodily contents, as well as damage and health)";
            power.icon = icon;
            power.targetLimb = power.name.Contains("Front") ? TargettedLimb.FrontArm : TargettedLimb.BackArm;
            power.physicalBehaviour = Limb.GetComponent<PhysicalBehaviour>();
            power.limb = Limb;
            power.Person = Person;
            power.PFX = Instantiate(RunePrefab);
            power.PFX.GetComponent<ParticleSystem>().Stop();

            return power;
        }

        public void Use2ContinuousStart()
        {
            if (!Enabled)
                return;
            doing = true;
            layerMask = LayerMask.GetMask("Objects");
            RaycastHit2D hit = Physics2D.Raycast(transform.position, -transform.up, rayDistance, layerMask);

            if (hit.collider != null)
            {
                if (hit.collider.transform.root != transform.root && hit.collider.gameObject.GetComponent<Rigidbody2D>().bodyType != RigidbodyType2D.Static && !hit.collider.GetComponent<HatBehaviour>())
                {
                    if (hit.collider.GetComponent<LimbBehaviour>())
                    {
                        this.target = hit.collider.gameObject;
                    }
                }
            }
            else
            {
                target = null;
            }
        }

        public void Use2Continuous()
        {
            if (!Enabled)
                return;

            if (target != null)
            {
                if(!PFX.GetComponent<ParticleSystem>().isPlaying)
                    PFX.GetComponent<ParticleSystem>().Play();
                target.GetComponent<LimbBehaviour>().Person.OverridePoseIndex = 3;
                foreach (var limb in transform.root.GetComponent<PersonBehaviour>().Limbs)
                {
                    limb.CirculationBehaviour.AddLiquid(Liquid.GetLiquid(limb.BloodLiquidType), 0.1f * Time.deltaTime);
                    limb.Health += limb.InitialHealth / 50;
                    limb.PhysicalBehaviour.BurnProgress -= Time.deltaTime * 0.16f;
                    limb.SkinMaterialHandler.AcidProgress -= Time.deltaTime * 0.8f;
                    limb.SkinMaterialHandler.RottenProgress -= Time.deltaTime * 0.8f;
                    for (int i = 0; i < limb.SkinMaterialHandler.damagePoints.Length; i++)
                    {
                        limb.SkinMaterialHandler.damagePoints[i].z *= Mathf.Pow(0.5f, Time.deltaTime);
                    }

                    limb.SkinMaterialHandler.Sync();
                }

                foreach(var limb in target.transform.root.GetComponent<PersonBehaviour>().Limbs)
                {
                    limb.CirculationBehaviour.RemoveLiquid(Liquid.GetLiquid(limb.BloodLiquidType), 0.1f * Time.deltaTime);
                    limb.Health -= limb.InitialHealth / 50;

                    limb.SkinMaterialHandler.AcidProgress *= 1.01f;

                    if(limb.name.Contains("Head") || limb.name.Contains("UpperBody"))
                        if (limb.Health < 5)
                            Use2ContinuousEnd();
                }
            }
        }

        // Replace the existing method body
        public void Use2()
        {
            if (!Enabled)
                return;

            doing = true;
            layerMask = LayerMask.GetMask("Objects");
            var hit = Physics2D.Raycast(transform.position, -transform.up, rayDistance, layerMask);

            var hitRb = hit.collider.GetComponent<Rigidbody2D>();
            var targetLimb = hit.collider.GetComponent<LimbBehaviour>();

            var sourcePerson = transform.root.GetComponent<PersonBehaviour>();
            var targetPerson = hit.collider.transform.root.GetComponent<PersonBehaviour>();

            var beat = sourcePerson.BrainDamaged;
            sourcePerson.BrainDamaged = targetPerson.BrainDamaged;
            targetPerson.BrainDamaged = beat;

            var seizureti = sourcePerson.SeizureTime;
            sourcePerson.SeizureTime = targetPerson.SeizureTime;
            targetPerson.SeizureTime = seizureti;

            var braindead = sourcePerson.Braindead;
            sourcePerson.Braindead = targetPerson.Braindead;
            targetPerson.Braindead = braindead;

            var braintime = sourcePerson.BrainDamagedTime;
            sourcePerson.BrainDamagedTime = targetPerson.BrainDamagedTime;
            targetPerson.BrainDamagedTime = braintime;

            var consc = sourcePerson.Consciousness;
            sourcePerson.Consciousness = targetPerson.Consciousness;
            targetPerson.Consciousness = consc;

            var pain = sourcePerson.PainLevel;
            sourcePerson.PainLevel = targetPerson.PainLevel;
            targetPerson.PainLevel = pain;

            var adrenaline = sourcePerson.AdrenalineLevel;
            sourcePerson.AdrenalineLevel = targetPerson.AdrenalineLevel;
            targetPerson.AdrenalineLevel = adrenaline;

            foreach (var limb in sourcePerson.Limbs)
            {
                foreach (var limb2 in targetPerson.Limbs)
                {
                    if (limb.name != limb2.name)
                    {
                        continue;
                    }

                    var liquidDistTmp = limb.CirculationBehaviour.LiquidDistribution;
                    limb.CirculationBehaviour.LiquidDistribution = limb2.CirculationBehaviour.LiquidDistribution;
                    limb2.CirculationBehaviour.LiquidDistribution = liquidDistTmp;

                    var gunshotWoundCountTmp = limb.CirculationBehaviour.GunshotWoundCount;
                    limb.CirculationBehaviour.GunshotWoundCount = limb2.CirculationBehaviour.GunshotWoundCount;
                    limb2.CirculationBehaviour.GunshotWoundCount = gunshotWoundCountTmp;

                    var stabWoundCountTmp = limb.CirculationBehaviour.StabWoundCount;
                    limb.CirculationBehaviour.StabWoundCount = limb2.CirculationBehaviour.StabWoundCount;
                    limb2.CirculationBehaviour.StabWoundCount = stabWoundCountTmp;

                    limb.CirculationBehaviour.HealBleeding();
                    limb2.CirculationBehaviour.HealBleeding();

                    var healthTmp = limb.Health;
                    limb.Health = limb2.Health;
                    limb2.Health = healthTmp;

                    var broken = limb.Broken;
                    if (limb2.Broken)
                        limb.BreakBone();
                    else
                        limb.HealBone();

                    if (broken)
                        limb2.BreakBone();
                    else
                        limb.HealBone();

                    var damagePointsTmp = limb.SkinMaterialHandler.damagePoints;
                    limb.SkinMaterialHandler.damagePoints = limb2.SkinMaterialHandler.damagePoints;
                    limb2.SkinMaterialHandler.damagePoints = damagePointsTmp;

                    var dama = limb.SkinMaterialHandler.currentDamagePointCount;
                    limb.SkinMaterialHandler.currentDamagePointCount = limb2.SkinMaterialHandler.currentDamagePointCount;
                    limb2.SkinMaterialHandler.currentDamagePointCount = dama;

                    limb.SkinMaterialHandler.Sync();
                    limb2.SkinMaterialHandler.Sync();

                    var burnProgressTmp = limb.PhysicalBehaviour.BurnProgress;
                    limb.PhysicalBehaviour.BurnProgress = limb2.PhysicalBehaviour.BurnProgress;
                    limb2.PhysicalBehaviour.BurnProgress = burnProgressTmp;

                    var acidProgressTmp = limb.SkinMaterialHandler.AcidProgress;
                    limb.SkinMaterialHandler.AcidProgress = limb2.SkinMaterialHandler.AcidProgress;
                    limb2.SkinMaterialHandler.AcidProgress = acidProgressTmp;

                    var rottenProgressTmp = limb.SkinMaterialHandler.RottenProgress;
                    limb.SkinMaterialHandler.RottenProgress = limb2.SkinMaterialHandler.RottenProgress;
                    limb2.SkinMaterialHandler.RottenProgress = rottenProgressTmp;

                    var heartBeat = limb.CirculationBehaviour.MeasuredPressure;
                    limb.CirculationBehaviour.MeasuredPressure = limb2.CirculationBehaviour.MeasuredPressure;
                    limb2.CirculationBehaviour.MeasuredPressure = heartBeat;

                    var press = limb.CirculationBehaviour.BloodFlow;
                    limb.CirculationBehaviour.BloodFlow = limb2.CirculationBehaviour.BloodFlow;
                    limb2.CirculationBehaviour.BloodFlow = press;

                    var num = limb.Numbness;
                    limb.Numbness = limb2.Numbness;
                    limb2.Numbness = num;
                }
            }

            var heart = sourcePerson.Heartbeat;
            sourcePerson.Heartbeat = targetPerson.Heartbeat;
            targetPerson.Heartbeat = heart;

            Instantiate(ExplodePrefab, target.transform.position, Quaternion.identity).AddComponent<OBJDestroyer>();
        }

        public void Use2ContinuousEnd()
        {
            if (target != null)
            {
                Instantiate(ExplodePrefab, target.transform.position, Quaternion.identity).AddComponent<OBJDestroyer>();
                target.GetComponent<LimbBehaviour>().Person.OverridePoseIndex = 11;
            }

            target = null;
            doing = false;
            PFX.GetComponent<ParticleSystem>().Stop();
        }

        public void Update()
        {
            if (Person.Braindead)
                return;

            if (physicalBehaviour.StartedBeingUsedContinuously())
                Use2ContinuousStart();

            if (physicalBehaviour.StoppedBeingUsedContinuously())
                Use2ContinuousEnd();

            if(target)
                PFX.transform.position = target.transform.position;
        }

        public void FixedUpdate()
        {
            if (physicalBehaviour.IsBeingUsedContinuously())
                Use2Continuous();
        }

        public void OnDestroy()
        {
            Destroy(PFX);
        }
    }

    public class WidowGauntlet : MonoBehaviour, Mod.ModAPIPlus.ISwap, Mod.ModAPIPlus.IUse2
    {
        
        PhysicalBehaviour _physicalBehaviour;

        public FixedJoint2D Joint;

        public ProjectileLauncherBehaviour stunner;

        public Collider2D triggerCol;

        EnergyWireBehaviour energyWire;

        bool OnCooldown;
        FixedJoint2D joint;
        DistanceJoint2D taserJoint;
        public List<Transform> stabPoints = new List<Transform>();

        public enum Mode
        {
            StunGun,
            TaserRope,
            knife
        }

        public Mode mode;

        public void Start()
        {
            _physicalBehaviour = GetComponent<PhysicalBehaviour>();
            var newCol = gameObject.AddComponent<BoxCollider2D>();

            newCol.size = new Vector2(0.142849f, 0.2273769f);
            newCol.offset = new Vector2(0, -0.3408651f);
            newCol.isTrigger = true;

            triggerCol = newCol;

            var stabber1 = new GameObject("StabPoint1");

            stabber1.transform.parent = transform;
            stabber1.transform.localPosition = new Vector2(0, -0.267f);

            var stabber2 = new GameObject("StabPoint2");

            stabber2.transform.parent = transform;
            stabber2.transform.localPosition = new Vector2(0, -0.42f);

            var stabber3 = new GameObject("StabPoint3");

            stabber3.transform.parent = transform;
            stabber3.transform.localPosition = new Vector2(-0.056f, -0.313f);

            var stabber4 = new GameObject("StabPoint4");

            stabber4.transform.parent = transform;
            stabber4.transform.localPosition = new Vector2(0.056f, -0.313f);

            stabPoints.Add(stabber1.transform);
            stabPoints.Add(stabber2.transform);
            stabPoints.Add(stabber3.transform);
            stabPoints.Add(stabber4.transform);

            GetComponent<Rigidbody2D>().mass = 0.1f;

            Destroy(GetComponent<Collider2D>());
            gameObject.AddComponent<PolygonCollider2D>();
            Timtam.CreateCollider(GetComponent<SpriteRenderer>());

            stunner = gameObject.AddComponent<ProjectileLauncherBehaviour>();
            stunner.projectilePrefab = ModAPI.FindSpawnable("Stunner").Prefab.GetComponent<ProjectileLauncherBehaviour>().projectilePrefab;
            stunner.launchSound = ModAPI.FindSpawnable("Stunner").Prefab.GetComponent<ProjectileLauncherBehaviour>().launchSound;
            stunner.projectileLaunchStrength = ModAPI.FindSpawnable("Stunner").Prefab.GetComponent<ProjectileLauncherBehaviour>().projectileLaunchStrength;
            stunner.barrelDirection = -transform.up; 
            stunner.barrelPosition = new Vector2(0, -0.5f);
            
            stunner.OnLaunch += fuckyou;
        }

        private void fuckyou(object sender, GameObject e)
        {
            var s2 = e.AddComponent<StunnerBehaviour2>();
            var s = e.GetComponent<StunnerBehaviour>();
            s2.Speed = s.Speed;
            s2.Gravity = s.Gravity;
            s2.ImpactEffect = s.ImpactEffect;
            s2.mask = s.mask;
            s2.right = transform.localScale.x > 0 ? -transform.up : transform.up;
            Destroy(s);
        }

        public void Swap()
        {
            if (mode == Mode.StunGun)
            {
                stunner.enabled = false;
                mode = Mode.TaserRope;
            }
            else if (mode == Mode.TaserRope)
            {
                mode = Mode.knife;
                GetComponent<SpriteRenderer>().sprite = Mod.WidowGauntletKnife;
            }
            else if (mode == Mode.knife)
            {
                GetComponent<SpriteRenderer>().sprite = Mod.WidowGauntlet;
                mode = Mode.StunGun;
                stunner.enabled = true;
            }

            FakeNotifDissapearer.CreateNotification(mode.ToString(), transform.position);
        }

        public void Use(ActivationPropagation activation)
        {
            Vector2 origin = transform.position + transform.up * -0.3f;
            Vector2 direction = -transform.up;
            float maxDistance = 10;

            RaycastHit2D hit = Physics2D.Raycast(origin, direction, maxDistance);
            RaycastHit2D[] hits = Physics2D.RaycastAll(origin, direction, maxDistance);
            bool ishit = true;

            foreach (var hitt in hits)
            {
                if (hitt.collider.TryGetComponent<LimbBehaviour>(out var limb))
                {
                    if (transform.root.GetComponent<PersonBehaviour>() && limb.Person != transform.root.GetComponent<PersonBehaviour>())
                    {
                        hit = hitt; break;
                    }
                }
                else
                {
                    if (hitt.collider.GetComponent<PhysicalBehaviour>())
                        hit = hitt; break;
                }
            }

            if (hits == null)
            {
                ishit = false;
            }

            if (hit.collider != null)
            {
                if (hit.collider.TryGetComponent<LimbBehaviour>(out var limb))
                {
                    if (transform.root.GetComponent<PersonBehaviour>() && limb.Person == transform.root.GetComponent<PersonBehaviour>())
                        ishit = false;
                }
            }

            if (mode == Mode.TaserRope && !taserJoint)
            {
                taserJoint = gameObject.AddComponent<DistanceJoint2D>();
                taserJoint.anchor = new Vector2(0, -0.25f);
                taserJoint.connectedBody = hit.rigidbody;
                taserJoint.autoConfigureDistance = false;
                taserJoint.enableCollision = true;
                taserJoint.connectedAnchor = hit.rigidbody.transform.InverseTransformPoint(hit.point);
                taserJoint.distance = Vector2.Distance(transform.position, hit.point);
                taserJoint.maxDistanceOnly = true;
                taserJoint.breakForce = 5000 * hit.rigidbody.mass;
                JointCreated(taserJoint);
            }else
            {
                Destroy(taserJoint);
                Destroy(energyWire);
            }
        }
         
        public void OnCollisionEnter2D(Collision2D col)
        {
            if (col.collider.TryGetComponent<LimbBehaviour>(out var limb) && col.collider.gameObject.name.Contains("LowerArm") && !Joint & !OnCooldown && !col.collider.GetComponentInChildren<WidowGauntlet>())
                Connect(limb);
        }

        public void Connect(LimbBehaviour connected)
        {
            StartCoroutine(fuckyouunitykys(connected));
        }

        public IEnumerator fuckyouunitykys(LimbBehaviour connected)
        {
            yield return null;
            if (Joint)
            {
                transform.parent = null;
                Destroy(Joint);
            }

            GetComponent<Rigidbody2D>().mass = connected.PhysicalBehaviour.rigidbody.mass;

            GetComponent<SpriteRenderer>().sortingLayerName = connected.GetComponent<SpriteRenderer>().sortingLayerName;
            GetComponent<SpriteRenderer>().sortingOrder = connected.GetComponent<SpriteRenderer>().sortingOrder + 1;

            transform.parent = connected.transform;
            transform.localPosition = Vector3.zero;
            transform.localRotation = Quaternion.identity;
            transform.localScale = Vector3.one;

            Joint = gameObject.AddComponent<FixedJoint2D>();
            Joint.connectedBody = connected.PhysicalBehaviour.rigidbody;
            Joint.autoConfigureConnectedAnchor = false;

            foreach (var col in Joint.connectedBody.transform.root.GetComponentsInChildren<Collider2D>())
                foreach (var ocol in GetComponents<Collider2D>())
                    Physics2D.IgnoreCollision(col, ocol, true);
        }

        public void Use2()
        {
            foreach (var col in Joint.connectedBody.transform.root.GetComponentsInChildren<Collider2D>())
                foreach (var ocol in GetComponents<Collider2D>())
                    Physics2D.IgnoreCollision(col, ocol, false);
            StartCoroutine(Cooldown2());
            Destroy(Joint);
            transform.parent = null;
            GetComponent<Rigidbody2D>().mass = 0.1f;
        }

        public void OnTriggerEnter2D(Collider2D col)
        {
            if (col.gameObject.GetComponent<LimbBehaviour>() && !OnCooldown && mode == Mode.knife && Joint)
            {
                if (transform.root.GetComponent<PersonBehaviour>() != col.transform.root.GetComponent<PersonBehaviour>())
                {
                    if (col.GetComponent<LimbBehaviour>().IsAndroid == false)
                        ModAPI.CreateParticleEffect("BloodExplosion", col.transform.position).transform.localScale = new Vector3(0.2f, 0.2f, 0.2f);
                    else
                        ModAPI.CreateParticleEffect("Zap", col.transform.position).transform.localScale = new Vector3(0.2f, 0.2f, 0.2f);
                    col.GetComponent<LimbBehaviour>().Damage(20);
                }
            }
        }

        public void OnTriggerExit2D(Collider2D col)
        {
            if (col.gameObject.GetComponent<LimbBehaviour>() && !OnCooldown && mode == Mode.knife && Joint)
            {
                if (transform.root.GetComponent<PersonBehaviour>() != col.transform.root.GetComponent<PersonBehaviour>())
                    {
                        if (col.GetComponent<LimbBehaviour>().IsAndroid == false)
                            ModAPI.CreateParticleEffect("BloodExplosion", col.transform.position).transform.localScale = new Vector3(0.2f, 0.2f, 0.2f);
                        else
                            ModAPI.CreateParticleEffect("Zap", col.transform.position).transform.localScale = new Vector3(0.2f, 0.2f, 0.2f);
                        col.GetComponent<LimbBehaviour>().Damage(20);
                    }
            }
        }

        public void OnTriggerStay2D(Collider2D col)
        {
            if (mode == Mode.knife && Joint)
            {
                if (col.GetComponent<LimbBehaviour>() && !OnCooldown)
                {
                    if (transform.root.GetComponent<PersonBehaviour>() != col.transform.root.GetComponent<PersonBehaviour>())
                    {
                        if (joint == null && col.GetComponent<Rigidbody2D>())
                        {
                            joint = transform.parent.gameObject.AddComponent<FixedJoint2D>();
                            joint.connectedBody = col.GetComponent<Rigidbody2D>();
                            joint.breakForce = 35;
                            joint.breakTorque = 35;
                            joint.enableCollision = true;
                        }
                        GetComponent<Rigidbody2D>().velocity = Vector2.zero;
                        GetComponent<Rigidbody2D>().angularVelocity = 0f;

                        if (stabPoints.Count > 0)
                        {
                            foreach (var stabbah in stabPoints)
                            {
                                col.GetComponent<LimbBehaviour>().SkinMaterialHandler.AddDamagePoint(DamageType.Stab, stabbah.transform.position, 8);
                                col.GetComponent<LimbBehaviour>().CirculationBehaviour.CreateBleedingParticle(transform.position, Vector2.zero, 0.4f, true);
                                StartCoroutine(Cooldown());
                            }
                        }
                        else
                        {
                            col.GetComponent<LimbBehaviour>().SkinMaterialHandler.AddDamagePoint(DamageType.Stab, transform.position, 8);
                            col.GetComponent<LimbBehaviour>().CirculationBehaviour.CreateBleedingParticle(transform.position, Vector2.zero, 0.4f, true);
                            StartCoroutine(Cooldown());
                        }

                        if (col.gameObject.GetComponent<Rigidbody2D>().velocity.magnitude >= 25 || gameObject.GetComponent<Rigidbody2D>().velocity.magnitude >= 25 || gameObject.GetComponent<Rigidbody2D>().angularVelocity >= 50)
                        {
                            if (!col.gameObject.GetComponent<LimbBehaviour>().IsDismembered && col.gameObject.GetComponent<LimbBehaviour>().HasJoint)
                            {
                                col.gameObject.GetComponent<LimbBehaviour>().Joint.breakTorque = 0.01f;
                                col.gameObject.GetComponent<Rigidbody2D>().angularVelocity = 90;
                            }
                        }

                        StartCoroutine(Cooldown());
                    }
                }
                else if (!OnCooldown)
                {
                    if (joint == null && col.GetComponent<Rigidbody2D>())
                    {
                        if (col.GetComponent<Rigidbody2D>().freezeRotation)
                        {
                            joint = transform.parent.gameObject.AddComponent<FixedJoint2D>();
                            joint.connectedBody = col.GetComponent<Rigidbody2D>();
                            joint.breakForce = 35;
                            joint.breakTorque = 35;
                            joint.enableCollision = true;
                        }
                    }
                    GetComponent<Rigidbody2D>().velocity = Vector2.zero;
                    GetComponent<Rigidbody2D>().angularVelocity = 0f;
                }
            }
        }

        public IEnumerator Cooldown()
        {
            OnCooldown = true;
            yield return new WaitForSeconds(0.15f);
            OnCooldown = false;
        }

        public IEnumerator Cooldown2()
        {
            OnCooldown = true;
            yield return new WaitForSeconds(1f);
            OnCooldown = false;
        }

        public void FixedUpdate()
        {
            _physicalBehaviour.ObjectArea = 0.001f;

            if (Joint)
            {
                Joint.anchor = Vector2.zero;
                Joint.connectedAnchor = Vector2.zero;
            }

            if (energyWire && taserJoint)
            {
                energyWire.WireColor = new Color(0.001f, 0.001f, UnityEngine.Random.Range(0.001f, 0.7f));
                taserJoint.connectedBody.GetComponent<PhysicalBehaviour>().charge = 5;
            }
        }

        public class StunnerBehaviour2 : MonoBehaviour
        {
            public float Speed = 1f;

            public float Gravity = 1f;

            public GameObject ImpactEffect;

            public LayerMask mask;

            private float t;

            public Vector3 right;

            public void Update()
            {
                right.y -= t;
                right.Normalize();
                float num = Speed * Time.deltaTime;
                RaycastHit2D raycastHit2D = Physics2D.Raycast(base.transform.position, right, num, mask);
                if ((bool)raycastHit2D)
                {
                    Destroy(base.gameObject);
                    Instantiate(ImpactEffect, base.transform.position, Quaternion.identity);
                    raycastHit2D.transform.SendMessage("StunImpact", new Shot(raycastHit2D.normal, raycastHit2D.point, 0f), SendMessageOptions.DontRequireReceiver);
                }
                else
                {
                    base.transform.position += right * num;
                }

                t += Time.deltaTime * 0.1f * Gravity;
            }
        }

        void JointCreated(DistanceJoint2D joint)
        {
            energyWire = joint.gameObject.AddComponent<EnergyWireBehaviour>();
            energyWire.WireColor = new Color(0.001f, 0.001f, 0.001f);
            energyWire.WireMaterial = Instantiate(ModAPI.FindMaterial("VeryBright"));
            energyWire.WireWidth = 0.055f;
            energyWire.typedJoint = joint;
            energyWire.WireMaterial.mainTexture = Mod.TaserRope.texture;
            energyWire.WireMaterial.mainTexture.wrapMode = TextureWrapMode.Repeat;
        }
    }

