            Orbit,
            Launched,
            Returning
        }

        private class RingData
        {
            public GameObject go;
            public Rigidbody2D rb;
            public Collider2D[] cols;
            public FixedJoint2D joint;
            public float orbitAngle;
            public RingState state;

            public Rigidbody2D homingTarget;
            public Collider2D targetCollider;
            public Vector2 targetPoint;
            public bool hasTarget;
            public Rings owner;
            public int index;
            public float launchStartTime;
            public Vector3 Jitter;
        }

        private class RingCollisionForwarder : UnityEngine.MonoBehaviour
        {
            public Rings owner;
            public int index;

            public bool cooldown = false;

            private void OnCollisionEnter2D(Collision2D col)
            {
                if (owner == null || cooldown) return;

                StartCoroutine(CooldownCoroutine());

                var data = owner._rings[index];
                if (owner.mode == Mode.Sword)
                {
                    if (col.rigidbody.bodyType == RigidbodyType2D.Dynamic)
                    {
                        ModAPI.CreateParticleEffect("Sparks", col.contacts[0].point);
                        CameraShakeBehaviour.main.Shake(col.relativeVelocity.magnitude < 3 ? col.relativeVelocity.magnitude : 3f, col.contacts[0].point);
                        col.rigidbody.AddForce(GetComponent<Rigidbody2D>().velocity);
                    }
                }

                if (owner.mode == Mode.Shoot && data.state == RingState.Launched && data.hasTarget)
                {
                    if (data.targetCollider != null && col.collider == data.targetCollider)
                    {
                        if (col.rigidbody.bodyType == RigidbodyType2D.Dynamic)
                        {
                            ModAPI.CreateParticleEffect("BlasterImpact", col.contacts[0].point);
                            ModAPI.CreateParticleEffect("HugeZap", col.contacts[0].point);
                            CameraShakeBehaviour.main.Shake(col.relativeVelocity.magnitude < 3 ? col.relativeVelocity.magnitude : 3f, col.contacts[0].point);
                            col.rigidbody.AddForce(GetComponent<Rigidbody2D>().velocity * 2);
                            if (col.transform.TryGetComponent<PhysicalBehaviour>(out var phys))
                                phys.charge += col.relativeVelocity.magnitude;
                        }
                    }
                    else if (data.homingTarget != null && col.rigidbody == data.homingTarget)
                    {
                        if (col.rigidbody.bodyType == RigidbodyType2D.Dynamic)
                        {
                            ModAPI.CreateParticleEffect("Flash", col.contacts[0].point);
                            ModAPI.CreateParticleEffect("HugeZap", col.contacts[0].point);
                            CameraShakeBehaviour.main.Shake(col.relativeVelocity.magnitude < 3 ? col.relativeVelocity.magnitude : 3f, col.contacts[0].point);
                            col.rigidbody.AddForce(GetComponent<Rigidbody2D>().velocity * 2);
                            if (col.transform.TryGetComponent<PhysicalBehaviour>(out var phys))
                                phys.charge += col.relativeVelocity.magnitude;
                        }
                    }
                }
            }

            public IEnumerator CooldownCoroutine()
            {
                cooldown = true;
                yield return new WaitForSeconds(0.5f);
                cooldown = false;
            }
        }

        public static Rings SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<Rings>();
            power.Name = "Five Rings";
            power.Description = "Allows the user to use five of the ten rings.";
            power.icon = icon;
            power.targetLimb = power.name.Contains("Front") ? TargettedLimb.FrontArm : TargettedLimb.BackArm;

            foreach(var limb in Person.Limbs)
            {
                limb.PhysicalBehaviour.ForceNoCharge = true;
            }

            return power;
        }
        
        public void OnCollisionEnter2D(Collision2D col)
        {
            StartCoroutine(CooldownCoroutine());

            if (mode == Mode.onArm)
            {
                if (col.rigidbody.bodyType == RigidbodyType2D.Dynamic)
                {
                    ModAPI.CreateParticleEffect("BlasterImpact", col.contacts[0].point);
                    CameraShakeBehaviour.main.Shake(col.relativeVelocity.magnitude < 4 ? col.relativeVelocity.magnitude : 4f, col.contacts[0].point);
                    col.rigidbody.AddForce(GetComponent<Rigidbody2D>().velocity);

                    if (col.transform.TryGetComponent<PhysicalBehaviour>(out var phys))
                        phys.charge += col.relativeVelocity.magnitude;
                }
            }
        }

        public override void Start()
        {
            base.Start();

            _limbRb = GetComponent<Rigidbody2D>();
            _ownerCols = transform.root.GetComponentsInChildren<Collider2D>(true);

            Ring1 = ModAPI.CreatePhysicalObject("Ring", Mod.Ring);
            Ring2 = ModAPI.CreatePhysicalObject("Ring", Mod.Ring);
            Ring3 = ModAPI.CreatePhysicalObject("Ring", Mod.Ring);
            Ring4 = ModAPI.CreatePhysicalObject("Ring", Mod.Ring);
            Ring5 = ModAPI.CreatePhysicalObject("Ring", Mod.Ring);

            SetupRing(Ring1, 0);
            SetupRing(Ring2, 1);
            SetupRing(Ring3, 2);
            SetupRing(Ring4, 3);
            SetupRing(Ring5, 4);

            ApplyGlobalIgnoreRules();
            RaiseRingSortingOrderAboveOwner();

            _swordLine = CreateSwordLineRenderer();

            mode = Mode.onArm;
            EnterOnArmMode();
        }

        public void Swap()
        {
            if (mode == Mode.onArm)
            {
                mode = Mode.Sword;
                EnterSwordMode();
            }
            else if (mode == Mode.Sword)
            {
                mode = Mode.Shoot;
                EnterShootMode();
            }
            else if (mode == Mode.Shoot)
            {
                mode = Mode.onArm;
                EnterOnArmMode();
            }
            FakeNotifDissapearer.CreateNotification(mode.ToString(), transform.position);
        }

        public void Use()
        {
            if (mode != Mode.Shoot) return;

            int idx = GetFirstOrbitingRingIndex();
            if (idx < 0) return;

            var origin = (Vector2)transform.position;
            var dir = -(Vector2)transform.up;
            var hits = Physics2D.RaycastAll(origin, dir, 250f);
            Collider2D targetCol = null;
            Rigidbody2D targetBody = null;
            Vector2 targetPoint = origin + dir * 10f;

            for (int i = 0; i < hits.Length; i++)
            {
                var h = hits[i];
                if (h.collider == null) continue;
                if (IsColliderOwner(h.collider)) continue;
                if (IsColliderRing(h.collider)) continue;

                targetCol = h.collider;
                targetBody = h.rigidbody != null && h.rigidbody.bodyType == RigidbodyType2D.Dynamic ? h.rigidbody : null;
                targetPoint = h.point;
                break;
            }

            LaunchRing(idx, targetPoint, targetCol, targetBody);
        }

        private void FixedUpdate()
        {
            float dt = Time.fixedDeltaTime;
            for (int i = 0; i < _rings.Count; i++)
            {
                var r = _rings[i];
                if (r == null || r.rb == null) continue;

                if (mode == Mode.onArm)
                    r.rb.mass = .00001f;

                switch (r.state)
                {
                    case RingState.SwordFollow:
                        {
                            Vector2 baseTarget = (Vector2)transform.position - (Vector2)transform.up * (SwordBaseBelow + (i * SwordStep));

                            Vector2 limbVel = _limbRb != null ? _limbRb.velocity : Vector2.zero;
                            baseTarget += limbVel * 0.035f;

                            float angVel = _limbRb != null ? _limbRb.angularVelocity : 0f;
                            Vector2 right = new Vector2(transform.right.x, transform.right.y);
                            baseTarget += right * (angVel * 0.0025f);

                            PDMove(r, baseTarget, dt, true);
                            break;
                        }
                    case RingState.Orbit:
                        {
                            r.orbitAngle += OrbitSpeed * dt;
                            Vector2 target = (Vector2)transform.position + new Vector2(Mathf.Cos(r.orbitAngle), Mathf.Sin(r.orbitAngle)) * OrbitRadius;
                            PDMove(r, target, dt, false);
                            break;
                        }
                    case RingState.Launched:
                        {
                            Vector2 pos = r.rb.position;

                            if (r.homingTarget != null)
                            {
                                Vector2 tgt = r.homingTarget.position;
                                Vector2 to = (tgt - pos);
                                Vector2 acc = to.normalized * HomingAccel;
                                r.rb.velocity = Vector2.ClampMagnitude(r.rb.velocity + acc * dt, LaunchSpeed * 1.2f);
                            }
                            else
                            {
                                Vector2 to = (r.targetPoint - pos);
                                Vector2 desiredVel = to.normalized * LaunchSpeed;
                                r.rb.velocity = Vector2.Lerp(r.rb.velocity, desiredVel, 10f * dt);

                                if (to.magnitude < 0.15f)
                                {
                                    BeginReturn(i);
                                }
                            }

                            if (Time.time - r.launchStartTime > 4f)
                            {
                                BeginReturn(i);
                            }
                            break;
                        }
                    case RingState.Returning:
                        {
                            Vector2 target = (Vector2)transform.position + new Vector2(Mathf.Cos(r.orbitAngle), Mathf.Sin(r.orbitAngle)) * OrbitRadius;
                            PDMove(r, target, dt, false);
                            if (((Vector2)r.rb.position - target).sqrMagnitude < ReturnThreshold * ReturnThreshold)
                            {
                                r.state = RingState.Orbit;
                                r.hasTarget = false;
                                r.homingTarget = null;
                                r.targetCollider = null;
                            }
                            break;
                        }
                }
            }

            if (_swordLine == null) return;

            bool swordActive = mode == Mode.Sword;
            if (_swordLine.enabled != swordActive)
                _swordLine.enabled = swordActive;

            if (!swordActive) return;

            int count = _rings.Count;
            if (count == 0) return;


            for (int i = 0; i < count; i++)
            {
                var r = _rings[i];
                if (r == null || r.rb == null) continue;

                Vector3 basePos = r.rb.position;

                r.Jitter = new Vector2(r.go.transform.position.x + UnityEngine.Random.Range(-0.25f, 0.25f), r.go.transform.position.y + UnityEngine.Random.Range(-0.25f, 0.25f));
            }
        }

        public void Update()
        {
            if (_swordLine == null) return;

            bool swordActive = mode == Mode.Sword;
            if (_swordLine.enabled != swordActive)
                _swordLine.enabled = swordActive;

            if (!swordActive) return;

            int count = _rings.Count;
            if (count == 0) return;

            _swordLine.positionCount = count;

            for (int i = 0; i < count; i++)
            {
                var r = _rings[i];
                if (r == null || r.rb == null) continue;

                Vector3 basePos = r.rb.position;


                if(Time.timeScale > 0.01f)
                    _swordLine.SetPosition(i, r.Jitter);
            }
        }

        private void EnterOnArmMode()
        {
            if (_swordLine != null) _swordLine.enabled = false;

            for (int i = 0; i < _rings.Count; i++)
            {
                var r = _rings[i];
                if (r == null) continue;

                if (r.joint == null)
                {
                    r.joint = r.go.AddComponent<FixedJoint2D>();
                }

                var worldPos = transform.position + (Vector3)transform.up * (AttachedUpOffset + _attachOffsets[i]);
                r.rb.position = worldPos;
                r.go.transform.rotation = transform.rotation;

                r.joint.connectedBody = _limbRb;
                r.joint.autoConfigureConnectedAnchor = true;
                r.joint.enableCollision = false;

                r.state = RingState.Attached;

                r.rb.gravityScale = 0f;
                r.rb.mass = 0.0001f;
                r.rb.drag = 0f;
                r.rb.angularDrag = 0f;
            }
        }

        private void EnterSwordMode()
        {
            if (_swordLine != null) _swordLine.enabled = true;

            for (int i = 0; i < _rings.Count; i++)
            {
                var r = _rings[i];
                if (r == null) continue;

                DestroyJointIfAny(r);
                SetRingCollidersEnabled(r, true);

                r.rb.gravityScale = 0f;
                r.rb.mass = AttachMass;
                r.rb.drag = 0.1f;
                r.rb.angularDrag = 0.05f;

                r.rb.velocity += (Vector2)transform.right * 0.5f;

                r.state = RingState.SwordFollow;
            }
        }

        private void EnterShootMode()
        {
            if (_swordLine != null) _swordLine.enabled = false;

            int n = _rings.Count;
            for (int i = 0; i < n; i++)
            {
                var r = _rings[i];
                if (r == null) continue;

                DestroyJointIfAny(r);
                SetRingCollidersEnabled(r, true);

                r.rb.gravityScale = 0f;
                r.rb.mass = AttachMass;
                r.orbitAngle = ((Mathf.PI * 2f) / n) * i;
                r.state = RingState.Orbit;
                r.hasTarget = false;
                r.homingTarget = null;
                r.targetCollider = null;
            }
        }

        private void LaunchRing(int index, Vector2 point, Collider2D col, Rigidbody2D body)
        {
            var r = _rings[index];
            if (r.state != RingState.Orbit) return;

            r.state = RingState.Launched;
            r.hasTarget = true;
            r.targetPoint = point;
            r.targetCollider = col;
            r.homingTarget = body;
            r.launchStartTime = Time.time;

            Vector2 dir = ((body != null ? (Vector2)body.position : point) - r.rb.position).normalized;
            r.rb.velocity = dir * LaunchSpeed;
        }

        private void BeginReturn(int index)
        {
            var r = _rings[index];
            r.state = RingState.Returning;
            r.hasTarget = false;
            r.homingTarget = null;
            r.targetCollider = null;
            r.orbitAngle = Mathf.Atan2(r.rb.position.y - transform.position.y, r.rb.position.x - transform.position.x);
        }

        private int GetFirstOrbitingRingIndex()
        {
            for (int i = 0; i < _rings.Count; i++)
            {
                if (_rings[i].state == RingState.Orbit) return i;
            }
            return -1;
        }

        private void PDMove(RingData r, Vector2 target, float dt, bool swordMode)
        {
            Vector2 pos = r.rb.position;
            Vector2 vel = r.rb.velocity;

            float kp = swordMode ? SwordFollowKp : FollowKp;
            float kd = swordMode ? SwordFollowKd : FollowKd;

            Vector2 err = target - pos;
            Vector2 desiredF = kp * err - kd * vel;

            if (swordMode)
            {
                Vector2 limbVel = _limbRb != null ? _limbRb.velocity : Vector2.zero;
                float limbSpeed = limbVel.magnitude;

                Vector2 boost = limbVel.normalized * Mathf.Clamp(limbSpeed * 0.9f, 0f, 12f);
                desiredF += boost;

                float angVel = _limbRb != null ? _limbRb.angularVelocity : 0f;
                Vector2 tangential = new Vector2(transform.right.x, transform.right.y) * (angVel * 0.35f);
                desiredF += tangential;
            }

            r.rb.AddForce(desiredF * r.rb.mass, ForceMode2D.Force);

            if (r.rb.velocity.sqrMagnitude > 0.001f)
            {
                float targetRot = Mathf.Atan2(r.rb.velocity.y, r.rb.velocity.x) * Mathf.Rad2Deg - 90f;
                float current = r.rb.rotation;
                float lerped = Mathf.LerpAngle(current, targetRot, swordMode ? 18f * dt : 10f * dt);
                r.rb.MoveRotation(lerped);
            }
        }

        private void SetupRing(GameObject ring, int index)
        {
            ring.transform.position = transform.position;
            ring.transform.rotation = transform.rotation;

            var rb = ring.GetComponent<Rigidbody2D>();
            if (rb == null) rb = ring.AddComponent<Rigidbody2D>();
            rb.gravityScale = 0f;
            rb.mass = 0.0001f;
            rb.drag = 0f;
            rb.angularDrag = 0f;
            rb.collisionDetectionMode = CollisionDetectionMode2D.Continuous;
            rb.interpolation = RigidbodyInterpolation2D.Interpolate;

            var cols = ring.GetComponentsInChildren<Collider2D>(true);
            foreach (var c in cols)
            {
                c.isTrigger = false;
            }

            ring.GetComponent<PhysicalBehaviour>().Properties = Instantiate(PhysicalProperty.Rod);
            ring.GetComponent<PhysicalBehaviour>().Properties.HardImpact = new AudioClip[0];
            ring.GetComponent<PhysicalBehaviour>().Properties.SparksOnSlide = false;
            ring.GetComponent<PhysicalBehaviour>().Properties.SlidingLoop = null;

            var forwarder = ring.GetComponent<RingCollisionForwarder>();
            if (forwarder == null) forwarder = ring.AddComponent<RingCollisionForwarder>();
            forwarder.owner = this;
            forwarder.index = index;

            var data = new RingData
            {
                go = ring,
                rb = rb,
                cols = cols,
                joint = null,
                orbitAngle = 0f,
                state = RingState.Attached,
                homingTarget = null,
                targetCollider = null,
                hasTarget = false,
                owner = this,
                index = index
            };
            _rings.Add(data);
        }

        private void DestroyJointIfAny(RingData r)
        {
            if (r.joint != null)
            {
                UnityEngine.Object.Destroy(r.joint);
                r.joint = null;
            }
        }

        private void SetRingCollidersEnabled(RingData r, bool enabled)
        {
            if (r.cols == null) return;
            for (int i = 0; i < r.cols.Length; i++)
            {
                r.cols[i].enabled = enabled;
            }
        }

        private void ApplyGlobalIgnoreRules()
        {
            for (int i = 0; i < _rings.Count; i++)
            {
                var ringCols = _rings[i].cols;
                for (int c = 0; c < ringCols.Length; c++)
                {
                    for (int oc = 0; oc < _ownerCols.Length; oc++)
                    {
                        Physics2D.IgnoreCollision(ringCols[c], _ownerCols[oc], true);
                    }
                }
            }

            for (int i = 0; i < _rings.Count; i++)
            {
                var aCols = _rings[i].cols;
                for (int j = i + 1; j < _rings.Count; j++)
                {
                    var bCols = _rings[j].cols;
                    for (int ac = 0; ac < aCols.Length; ac++)
                    {
                        for (int bc = 0; bc < bCols.Length; bc++)
                        {
                            Physics2D.IgnoreCollision(aCols[ac], bCols[bc], true);
                        }
                    }
                }
            }

            var allRingsBehaviours = transform.root.GetComponentsInChildren<Rings>(true);
            for (int rbi = 0; rbi < allRingsBehaviours.Length; rbi++)
            {
                var other = allRingsBehaviours[rbi];
                if (other == null || other == this) continue;

                for (int i = 0; i < _rings.Count; i++)
                {
                    var myCols = _rings[i].cols;
                    for (int j = 0; j < other._rings.Count; j++)
                    {
                        var otherCols = other._rings[j].cols;
                        for (int mc = 0; mc < myCols.Length; mc++)
                        {
                            for (int oc = 0; oc < otherCols.Length; oc++)
                            {
                                Physics2D.IgnoreCollision(myCols[mc], otherCols[oc], true);
                            }
                        }
                    }
                }
            }
        }

        private bool IsColliderOwner(Collider2D col)
        {
            for (int i = 0; i < _ownerCols.Length; i++)
            {
                if (col == _ownerCols[i]) return true;
            }
            return false;
        }

        private bool IsColliderRing(Collider2D col)
        {
            for (int i = 0; i < _rings.Count; i++)
            {
                var rd = _rings[i];
                for (int j = 0; j < rd.cols.Length; j++)
                {
                    if (col == rd.cols[j]) return true;
                }
            }
            return false;
        }

        private void RaiseRingSortingOrderAboveOwner()
        {
            var ownerSr = GetComponent<SpriteRenderer>();
            int baseOrder = ownerSr.sortingOrder;
            string baseLayer = ownerSr.sortingLayerName;

            for (int i = 0; i < _rings.Count; i++)
            {
                var ringSr = _rings[i].go.GetComponent<SpriteRenderer>();
                ringSr.sortingLayerName = baseLayer;
                ringSr.sortingOrder = baseOrder + 1;

                var r = _rings[i];
                if (r == null) continue;

                if (r.joint == null)
                {
                    r.joint = r.go.AddComponent<FixedJoint2D>();
                }
            }
        }

        private LineRenderer CreateSwordLineRenderer()
        {
            var go = new GameObject("RingsSwordLine");
            go.transform.SetParent(transform, false);
            var lr = go.AddComponent<LineRenderer>();
            lr.enabled = false;
            lr.positionCount = 2;
            lr.material = ModAPI.FindMaterial("VeryBright");
            lr.widthMultiplier = 0.01f;
            lr.sortingLayerName = GetComponent<SpriteRenderer>().sortingLayerName;
            lr.sortingOrder = GetComponent<SpriteRenderer>().sortingOrder + 2;
            lr.startColor = new Color(0.3f, 0.7f, 1f, 0.4f);
            lr.endColor = new Color(0.3f, 0.7f, 1f, 0.4f);
            lr.numCapVertices = 2;
            lr.numCornerVertices = 2;
            return lr;
        }

        public IEnumerator CooldownCoroutine()
        {
            cooldown = true;
            yield return new WaitForSeconds(0.5f);
            cooldown = false;
        }
    }

    public class Bow : MonoBehaviour, Mod.ModAPIPlus.ISwap, Messages.IOnGripped, Messages.IOnDrop
    {
        public float LoadTime = 0.25f;
        public float CurrentLoad = 0f;

        PhysicalBehaviour phys;
        public LineRenderer BowString;

        public GameObject FakeArrow;

        Transform BowPos1;
        Transform BowPos2;
        Transform BowPos3;

        const float MaxDrawDistance = 0.45f;
        const float FakeArrowForwardOffset = 0.3f;

        public List<GripBehaviour> grippers = new List<GripBehaviour>();

        public void OnGripped(GripBehaviour grip)
        {
            foreach(var gripper in grippers)
                if(gripper == null)
                    grippers.Remove(gripper);

            grippers.Add(grip);
        }

        public void OnDrop(GripBehaviour grip)
        {
            foreach (var gripper in grippers)
                if (gripper == null)
                    grippers.Remove(gripper);

            grippers.Remove(grip);
        }

        public enum ArrowType
        {
            Normal,
            Explosive,
            Stun,
            Electric,
            Punching
        }

        public void Swap()
        {
            if (arrowType == ArrowType.Normal)
                arrowType = ArrowType.Explosive;
            else if (arrowType == ArrowType.Explosive)
                arrowType = ArrowType.Stun;
            else if (arrowType == ArrowType.Stun)
                arrowType = ArrowType.Electric;
            else if (arrowType == ArrowType.Electric)
                arrowType = ArrowType.Punching;
            else if (arrowType == ArrowType.Punching)
                arrowType = ArrowType.Normal;

            FakeNotifDissapearer.CreateNotification(arrowType.ToString(), transform.position);
        }

        ArrowType arrowType = ArrowType.Normal;

        public void Start()
        {
            phys = GetComponent<PhysicalBehaviour>();
            BowString = gameObject.AddComponent<LineRenderer>();
            BowString.positionCount = 3;
            BowString.startWidth = 0.01f;
            BowString.endWidth = 0.01f;
            BowString.material = new Material(Shader.Find("Sprites/Default"));
            BowString.startColor = new Color(1, 1, 1, 0.7f);
            BowString.endColor = new Color(1, 1, 1, 0.7f);
            BowString.numCapVertices = 5;
            BowString.numCornerVertices = 5;
            BowString.SetPosition(0, transform.position + transform.up * 0.5f);
            BowString.SetPosition(1, transform.position);
            BowString.SetPosition(2, transform.position - transform.up * 0.5f);

            BowString.sortingLayerName = GetComponent<SpriteRenderer>().sortingLayerName;
            BowString.sortingOrder = GetComponent<SpriteRenderer>().sortingOrder - 1;

            BowPos1 = new GameObject("bowpos1").transform;
            BowPos1.SetParent(transform);
            BowPos1.localPosition = new Vector2(-4, 21) * ModAPI.PixelSize;

            BowPos2 = new GameObject("bowpos2").transform;
            BowPos2.SetParent(transform);
            BowPos2.localPosition = new Vector2(-4, -21) * ModAPI.PixelSize;

            BowPos3 = new GameObject("bowpos3").transform;
            BowPos3.SetParent(transform);
            BowPos3.localPosition = new Vector2(-4, 0) * ModAPI.PixelSize;
        }

        public void Update()
        {
            BowString.SetPosition(0, BowPos1.position);
            BowString.SetPosition(2, BowPos2.position);

            if (phys.StartedBeingUsedContinuously())
            {
                StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.BowStart, UnityEngine.Random.Range(0.8f, 1.2f)));
                FakeArrow = new GameObject("FakeArrow");
                var sr = FakeArrow.AddComponent<SpriteRenderer>();
                sr.sortingLayerName = GetComponent<SpriteRenderer>().sortingLayerName;
                sr.sortingOrder = GetComponent<SpriteRenderer>().sortingOrder + 1;
                sr.sprite = arrowType == ArrowType.Normal ? Mod.NormalArrow :
                            arrowType == ArrowType.Explosive ? Mod.ExplosiveArrow :
                            arrowType == ArrowType.Stun ? Mod.StunArrow :
                            arrowType == ArrowType.Electric ? Mod.ElectricArrow : Mod.PunchArrow;
                FakeArrow.transform.SetParent(transform, false);
            }

            if (phys.StoppedBeingUsedContinuously())
            {
                if (CurrentLoad > 0.01f)
                {
                    ModAPI.CreateParticleEffect("Vapor", transform.position);
                    StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Bow, UnityEngine.Random.Range(0.8f, 1.2f)));

                    var arrow = Instantiate(ModAPI.FindSpawnable("Crossbow Bolt").Prefab);
                    arrow.GetComponent<PhysicalBehaviour>().SpawnSpawnParticles = false;
                    if (transform.localScale.x < 0)
                        arrow.transform.localScale = new Vector3(-arrow.transform.localScale.x, arrow.transform.localScale.y, arrow.transform.localScale.z);
                    arrow.AddComponent<DebrisComponent>();
                    Physics2D.IgnoreCollision(arrow.GetComponent<Collider2D>(), GetComponent<Collider2D>());

                    foreach (var gripper in grippers)
                        foreach (var col in gripper.transform.root.GetComponentsInChildren<Collider2D>())
                            Physics2D.IgnoreCollision(col, arrow.GetComponent<Collider2D>(), true);

                    arrow.GetComponent<SpriteRenderer>().sprite = arrowType == ArrowType.Normal ? Mod.NormalArrow :
                                                                arrowType == ArrowType.Explosive ? Mod.ExplosiveArrow :
                                                                arrowType == ArrowType.Stun ? Mod.StunArrow :
                                                                arrowType == ArrowType.Electric ? Mod.ElectricArrow : Mod.PunchArrow;

                    if(arrowType == ArrowType.Explosive)
                    {
                        arrow.AddComponent<ExplosiveArrow>();
                    }
                    else if (arrowType == ArrowType.Stun)
                    {
                        arrow.AddComponent<ShockArrow>();
                    }
                    else if (arrowType == ArrowType.Electric)
                    {
                        arrow.AddComponent<ElectricArrow>();
                    }
                    else if (arrowType == ArrowType.Punching)
                    {
                        arrow.AddComponent<PunchArrow>();
                    }

                    var fwd = GetForward();
                    arrow.transform.position = BowPos3.position + fwd * 0.5f;
                    arrow.transform.rotation = transform.rotation;

                    var arrowPhys = arrow.GetComponent<PhysicalBehaviour>();
                    arrowPhys.rigidbody.velocity = (Vector3)phys.rigidbody.velocity + fwd * (60f * Mathf.Clamp01(CurrentLoad / LoadTime));
                }

                CurrentLoad = 0f;
                if (FakeArrow != null) Destroy(FakeArrow);
                FakeArrow = null;
            }

            if (phys.IsBeingUsedContinuously())
            {
                CurrentLoad += Time.deltaTime;
                if (CurrentLoad > LoadTime) CurrentLoad = LoadTime;

                UpdateStringAndArrow();
            }
            else
            {
                BowString.SetPosition(1, BowPos3.position);
            }
        }

        private void UpdateStringAndArrow()
        {
            var fwd = GetForward();
            var t = Mathf.Clamp01(CurrentLoad / LoadTime);

            BowString.SetPosition(1, BowPos3.position - fwd * (MaxDrawDistance * t));

            if (FakeArrow != null)
            {
                FakeArrow.transform.position = BowPos3.position + fwd * (FakeArrowForwardOffset - MaxDrawDistance * t);
                FakeArrow.transform.rotation = transform.rotation;
            }
        }

        private Vector3 GetForward()
        {
            return transform.right * (transform.lossyScale.x >= 0f ? 1f : -1f);
        }

        public class ExplosiveArrow : MonoBehaviour
        {
            private Rigidbody2D rigidbody;
            FixedJoint2D Joint;
            GripBehaviour holder;
            GameObject ExplosiveActive;

            public IEnumerator ToggleSpriteRenderer(GameObject obj)
            {
                var spriteRenderer = obj.GetComponent<SpriteRenderer>();
                while (true)
                {
                    if (spriteRenderer != null)
                    {
                        spriteRenderer.enabled = !spriteRenderer.enabled;
                    }
                    yield return new WaitForSeconds(0.3f);
                }
            }

            public void Start()
            {
                GetComponent<PhysicalBehaviour>().Properties = PhysicalProperty.Rod;
                GetComponent<PhysicalBehaviour>().rigidbody.mass = 1;
                GetComponent<PhysicalBehaviour>().TrueInitialMass = 1;

                var thing2 = new GameObject("ExplosionLight");
                thing2.transform.parent = transform;
                thing2.transform.localPosition = new Vector2(8, 0) * ModAPI.PixelSize;
                thing2.transform.localScale = Vector3.one;
                thing2.transform.localRotation = Quaternion.identity;

                var sr2 = thing2.AddComponent<SpriteRenderer>();
                sr2.sprite = Mod.Pixel;
                sr2.sortingLayerName = GetComponent<SpriteRenderer>().sortingLayerName;
                sr2.sortingOrder = GetComponent<SpriteRenderer>().sortingOrder + 1;
                sr2.material = ModAPI.FindMaterial("VeryBright");

                thing2.SetActive(false);

                ExplosiveActive = thing2;
                StartCoroutine(ToggleSpriteRenderer(ExplosiveActive));
                rigidbody = gameObject.GetComponent<Rigidbody2D>();
                rigidbody.collisionDetectionMode = CollisionDetectionMode2D.Continuous;

                var phys = gameObject.GetComponent<PhysicalBehaviour>();
                phys.ForceContinuous = true;
            }

            public void OnJointBreak2D(Joint2D brokenJoint)
            {
                if (brokenJoint.connectedBody.gameObject.TryGetComponent<LimbBehaviour>(out var limb))
                {
                    foreach (var limbs in limb.Person.Limbs)
                    {
                        if (holder.GetComponent<LimbBehaviour>().Person != limb.Person)
                            Physics2D.IgnoreCollision(limbs.GetComponent<Collider2D>(), gameObject.GetComponent<Collider2D>(), false);
                    }
                }

                Joint = null;
            }

            public IEnumerator ChangeBreakForce()
            {
                yield return new WaitForSeconds(0.2f);
                Joint.breakForce = 150;
            }

            public void OnCollisionEnter2D(Collision2D collision)
            {
                if (collision.relativeVelocity.magnitude > 6 && Joint == null)
                {
                    Joint = gameObject.AddComponent<FixedJoint2D>();
                    Joint.connectedBody = collision.rigidbody;
                    StartCoroutine(ChangeBreakForce());
                    GetComponent<Rigidbody2D>().velocity = collision.otherRigidbody.velocity;

                    StartCoroutine(Explode());

                    if (collision.gameObject.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        limb.SkinMaterialHandler.AddDamagePoint(DamageType.Stab, Vector2.Lerp(collision.collider.transform.position, gameObject.transform.position, 0.5f), collision.relativeVelocity.magnitude);
                        limb.Damage(collision.relativeVelocity.magnitude);
                        ModAPI.CreateParticleEffect("BloodExplosion", collision.contacts[0].point).GetComponent<ParticleSystem>().startColor = limb.CirculationBehaviour.GetComputedColor();
                        foreach (var limbs in limb.Person.Limbs)
                        {
                            if (limb.GetComponent<Collider2D>())
                                Physics2D.IgnoreCollision(limbs.GetComponent<Collider2D>(), gameObject.GetComponent<Collider2D>(), true);
                        }
                    }
                }
            }

            public IEnumerator Explode()
            {
                ExplosiveActive.SetActive(true);
                ExplosiveActive.GetComponent<SpriteRenderer>().enabled = true;

                StartCoroutine(PlaySound(Mod.BatarangCharge));

                yield return new WaitForSeconds(2f);

                ExplosionCreator.Explode(transform.position, 5);

                Destroy(gameObject);
            }

            IEnumerator PlaySound(AudioClip SoundToPlay)
            {
                var sound = new GameObject();
                sound.name = "SFX";
                sound.transform.position = gameObject.transform.position;
                sound.AddComponent<AudioSource>();
                sound.GetComponent<AudioSource>().playOnAwake = false;
                sound.GetComponent<AudioSource>().clip = SoundToPlay;
                sound.GetComponent<AudioSource>().spatialBlend = 1;
                sound.GetComponent<AudioSource>().volume = 5f;
                sound.AddComponent<AudioDistortionFilter>().distortionLevel = 0.85f;
                sound.AddComponent<AudioSourceTimeScaleBehaviour>();
                sound.GetComponent<AudioSource>().Play();

                yield return new WaitForSeconds(SoundToPlay.length);

                Destroy(sound);
            }
        }

