        public class PunchArrow : MonoBehaviour
        {
            public void Start()
            {
                GetComponent<PhysicalBehaviour>().Properties = PhysicalProperty.Insulator;
                GetComponent<PhysicalBehaviour>().rigidbody.mass = 0.4f;
                GetComponent<PhysicalBehaviour>().TrueInitialMass = 0.4f;
            }

            void OnCollisionEnter2D(Collision2D collision)
            {
                Vector2 relativeVelocity = collision.relativeVelocity;

                float impactStrength = relativeVelocity.magnitude * 3;

                if (collision.gameObject.GetComponent<Rigidbody2D>() && collision.relativeVelocity.magnitude > 3)
                {
                    Vector2 directionToThisObject = (GetComponent<Rigidbody2D>().position - collision.rigidbody.position).normalized;

                    float dotProduct = Vector2.Dot(relativeVelocity, directionToThisObject);

                    if (dotProduct > 0)
                    {
                        collision.gameObject.GetComponent<Rigidbody2D>().velocity += -relativeVelocity.normalized * impactStrength;
                        CameraShakeBehaviour.main.Shake(6, transform.position);

                        ModAPI.CreateParticleEffect("Vapor", transform.position).transform.localScale = Vector3.one * 3;
                    }

                }
            }
        }
    }

    public class AstralProjection : Power, Mod.ModAPIPlus.IUse2
    {
        public class LimbProps
        {
            public LimbBehaviour limb;
            public float baseStrength;
            public float Upright;
        }

        PersonBehaviour person;

        public static GameObject SoulRune;
        public GameObject soulOBJ;

        bool OneTimeOnly = false;
        bool Projecting = false;

        List<LimbProps> originals = new List<LimbProps>();

        public static AstralProjection SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, bool oneTimeOnly = false)
        {
            var power = Limb.gameObject.AddComponent<AstralProjection>();
            power.Name = "Astral Projection";
            power.Description = "Allows the user to separate their astral form (soul) from their own body.";
            power.icon = icon;
            power.targetLimb = TargettedLimb.Head;
            power.OneTimeOnly = oneTimeOnly;
            power.person = Person;

            return power;
        }

        public override void DisablePower()
        {
            base.DisablePower();
            Unproject();
        }

        public override void Start()
        {
            base.Start();

            if (OneTimeOnly)
                Project();
        }

        public void Use2()
        {
            if(!Enabled) return;

            if (Projecting || soulOBJ != null)
                Unproject();
            else if (!Projecting && soulOBJ == null)
                Project();
        }

        public void Project()
        {
            if (Projecting)
                return;
            Projecting = true;

            originals = new List<LimbProps>();

            foreach (var limb in person.Limbs)
            {
                originals.Add(new LimbProps{limb = limb, baseStrength = limb.BaseStrength, Upright = limb.FakeUprightForce});
            }

            //ModAPI.CreateParticleEffect(ParticleEffects.Disintegration, person.Limbs[1].transform.position);
            soulOBJ = Instantiate(ModAPI.FindSpawnable("Human").Prefab);
            soulOBJ.transform.localScale = transform.root.localScale;
            soulOBJ.transform.position = transform.root.position;

            soulOBJ.GetComponent<PersonBehaviour>().Limbs[0].gameObject.AddComponent<Projection>().projector = this;

            foreach (var renderer in soulOBJ.GetComponentsInChildren<SpriteRenderer>())
            {
                if (renderer.TryGetComponent<PhysicalBehaviour>(out var ph))
                {
                    ph.SpawnSpawnParticles = false;
                    ph.rigidbody.gravityScale = 0;
                    ph.rigidbody.drag = 5;
                    ph.rigidbody.angularDrag = 5;
                    ph.gameObject.layer = Layers.Debris;
                    ph.GetComponent<LimbBehaviour>().BaseStrength /= 2;
                }

                foreach (var renderer2 in transform.root.GetComponentsInChildren<SpriteRenderer>())
                    if (renderer2.gameObject.name == renderer.gameObject.name)
                    {
                        renderer.sprite = renderer2.sprite;
                        renderer.color = new Color(0.7f, 0.7f, 1f, 0.3f);

                        if (renderer2.TryGetComponent<PhysicalBehaviour>(out var ph2))
                        {
                            ph2.GetComponent<LimbBehaviour>().BaseStrength = 0;
                            ph2.GetComponent<LimbBehaviour>().FakeUprightForce = 0;
                            if(ph2.GetComponent<LimbBehaviour>().Joint)
                                ph2.GetComponent<LimbBehaviour>().Joint.autoConfigureConnectedAnchor = false;

                            if (renderer.TryGetComponent<PhysicalBehaviour>(out var phh))
                            {
                                phh.transform.position = ph2.transform.position;
                                phh.transform.rotation = ph2.transform.rotation;
                                phh.transform.localScale = ph2.transform.localScale;
                            }
                        }
                    }
            }
        }

        public void Unproject()
        {
            if (!Projecting || soulOBJ == null)
                return;

            Projecting = false;

            if (soulOBJ)
            {
                foreach (var limb in soulOBJ.GetComponentsInChildren<LimbBehaviour>())
                    ModAPI.CreateParticleEffect(ParticleEffects.Vapor, limb.transform.position);

                Destroy(soulOBJ);
            }

            ModAPI.CreateParticleEffect(ParticleEffects.Disintegration, person.Limbs[1].transform.position);

            foreach (var limb in person.Limbs)
            {
                limb.PhysicalBehaviour.rigidbody.gravityScale = 1;
                limb.PhysicalBehaviour.rigidbody.drag = 0;
                limb.PhysicalBehaviour.rigidbody.angularDrag = 0;
                limb.BaseStrength = originals.Find(x => x.limb == limb).baseStrength;
                limb.FakeUprightForce = originals.Find(x => x.limb == limb).Upright;
            }

            if (OneTimeOnly)
                DisablePower();
        }

        public void Update()
        {
            if (Projecting)
                person.Consciousness = 0;
        }

        public class Projection : MonoBehaviour, Mod.ModAPIPlus.IUse2
        {
            public AstralProjection projector;
            PersonBehaviour person;

            public void Start()
            {
                person = transform.root.GetComponent<PersonBehaviour>();
            }

            public void Use2()
            {
                projector.Unproject();
            }

            public void FixedUpdate()
            {
                if (person.Braindead == true || !person.IsAlive())
                {
                    projector.person.Braindead = true;
                    projector.person.Heartbeat = 0;
                    projector.person.Limbs[0].BreakBone();
                    projector.person.Limbs[0].Health = 0;
                    projector.Unproject();
                }
            }
        }
    }

    public class AstralFist : Power, Mod.ModAPIPlus.IUse2
    {
        public static GameObject SoulRune;

        GameObject PFX;

        bool Punching = false;

        public static AstralFist SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<AstralFist>();
            power.Name = "Astral Fist";
            power.Description = "Allows the user to separate a victim's astral form (soul) from their body.";
            power.icon = icon;
            power.targetLimb = power.name.Contains("Front") ? TargettedLimb.FrontArm : TargettedLimb.BackArm;

            power.PFX = Instantiate(SoulRune);
            power.PFX.GetComponent<ParticleSystem>().Stop();
            power.PFX.transform.SetParent(Limb.transform, false);
            foreach (var ps in power.PFX.GetComponentsInChildren<ParticleSystem>())
            {
                ps.transform.localScale = Vector3.one * 0.25f;
            }
            power.PFX.transform.localPosition = new Vector3(0, -0.2f, 0);
            return power;
        }

        public override void DisablePower()
        {
            base.DisablePower();
            Punching = false;
            PFX.GetComponent<ParticleSystem>().Stop();
        }

        public void Use2()
        {
            if (!Enabled) return;
            Punching = !Punching;
            if (!Punching)
            {
                PFX.GetComponent<ParticleSystem>().Stop();
            }
            else
            {
                PFX.GetComponent<ParticleSystem>().Play();
            }
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            if (!Enabled || !Punching)
                return;

            Vector2 relativeVelocity = col.relativeVelocity;

            float impactStrength = relativeVelocity.magnitude * 2;

            if (col.gameObject.TryGetComponent<LimbBehaviour>(out var limb) && col.relativeVelocity.magnitude > 3)
            {
                Punching = false;
                PFX.GetComponent<ParticleSystem>().Stop();

                CameraShakeBehaviour.main.Shake(7, base.transform.position);
                if (!limb.Person.GetComponentInChildren<AstralProjection>())
                    AstralProjection.SetPower(limb.Person, limb.Person.Limbs[0], null, true).EnablePower();
                else
                    limb.Person.GetComponentInChildren<AstralProjection>().Project();
            }
        }
    }

    public class StretchyBody : MonoBehaviour, Messages.IUse
    {
        public float SizeAdded = 0;
        public bool CanStretch = false; // Assuming it's true so it can be tested
        public bool Stretched = false;
        float stretchDuration = 0.5f; // Time it takes to stretch/unstretch
        public bool stretching;

        public void Start()
        {
            gameObject.GetComponent<PhysicalBehaviour>().ContextMenuOptions.Buttons.Add(new ContextMenuButton(() => !ColorpickerDialogBehaviour.IsOpen, "setAddSizeThing", "Add Stretch Size", "Add Stretch Size", delegate
            {
                Utils.OpenFloatInputDialog(0, this, delegate (StretchyBody obj, float c)
                {
                    if (c >= 10)
                    {
                        DialogBox dialog = (DialogBox)null;
                        dialog = DialogBoxManager.Notification($"<color=\"red\">This size is too big, please choose a size <10");
                    }
                    else
                    {
                        SizeAdded = c;
                    }

                }, "Add More Size", "Size to add");
            }));
        }

        public void Use(ActivationPropagation activation)
        {
            if (!CanStretch || stretching)
                return;

            if (Stretched)
            {
                stretching = true;
                foreach (var limb in GetComponent<LimbBehaviour>().Person.Limbs)
                {
                    if (limb.GetComponent<StretchyArms>())
                    {
                        limb.GetComponent<StretchyArms>().Stretched = false;
                        limb.GetComponent<StretchyArms>().CanStretch = true;
                    }
                    StartCoroutine(SmoothScale(limb.transform, new Vector2(1, 1)));
                }
                Stretched = false;
            }
            else
            {
                stretching = true;
                foreach (var limb in GetComponent<LimbBehaviour>().Person.Limbs)
                {

                    if (limb.GetComponent<StretchyArms>())
                    {
                        limb.GetComponent<StretchyArms>().CanStretch = false;
                    }
                    if (limb.name.Contains("Head"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(1.8f + SizeAdded, 1.8f + SizeAdded)));
                    }
                    if (limb.name.Contains("Body"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(1.9f + SizeAdded, 1.9f + SizeAdded)));
                    }
                    if (limb.name.Contains("UpperArm"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(2f + SizeAdded, 2f + SizeAdded)));
                    }
                    if (limb.name.Contains("LowerArm"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(1.8f + SizeAdded, 1.8f + SizeAdded)));
                    }
                    if (limb.name.Contains("Leg"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(1.8f + SizeAdded, 1.8f + SizeAdded)));
                    }
                    if (limb.name.Contains("Foot"))
                    {
                        StartCoroutine(SmoothScale(limb.transform, new Vector2(1.5f + SizeAdded, 1.5f + SizeAdded)));
                    }
                }
                Stretched = true;
            }
        }

        public IEnumerator SmoothScale(Transform Target, Vector2 targetScale)
        {
            Vector2 initialScale = Target.localScale;
            float elapsed = 0f;

            while (elapsed < stretchDuration)
            {
                Target.localScale = Vector2.Lerp(initialScale, targetScale, elapsed / stretchDuration);
                Target.GetComponent<PhysicalBehaviour>().RecalculateMassBasedOnSize();
                elapsed += Time.deltaTime;
                yield return null;
            }

            Target.localScale = targetScale; // Ensure it reaches the exact target scale
            stretching = false;
        }
    }

    public class StretchyArms : MonoBehaviour, Messages.IUse
    {
        public float StretchLength = 0.5f;
        public bool CanStretch = false; // Assuming it's true so it can be tested
        public bool Stretched = false;
        float stretchDuration = 0.5f; // Time it takes to stretch/unstretch
        public bool stretching;

        public void Start()
        {
            gameObject.GetComponent<PhysicalBehaviour>().ContextMenuOptions.Buttons.Add(new ContextMenuButton(() => !ColorpickerDialogBehaviour.IsOpen, "changeStretchLength", "Change Stretch Length", "Change Stretch Length", delegate
            {
                Utils.OpenFloatInputDialog(1, this, delegate (StretchyArms obj, float c)
                {
                    if (c >= 10)
                    {
                        DialogBox dialog = (DialogBox)null;
                        dialog = DialogBoxManager.Notification($"<color=\"red\">This size is too big, please choose a size <10");
                    }
                    else
                    {
                        StretchLength = c;
                    }
                }, "Add More Size", "Size to add");
            }));
        }

        public void Use(ActivationPropagation activation)
        {
            if (!CanStretch || stretching)
                return;

            if (Stretched)
            {
                stretching = true;
                foreach (var limb in transform.parent.GetComponentsInChildren<LimbBehaviour>())
                {
                    StartCoroutine(SmoothScale(limb.transform, new Vector2(1, 1)));
                }
                Stretched = false;
            }
            else
            {
                stretching = true;
                foreach (var limb in transform.parent.GetComponentsInChildren<LimbBehaviour>())
                {
                    StartCoroutine(SmoothScale(limb.transform, new Vector2(limb.transform.localScale.x + StretchLength, limb.transform.localScale.y + StretchLength)));
                }
                Stretched = true;
            }
        }

        public IEnumerator SmoothScale(Transform Target, Vector2 targetScale)
        {
            Vector2 initialScale = Target.localScale;
            float elapsed = 0f;

            while (elapsed < stretchDuration)
            {
                Target.localScale = Vector2.Lerp(initialScale, targetScale, elapsed / stretchDuration);
                Target.GetComponent<PhysicalBehaviour>().RecalculateMassBasedOnSize();
                elapsed += Time.deltaTime;
                yield return null;
            }

            Target.localScale = targetScale; // Ensure it reaches the exact target scale
            stretching = false;
        }
    }

    public class StretchyManager : Power
    {
        public static Power SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<StretchyManager>();
            power.Name = "Strechy";
            power.icon = icon;

            power.targetLimb = TargettedLimb.Head;


            foreach (var limb in Person.Limbs)
            {
                if (limb.Joint != null)
                {
                    limb.Joint.autoConfigureConnectedAnchor = false;
                }

                if (limb.name.Contains("UpperBody"))
                {
                    limb.gameObject.AddComponent<StretchyBody>();
                }

                if (limb.name.Contains("UpperArm"))
                {
                    limb.gameObject.AddComponent<StretchyArms>();
                }

                if (limb.name.Contains("UpperLeg"))
                {
                    limb.gameObject.AddComponent<StretchyArms>();
                }
            }

            return power;
        }

        public override void EnablePower()
        {
            base.EnablePower();

            foreach (var limb in GetComponent<LimbBehaviour>().Person.Limbs)
            {
                if (limb.TryGetComponent<StretchyArms>(out var arm))
                {
                    arm.CanStretch = true;
                }

                if (limb.TryGetComponent<StretchyBody>(out var bod))
                {
                    bod.CanStretch = true;
                }
            }
        }

        public override void DisablePower()
        {
            base.DisablePower();

            foreach (var limb in GetComponent<LimbBehaviour>().Person.Limbs)
            {
                if (limb.TryGetComponent<StretchyArms>(out var arm))
                {
                    arm.CanStretch = false;
                    arm.stretching = true;
                    foreach (var limbb in transform.parent.GetComponentsInChildren<LimbBehaviour>())
                    {
                        StartCoroutine(arm.SmoothScale(limbb.transform, new Vector2(1, 1)));
                    }
                    arm.Stretched = false;
                }

                if (limb.TryGetComponent<StretchyBody>(out var bod))
                {
                    bod.CanStretch = false;
                    bod.stretching = true;
                    foreach (var limbb in transform.parent.GetComponentsInChildren<LimbBehaviour>())
                    {
                        StartCoroutine(bod.SmoothScale(limbb.transform, new Vector2(1, 1)));
                    }
                    bod.Stretched = false;
                }
            }
        }
    }

    public class MysticFist : Power, Mod.ModAPIPlus.IUse2
    {
        GameObject PFX;

        bool Punching = false;

        public static MysticFist SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, GameObject overridePFX = null)
        {
            var power = Limb.gameObject.AddComponent<MysticFist>();
            power.Name = "Mystic Fist";
            power.Description = "Blocks most projectile attacks, and stuns enemies on impact.";
            power.icon = icon;
            power.targetLimb = power.name.Contains("Front") ? TargettedLimb.FrontArm : TargettedLimb.BackArm;

            power.PFX = Instantiate(overridePFX??Telekinesis.RunePrefab);
            power.PFX.GetComponent<ParticleSystem>().Stop();
            power.PFX.transform.SetParent(Limb.transform, false);
            foreach (var ps in power.PFX.GetComponentsInChildren<ParticleSystem>())
            {
                ps.transform.localScale = Vector3.one * 0.25f;
            }
            power.PFX.transform.localPosition = new Vector3(0, -0.2f, 0);
            return power;
        }

        public override void DisablePower()
        {
            base.DisablePower();
            Punching = false;
            PFX.GetComponent<ParticleSystem>().Stop();
        }

        public void Use2()
        {
            if(!Enabled) return;
            Punching = !Punching;
            if(!Punching)
            {
                PFX.GetComponent<ParticleSystem>().Stop();
            }else
            {
                PFX.GetComponent<ParticleSystem>().Play();
            }
        }

        private static readonly Collider2D[] _overlapBuf = new Collider2D[64];
        private static readonly List<LineRenderer> _tracerCache = new List<LineRenderer>(64);
        private static readonly HashSet<int> _processedIds = new HashSet<int>();
        private float _nextScanTime;
        private float _nextTracerRefreshTime;
        private const float ScanInterval = 0.05f;
        private const float TracerRefreshInterval = 0.25f;

        public void Update()
        {
            if (!Enabled || !Punching) return;

            CheckBulletTracersFast();
        }

        private void CheckBulletTracersFast()
        {
            const float radius = 7f;
            float radiusSqr = radius * radius;
            Vector3 center3 = transform.position;
            Vector2 center = center3;

            int count = Physics2D.OverlapCircleNonAlloc(center, radius, _overlapBuf);
            if (count > 0)
            {
                _processedIds.Clear();

                for (int i = 0; i < count; i++)
                {
                    var c = _overlapBuf[i];
                    if (!c) continue;

                    if (c.TryGetComponent<BlasterboltBehaviour>(out var bb) || c.GetComponentInParent<BlasterboltBehaviour>())
                    {
                        if (bb && _processedIds.Add(bb.gameObject.GetInstanceID()))
                        {
                            Vector3 p = bb.transform.position;
                            if ((p - center3).sqrMagnitude <= radiusSqr)
                            {
                                ModAPI.CreateParticleEffect("Flash", p);
                                Destroy(bb.gameObject);
                            }
                        }
                    }

                    if (c.TryGetComponent<ProjectileBehaviour>(out var pj) || c.GetComponentInParent<ProjectileBehaviour>())
                    {
                        if (pj && _processedIds.Add(pj.gameObject.GetInstanceID()))
                        {
                            Vector3 p = pj.transform.position;
                            if ((p - center3).sqrMagnitude <= radiusSqr)
                            {
                                ModAPI.CreateParticleEffect("Flash", p);
                                Destroy(pj.gameObject);
                            }
                        }
                    }

                    if (c.TryGetComponent<MagicProjectile.MagicProj>(out var mp) || c.GetComponentInParent<MagicProjectile.MagicProj>())
                    {
                        if (mp && _processedIds.Add(mp.gameObject.GetInstanceID()))
                        {
                            Vector3 p = mp.transform.position;
                            if ((p - center3).sqrMagnitude <= radiusSqr)
                            {
                                ModAPI.CreateParticleEffect("Flash", p);
                                Destroy(mp.gameObject);
                            }
                        }
                    }
                }
            }

            if (Time.time >= _nextTracerRefreshTime)
            {
                _nextTracerRefreshTime = Time.time + TracerRefreshInterval;
                RebuildTracerCache();
            }

            if (_tracerCache.Count == 0)
                return;

            for (int i = _tracerCache.Count - 1; i >= 0; i--)
            {
                var lr = _tracerCache[i];
                if (!lr)
                {
                    _tracerCache.RemoveAt(i);
                    continue;
                }

                int pc = lr.positionCount;
                if (pc < 2) continue;

                bool world = lr.useWorldSpace;
                int startIdx = Mathf.Max(0, pc - 1 - 6);
                Vector3 prev = GetWorldPos(lr, startIdx, world);

                for (int p = startIdx + 1; p < pc; p++)
                {
                    Vector3 cur = GetWorldPos(lr, p, world);
                    Vector3 seg = cur - prev;
                    float segLenSqr = seg.sqrMagnitude;
                    if (segLenSqr > 0.0001f)
                    {
                        float t = Vector3.Dot(center3 - prev, seg) / segLenSqr;
                        t = Mathf.Clamp01(t);
                        Vector3 closest = prev + seg * t;

                        if ((closest - center3).sqrMagnitude <= radiusSqr)
                        {
                            ModAPI.CreateParticleEffect("Flash", closest);
                            Destroy(lr.gameObject);
                            _tracerCache.RemoveAt(i);
                            break;
                        }
                    }

                    prev = cur;
                }
            }
        }

        private static void RebuildTracerCache()
        {
            var helpers = UnityEngine.Object.FindObjectsOfType<PoolableSizeHelper>(false);
            _tracerCache.Clear();
            for (int i = 0; i < helpers.Length; i++)
            {
                var h = helpers[i];
                if (!h) continue;
                if (h.name != "Tracer poolable(Clone)") continue;
                if (h.TryGetComponent<LineRenderer>(out var lr) && lr)
                {
                    _tracerCache.Add(lr);
                }
            }
        }

        private static Vector3 GetWorldPos(LineRenderer lr, int index, bool world)
        {
            var raw = lr.GetPosition(index);
            return world ? raw : lr.transform.TransformPoint(raw);
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            if (!Enabled || !Punching)
                return;

            Vector2 relativeVelocity = col.relativeVelocity;

            float impactStrength = relativeVelocity.magnitude * 3;

            if (col.gameObject.GetComponent<Rigidbody2D>() && col.relativeVelocity.magnitude > 3)
            {
                Vector2 directionToThisObject = (GetComponent<Rigidbody2D>().position - col.rigidbody.position).normalized;

                float dotProduct = Vector2.Dot(relativeVelocity, directionToThisObject);

                if (dotProduct > 0)
                {
                    col.gameObject.GetComponent<Rigidbody2D>().velocity += -relativeVelocity.normalized * impactStrength;
                    CameraShakeBehaviour.main.Shake(7, base.transform.position);
                    if (col.gameObject.GetComponent<PhysicalBehaviour>())
                        col.gameObject.GetComponent<PhysicalBehaviour>().charge += impactStrength / 10;
                    ModAPI.CreateParticleEffect("Flash", base.transform.position);
                }

            }
        }
    }

    public class TimeFreeze : Power, Messages.IUse
    {
        public static GameObject RunePrefab;

        public Transform Stopped;
        public GameObject PFX;

        public static TimeFreeze SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<TimeFreeze>();
            power.Name = "Time Freeze";
            power.Description = "Freezes any object the user aims at, velocity builds on the victim";
            power.icon = icon;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            power.PFX = Instantiate(RunePrefab);
            power.PFX.GetComponent<ParticleSystem>().Stop();

            return power;
        }

        public void OnDestroy()
        {
            if (Stopped != null)
            {
                foreach (var physicalBehaviour in Stopped.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    var freeze = physicalBehaviour.GetComponent<FreezeBehaviour2>();
                    if (freeze != null)
                    {
                        Destroy(freeze);
                    }
                }
            }

            Destroy(PFX);
        }

        public override void DisablePower()
        {
            base.DisablePower();

            if (Stopped != null)
            {
                foreach (var physicalBehaviour in Stopped.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    var freeze = physicalBehaviour.GetComponent<FreezeBehaviour2>();
                    if (freeze != null)
                    {
                        Destroy(freeze);
                    }
                }
                PFX.GetComponent<ParticleSystem>().Stop();
                Stopped = null;
            }
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            if(Stopped != null)
            {
                foreach (var physicalBehaviour in Stopped.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    var freeze = physicalBehaviour.GetComponent<FreezeBehaviour2>();
                    if (freeze != null)
                    {
                        Destroy(freeze);
                    }
                }
                PFX.GetComponent<ParticleSystem>().Stop();
                Stopped = null;
                return;
            }

            var origin = (Vector2)transform.position;
            var dir = -(Vector2)transform.up;

            RaycastHit2D[] hits = Physics2D.RaycastAll(origin, dir, 10);
            RaycastHit2D chosen = new RaycastHit2D();
            foreach (var hit in hits)
            {
                if (hit.collider == null) continue;
                if (hit.transform == null) continue;
                if (hit.transform.root == transform.root) continue;
                if (hit.rigidbody && hit.rigidbody.bodyType != RigidbodyType2D.Dynamic) continue;

                if (hit.collider.GetComponent<PhysicalBehaviour>())
                {
                    chosen = hit;
                    break;
                }
            }

            if (chosen.collider == null)
            {
                return;
            }

            StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Clock));

            Stopped = chosen.transform.root;

            Vector2 pfxPos = Vector2.zero;

            List<PhysicalBehaviour> colliders = Stopped.GetComponentsInChildren<PhysicalBehaviour>().ToList();

            foreach (var physicalBehaviour in colliders)
            {
                pfxPos += (Vector2)physicalBehaviour.transform.position;

                if (physicalBehaviour.GetComponent<FreezeBehaviour2>() == null)
                {
                    physicalBehaviour.gameObject.AddComponent<FreezeBehaviour2>();
                }
            }

            pfxPos /= colliders.Count;

            PFX.transform.position = pfxPos;

            PFX.GetComponent<ParticleSystem>().Play();
        }

    }

    public class FreezeBehaviour2 : MonoBehaviour
    {
        private Rigidbody2D rb;
        public Vector2 velocity;
        public float angularVelocity;
        private LineRenderer lineRenderer;
        Transform[] arrows;
        Transform LastArrow;

        public void Start()
        {
            rb = GetComponent<Rigidbody2D>();

            if (rb.bodyType == RigidbodyType2D.Static)
                return;

            velocity = rb.velocity;
            angularVelocity = rb.angularVelocity;
            FreezeStackController.RequestFreeze(rb);

            var line = new GameObject("RenderThing");
            line.AddComponent<ExistInDetailView>();
            line.transform.parent = transform;
            line.transform.localPosition = Vector2.zero;
            line.transform.localScale = Vector2.one;
            lineRenderer = line.gameObject.AddComponent<LineRenderer>();
            lineRenderer.positionCount = 2;
            lineRenderer.material = new Material(Shader.Find("Sprites/Default"));
            lineRenderer.widthMultiplier = 0.05f;
            lineRenderer.startColor = new Color(1f, 1f, 1f, 0.05f);
            lineRenderer.endColor = new Color(1f, 1f, 1f, 0.05f);
            lineRenderer.useWorldSpace = true;
            lineRenderer.sortingLayerName = "Top";

            var lastArrow = new GameObject("aa");
            lastArrow.name = "LastArrow";
            lastArrow.transform.SetParent(line.transform);
            lastArrow.transform.localScale = new Vector3(0.35f, 0.35f, 0.35f);
            lastArrow.AddComponent<SpriteRenderer>().sprite = Mod.Arrow;
            lastArrow.GetComponent<SpriteRenderer>().sortingLayerName = "Top";
            lastArrow.GetComponent<SpriteRenderer>().material = new Material(Shader.Find("Sprites/Default")) { color = Color.gray };
            lastArrow.GetComponent<SpriteRenderer>().sortingOrder = 5;
            Destroy(lastArrow.GetComponent<Collider>());
            LastArrow = lastArrow.transform;

            for (int i = 0; i < 1; i++)
            {
                var arrow = new GameObject("a");
                arrow.name = "ArrowHead";
                arrow.transform.SetParent(line.transform);
                arrow.transform.localScale = new Vector3(0.22f, 0.22f, 0.22f);
                arrow.AddComponent<SpriteRenderer>().sprite = Mod.Arrow;
                arrow.GetComponent<SpriteRenderer>().sortingLayerName = "Top";
                arrow.GetComponent<SpriteRenderer>().material = new Material(Shader.Find("Sprites/Default")) { color = Color.gray };
                arrow.GetComponent<SpriteRenderer>().sortingOrder = 5;
                arrow.GetComponent<SpriteRenderer>().color = new Color(1f, 1f, 1f, 0.6f);
                Destroy(arrow.GetComponent<Collider>());
            }

            Vector3 start = transform.position;
            Vector3 dir = velocity.normalized;
            float lineLength = velocity.magnitude * 0.05f + 0.2f;
            Vector3 end = start + dir * lineLength;
            lineRenderer.SetPosition(0, start);
            lineRenderer.SetPosition(1, end);
        }

        private void Update()
        {
            if (lineRenderer != null)
            {
                Vector3 start = transform.position;
                Vector3 dir = velocity.normalized;
                float lineLength = velocity.magnitude * 0.05f + 0.2f;
                Vector3 end = start + dir * lineLength;
                lineRenderer.SetPosition(0, start);
                lineRenderer.SetPosition(1, Vector3.Lerp(lineRenderer.GetPosition(1), end, Time.time * 0.0001f));

                if (LastArrow != null && lineRenderer != null)
                {
                    end = lineRenderer.GetPosition(1);
                    LastArrow.position = end;
                    if (velocity.sqrMagnitude > 0.0001f)
                    {
                        float angle = Mathf.Atan2(velocity.y, velocity.x) * Mathf.Rad2Deg - 90f;
                        LastArrow.rotation = Quaternion.Euler(0, 0, angle);
                    }
                }

                if (arrows == null)
                {
                    arrows = lineRenderer.transform.GetComponentsInChildren<SpriteRenderer>().Select(mr => mr.transform).ToArray();
                }

                float arrowSpeed = Mathf.Max(velocity.magnitude * 0.1f, 0.2f);
                float t = Time.time * arrowSpeed;
                for (int i = 0; i < arrows.Length; i++)
                {
                    if (arrows[i] != LastArrow)
                    {
                        float offset = ((float)i / arrows.Length + t) % 1f;
                        Vector3 arrowPos = Vector3.Lerp(start, end, offset);
                        arrows[i].position = arrowPos;
                        arrows[i].rotation = Quaternion.LookRotation(Vector3.forward, dir);
                    }
                }
            }
        }

        private void OnDestroy()
        {
            if (rb)
            {
                FreezeStackController.RequestUnfreeze(rb);
                rb.velocity = velocity;
                rb.angularVelocity = angularVelocity;
            }
            if (lineRenderer != null && lineRenderer.transform)
            {
                Destroy(lineRenderer.transform.gameObject);
            }
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            velocity += col.relativeVelocity;
        }
    }

    public class Telekinesis : Power
    {
        public static GameObject RunePrefab;
        public GameObject overrideRunePrefab;

        public float rayDistance = 10f;
        public float forceMagnitude = 10f;
        public LayerMask layerMask;
        public float holdDistance = 4f;
        public float closeDistanceThreshold = 0.1f;
        bool doing;
        private LimbBehaviour limb;
        GameObject target;

        PhysicalBehaviour physicalBehaviour;

        GameObject PFX;

        public static Telekinesis SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, GameObject overrideRune = null)
        {
            var power = Limb.gameObject.AddComponent<Telekinesis>();
            power.Name = "Magic Telekinesis";
            power.Description = "Hold the activation key to make any object in from of the user's arm float\n<color =\"yellow\">This power also suffocates any object held with telekinesis";
            power.icon = icon;
            power.targetLimb = power.name.Contains("Front") ? TargettedLimb.FrontArm : TargettedLimb.BackArm;
            power.physicalBehaviour = Limb.GetComponent<PhysicalBehaviour>();
            power.limb = Limb;
            
            power.PFX = Instantiate(overrideRune??RunePrefab);
            power.PFX.GetComponent<ParticleSystem>().Stop();

            return power;
        }

        public void Use2ContinuousStart()
        {
            if (!Enabled)
                return;
            doing = true;
            layerMask = LayerMask.GetMask("Objects");
            RaycastHit2D hit = Physics2D.Raycast(transform.position, -transform.up, rayDistance, layerMask);
            
            if (hit.collider != null)
            {
                if (target != hit.collider.gameObject && hit.collider.gameObject.GetComponent<Rigidbody2D>().bodyType != RigidbodyType2D.Static)
                {
                    target = hit.collider.gameObject;
                    PFX.GetComponent<ParticleSystem>().Play();
                }
            }
            else
            {
                target = null;
            }
        }

        public void Use2Continuous()
        {
            if (!Enabled)
                return;

            if (target != null)
            {
                Rigidbody2D rb = target.GetComponent<Rigidbody2D>();
                PFX.transform.position = target.transform.position;
                if (rb != null && rb.bodyType != RigidbodyType2D.Static)
                {
                    Vector2 targetPosition = (Vector3)transform.position + (-transform.up * holdDistance);
                    Vector2 direction = targetPosition - rb.position;
                    float distance = direction.magnitude;

                    float adjustedForceMagnitude = Mathf.Lerp(0, (target.GetComponent<Rigidbody2D>().mass) + forceMagnitude, distance / closeDistanceThreshold);
                    adjustedForceMagnitude = Mathf.Clamp(adjustedForceMagnitude, 0, (target.GetComponent<Rigidbody2D>().mass) + forceMagnitude);

                    if (target.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        rb.velocity = direction.normalized * adjustedForceMagnitude * 4;

                        limb.Person.OxygenLevel -= 0.1f;
                    }
                    else
                    {
                        rb.velocity = direction.normalized * adjustedForceMagnitude;
                    }
                }
            }
            else
            {
                layerMask = LayerMask.GetMask("Objects");
                RaycastHit2D[] hits = Physics2D.RaycastAll(transform.position, -transform.up, rayDistance, layerMask);
                foreach (var hit in hits)
                {
                    if (hit.collider.transform.root != transform.root && hit.collider.gameObject.GetComponent<Rigidbody2D>().bodyType != RigidbodyType2D.Static && !hit.collider.GetComponent<HatBehaviour>())
                    {
                        if (hit.collider.GetComponent<LimbBehaviour>())
                        {
                            if (hit.collider.name.Contains("Body"))
                                this.target = hit.collider.gameObject;
                        }
                        else
                        {
                            this.target = hit.collider.gameObject;
                        }
                        return;
                    }
                }
            }
        }

        public void Use2ContinuousEnd()
        {
            target = null;
            doing = false;
            PFX.GetComponent<ParticleSystem>().Stop();
        }

        public void Update()
        {
            if(physicalBehaviour.StartedBeingUsedContinuously())
                Use2ContinuousStart();
            if (physicalBehaviour.IsBeingUsedContinuously())
                Use2Continuous();
            if (physicalBehaviour.StoppedBeingUsedContinuously())
                Use2ContinuousEnd();
        }

        public void FixedUpdate()
        {
            if (doing)
            {
                if (!SelectionController.Main.SelectedObjects.Contains(physicalBehaviour))
                    Use2ContinuousEnd();
            }
        }

        public void OnDestroy()
        {
            Destroy(PFX);
        }
    }

    public class MagicProjectile : Power, Messages.IUse
    {
        public static GameObject ProjectilePrefab;

        public static MagicProjectile SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<MagicProjectile>();
            power.Name = "Magic Projectile";
            power.Description = "Create a projectile that can be launched at anything to damage it.";
