            bullet.transform.position = transform.position + -transform.up;
            bullet.transform.rotation = transform.rotation;
        }

        public class MagicProj : MonoBehaviour
        {
            public MagicProjectile projectile;
            public float speed = 35;

            private bool _shooting;
            private float _hoverOffset = 0.75f;
            private float _hoverLerpDuration = 2f;
            private float _hoverTime = 1.5f;

            private void Start()
            {
                StartCoroutine(PrepareAndShoot());
            }

            private IEnumerator PrepareAndShoot()
            {
                float t = 0f;
                while (t < _hoverLerpDuration)
                {
                    t += Time.deltaTime;

                    Transform projTr = projectile.transform;
                    Vector3 targetPos = projTr.position + (-projTr.up * _hoverOffset);
                    Quaternion targetRot = projTr.rotation;

                    transform.position = Vector3.Slerp(transform.position, targetPos, Time.deltaTime * 5);
                    transform.rotation = Quaternion.Slerp(transform.rotation, targetRot, Time.deltaTime * 5);

                    yield return null;
                }

                _shooting = true;
            }

            public void Update()
            {
                if (_shooting)
                {
                    Vector3 dir = -transform.up;
                    transform.position += dir * speed * Time.deltaTime;

                    RaycastHit2D hit = Physics2D.Raycast(transform.position, dir, 0.1f);
                    if (hit.collider != null && hit.transform.root != projectile.transform.root)
                    {
                        Hit();
                    }
                }
            }

            public void Hit()
            {
                ExplosionCreator.Explode(transform.position, 7);
                Destroy(gameObject);
            }
        }
    }

    public class Portaller : Power, Messages.IUse, Mod.ModAPIPlus.IUse2
    {
        public static GameObject PortalPrefab;

        public GameObject Portal1;
        public GameObject Portal2;

        bool OnFirstPortal = true;

        public List<Transform> cooldowned= new List<Transform>();

        public static Portaller SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, GameObject customPrefab = null)
        {
            var power = Limb.gameObject.AddComponent<Portaller>();
            power.Name = "Magic Portal";
            power.Description = "Create a portal that teleports objects to a designated location.";
            power.icon = icon;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            return power;
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            if (Portal1 == null)
            {
                Portal1 = Instantiate(PortalPrefab);
                Portal1.AddComponent<Portal>().parentPower = this;
                Portal1.transform.position = transform.position + -transform.up * 1.5f;
                Portal1.transform.localScale = Vector3.one * 0.75f;
                Portal1.transform.rotation = Quaternion.Euler(89, 0, 0);
                Portal1.transform.GetChild(0).transform.localScale = Vector3.one;
                Portal1.transform.GetChild(1).transform.localScale = Vector3.one;
            }
            else if (Portal2 == null)
            {
                Portal2 = Instantiate(PortalPrefab);
                Portal2.AddComponent<Portal>().parentPower = this;
                Portal2.transform.position = transform.position + -transform.up * 1.5f;
                Portal2.transform.localScale = Vector3.one * 0.75f;
                Portal2.transform.rotation = Quaternion.Euler(89, 0, 0);
                Portal2.transform.GetChild(0).transform.localScale = Vector3.one;
                Portal2.transform.GetChild(1).transform.localScale = Vector3.one;
            }
            else 
            { 
                if (OnFirstPortal)
                {
                    Portal1.SetActive(false);
                    Portal1.transform.position = transform.position + -transform.up * 1.5f;
                    Portal1.SetActive(true);
                    OnFirstPortal = false;
                }
                else
                {
                    Portal2.SetActive(false);
                    Portal2.transform.position = transform.position + -transform.up * 1.5f;
                    Portal2.SetActive(true);
                    OnFirstPortal = true;
                }
            }
        }

        public void Use2()
        {
            Destroy(Portal1);
            Destroy(Portal2);
        }

        public override void DisablePower()
        {
            base.DisablePower();

            Destroy(Portal1);
            Destroy(Portal2);
        }

        public class Portal : MonoBehaviour
        {
            public Portaller parentPower;

            public void Start()
            {
                gameObject.layer = Layers.Objects;
                gameObject.AddComponent<DebrisComponent>();
                var col = gameObject.AddComponent<BoxCollider2D>();
                col.size = new Vector2(2, 2);
                col.isTrigger = true;
            }

            public void OnTriggerEnter2D(Collider2D collision)
            {
                var otherPortal = parentPower.Portal1 == gameObject ? parentPower.Portal2 : parentPower.Portal1;
                if (otherPortal == null) return;

                var root = collision.transform.root;
                if (root == null) return;

                if (parentPower.cooldowned.Contains(root)) return;

                if (root == otherPortal.transform.root) return;

                StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Teleport));

                foreach (var ph in root.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    ModAPI.CreateParticleEffect("Flash", ph.transform.position);
                }

                Vector3 offsetFromPortal = root.position - transform.position;

                Quaternion originalRotation = root.rotation;

                CameraShakeBehaviour.main.Shake(1, transform.position, 0.5f);

                root.position = otherPortal.transform.position + offsetFromPortal;
                root.rotation = originalRotation;

                foreach (var ph in root.GetComponentsInChildren<PhysicalBehaviour>())
                {
                    ModAPI.CreateParticleEffect("Flash", ph.transform.position);
                }

                StartCoroutine(TempCooldown(root));
            }

            private IEnumerator TempCooldown(Transform target)
            {
                parentPower.cooldowned.Add(target);
                yield return new WaitForSeconds(0.5f);
                parentPower.cooldowned.Remove(target);
            }
        }
    }

    public class MagicWhip : Power, Messages.IUse
    {
        public DistanceJoint2D whipJoint;

        private LineRenderer _whipLine;
        private GameObject _whipGO;
        private Coroutine _whipRoutine;
        private Rigidbody2D _selfRb;

        private Rigidbody2D _targetRb;
        private Vector2 _targetLocalAnchor;
        private Vector2 _staticWorldAnchor;
        private bool _hasDynamicTarget;

        bool extending = false;

        private const float RayDistance = 14f;
        private const int LineSegments = 20;
        private const float ExtendDuration = 0.18f;
        private const float PullDuration = 1.25f;
        private const float InitialWobble = 0.25f;
        private const float SustainWobble = 0.05f;
        private const float MinDistance = 1f;
        private const float PullForce = 5f;

        public static MagicWhip SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<MagicWhip>();
            power.Name = "Magic Whip";
            power.Description = "Shoot a whip that latches to moving targets and pulls them toward you.";
            power.icon = icon;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            return power;
        }

        public override void Start()
        {
            base.Start();
            _selfRb = GetComponent<Rigidbody2D>();
            if (_selfRb == null)
            {
                _selfRb = gameObject.AddComponent<Rigidbody2D>();
            }
        }

        public void Use(ActivationPropagation activation)
        {
            if(extending || !Enabled) return;

            if (whipJoint != null)
            {
                DestroyWhip();
                return;
            }
            var origin = (Vector2)transform.position;
            var dir = -(Vector2)transform.up;

            RaycastHit2D[] hits = Physics2D.RaycastAll(origin, dir, RayDistance);
            RaycastHit2D chosen = new RaycastHit2D();
            foreach (var hit in hits)
            {
                if (hit.collider == null) continue;
                if (hit.transform == null) continue;
                if (hit.transform.root == transform.root) continue;
                if (hit.rigidbody && hit.rigidbody.bodyType != RigidbodyType2D.Dynamic) continue;

                if (hit.collider.GetComponent<PhysicalBehaviour>())
                {
                    chosen = hit;
                    break;
                }
            }

            if (chosen.collider == null)
            {
                return;
            }

            StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Whipy));

            extending = true;

            _whipLine = CreateLineRenderer(out _whipGO);
            if (_whipRoutine != null) StopCoroutine(_whipRoutine);
            _whipRoutine = StartCoroutine(ShootWhip(chosen));
        }

        private LineRenderer CreateLineRenderer(out GameObject holder)
        {
            ModAPI.CreateParticleEffect("Flash", transform.position);

            holder = new GameObject("MagicWhipLine");
            holder.transform.SetParent(null, false);
            var lr = holder.AddComponent<LineRenderer>();
            lr.useWorldSpace = true;

            lr.positionCount = LineSegments;
            lr.textureMode = LineTextureMode.Tile;
            lr.alignment = LineAlignment.TransformZ;
            lr.numCapVertices = 4;
            lr.numCornerVertices = 4;

            var curve = new AnimationCurve();
            curve.AddKey(0f, 0.08f);
            curve.AddKey(0.5f, 0.12f);
            curve.AddKey(1f, 0.08f);
            lr.widthCurve = curve;

            Material mat = UnityEngine.Object.Instantiate(ModAPI.FindMaterial("VeryBright"));

            lr.material = mat;

            Texture2D tex = Mod.Whip;
            if (tex != null)
            {
                tex.wrapMode = TextureWrapMode.Repeat;
                lr.material.mainTexture = tex;
            }

            lr.sortingLayerName = Layers.Sorting.Top;
            lr.sortingOrder = 10;
            lr.startColor = Color.white;
            lr.endColor = Color.white;

            Vector3 p = transform.position;
            for (int i = 0; i < LineSegments; i++) lr.SetPosition(i, p);
            return lr;
        }

        private IEnumerator ShootWhip(RaycastHit2D hit)
        {
            _targetRb = hit.rigidbody;
            _hasDynamicTarget = _targetRb != null && _targetRb.bodyType == RigidbodyType2D.Dynamic;
            if (_hasDynamicTarget)
            {
                _targetLocalAnchor = _targetRb.transform.InverseTransformPoint(hit.point);
            }
            else
            {
                _staticWorldAnchor = hit.point;
                _targetRb = null;
            }

            float elapsed = 0f;

            while (elapsed < ExtendDuration)
            {
                if (_hasDynamicTarget && (_targetRb == null || !_targetRb || !_targetRb.gameObject.activeInHierarchy))
                {
                    DestroyWhip();
                    yield break;
                }

                elapsed += Time.deltaTime;
                float p = Mathf.Clamp01(elapsed / Mathf.Max(0.01f, ExtendDuration));
                float eased = Mathf.SmoothStep(0f, 1f, p);

                Vector3 curStart = transform.position;
                Vector3 curEnd = _hasDynamicTarget
                    ? (Vector3)_targetRb.transform.TransformPoint(_targetLocalAnchor)
                    : (Vector3)_staticWorldAnchor;

                Vector3 tip = Vector3.Lerp(curStart, curEnd, eased);
                float amp = Mathf.Lerp(InitialWobble, SustainWobble, p);
                UpdateLine(curStart, tip, amp);
                yield return null;
            }

            if (_hasDynamicTarget && (_targetRb == null || !_targetRb || !_targetRb.gameObject.activeInHierarchy))
            {
                DestroyWhip();
                yield break;
            }

            whipJoint = gameObject.AddComponent<DistanceJoint2D>();
            whipJoint.enableCollision = false;
            whipJoint.autoConfigureConnectedAnchor = false;
            whipJoint.autoConfigureDistance = false;
            whipJoint.maxDistanceOnly = true;
            ModAPI.CreateParticleEffect("Flash", _hasDynamicTarget ? _targetRb.transform.position : (Vector3)_staticWorldAnchor);

            if (_hasDynamicTarget)
            {
                whipJoint.connectedBody = _targetRb;
                whipJoint.connectedAnchor = _targetLocalAnchor;
            }
            else
            {
                whipJoint.connectedBody = null;
                whipJoint.connectedAnchor = _staticWorldAnchor;
            }

            extending = false;

            whipJoint.anchor = Vector2.zero;

            Vector2 curEnd2D = _hasDynamicTarget
                ? (Vector2)_targetRb.transform.TransformPoint(_targetLocalAnchor)
                : _staticWorldAnchor;
            float initialDist = Vector2.Distance((Vector2)transform.position, curEnd2D);
            whipJoint.distance = initialDist;
            
            yield return StartCoroutine(PullRoutine());

            while (whipJoint != null)
            {
                if (_hasDynamicTarget && (whipJoint.connectedBody == null || !whipJoint.connectedBody || !whipJoint.connectedBody.gameObject.activeInHierarchy))
                {
                    DestroyWhip();
                    yield break;
                }

                Vector3 end = GetJointWorldAnchor();
                UpdateLine(transform.position, end, SustainWobble * 0.45f);
                yield return null;
            }
        }

        private IEnumerator PullRoutine()
        {
            if (whipJoint == null) yield break;

            float elapsed = 0f;
            float startDist = whipJoint.distance;

            while (whipJoint != null && elapsed < PullDuration)
            {
                if (_hasDynamicTarget && (whipJoint.connectedBody == null || !whipJoint.connectedBody || !whipJoint.connectedBody.gameObject.activeInHierarchy))
                {
                    DestroyWhip();
                    yield break;
                }

                elapsed += Time.deltaTime;
                float k = Mathf.Clamp01(elapsed / PullDuration);

                whipJoint.distance = Mathf.Lerp(startDist, MinDistance, k);

                Vector2 endPos = (Vector2)GetJointWorldAnchor();
                Vector2 selfPos = (Vector2)transform.position;
                Vector2 dir = selfPos - endPos;

                if (whipJoint.connectedBody != null)
                {
                    whipJoint.connectedBody.AddForce(dir.normalized * PullForce, ForceMode2D.Force);
                }

                if (_selfRb != null)
                {
                    _selfRb.AddForce(-dir.normalized * (PullForce * 0.5f), ForceMode2D.Force);
                }

                UpdateLine(transform.position, endPos, Mathf.Lerp(SustainWobble, SustainWobble * 0.25f, k));
                yield return null;
            }
        }

        private Vector3 GetJointWorldAnchor()
        {
            if (whipJoint == null) return transform.position;
            if (whipJoint.connectedBody != null)
            {
                return whipJoint.connectedBody.transform.TransformPoint(whipJoint.connectedAnchor);
            }
            return whipJoint.connectedAnchor;
        }

        private void UpdateLine(Vector3 start, Vector3 end, float amplitude)
        {
            if (_whipLine == null) return;

            Vector3 delta = end - start;
            float len = delta.magnitude;
            Vector3 dir = len > 0.0001f ? delta / len : Vector3.up;
            Vector3 normal = new Vector3(-dir.y, dir.x, 0f);

            for (int i = 0; i < LineSegments; i++)
            {
                float t = (float)i / (LineSegments - 1);
                Vector3 pos = Vector3.Lerp(start, end, t);
                
                float wave = Mathf.Sin(t * Mathf.PI);
                float noise = Mathf.PerlinNoise(Time.time * 10f, t * 3.3f) - 0.5f;
                Vector3 offset = normal * (wave * amplitude + noise * amplitude * 0.5f);
                _whipLine.SetPosition(i, pos + offset);
            }

            if (_whipLine.material != null && _whipLine.material.mainTexture != null)
            {
                float tiling = Mathf.Max(1f, len * 2f);
                _whipLine.material.mainTextureScale = new Vector2(tiling, 1f);
            }

            if (_whipGO != null)
            {
                _whipGO.transform.position = (start + end) * 0.5f;
            }
        }

        private void DestroyWhip()
        {
            if (_whipRoutine != null)
            {
                StopCoroutine(_whipRoutine);
                _whipRoutine = null;
            }

            if (whipJoint != null)
            {
                UnityEngine.Object.Destroy(whipJoint);
                whipJoint = null;
            }

            if (_whipGO != null)
            {
                UnityEngine.Object.Destroy(_whipGO);
                _whipGO = null;
                _whipLine = null;
            }

            _targetRb = null;
            _hasDynamicTarget = false;
        }

        private void OnDestroy()
        {
            DestroyWhip();
        }

        public void OnJointBreak()
        {
            DestroyWhip();
        }
    }

    public class BifrostTeleportation : Power, Mod.ModAPIPlus.IUse2
    {
        public static BifrostTeleportation SetPower(PersonBehaviour person, LimbBehaviour attachLimb, Sprite icon)
        {
            var power = attachLimb.gameObject.AddComponent<BifrostTeleportation>();
            power.Name = "Bifrost Teleportation";
            power.Description = "Grants teleportation abilities via the bifrost.";
            power.icon = icon;
            power.targetLimb = TargettedLimb.Head;

            return power;
        }

        public void Use2()
        {
            if (!Enabled)
                return;

            Vector2 center = (Vector2)transform.position;
            const float radius = 3f;

            Collider2D[] hits = Physics2D.OverlapCircleAll(center, radius);

            var toTeleport = new List<Transform>();

            for (int i = 0; i < hits.Length; i++)
            {
                var col = hits[i];
                if (col == null) continue;

                Rigidbody2D phys = col.GetComponent<Rigidbody2D>();

                if (phys == null || transform.root.name.Contains("WORLD") || phys.bodyType != RigidbodyType2D.Dynamic) continue;

                Transform t = phys.transform;
                if(!toTeleport.Contains(t))
                    toTeleport.Add(t);
                
            }

            FindObjectOfType<BifrostTeleportHandler>().Teleport(toTeleport);
        }

        public class BifrostTeleportHandler : MonoBehaviour
        {
            public BifrostTeleportation CurrentUser;
            public List<Transform> toTeleport;
            public bool Teleporting;

            private LineRenderer bifrostLine;
            private LineRenderer previewLine;

            private const float PreviewWidth = 0.1f;
            private const float BeamMaxWidth = 0.9f;
            private const float BeamInDuration = 0.5f;
            private const float BeamOutDuration = 0.5f;
            private const float BetweenBeamsPause = 0.5f;
            private const float RayDownDistance = 15f;

            public void Start()
            {
                bifrostLine = new GameObject("BifrostLine").AddComponent<LineRenderer>();
                previewLine = new GameObject("PreviewLine").AddComponent<LineRenderer>();

                bifrostLine.useWorldSpace = true;
                previewLine.useWorldSpace = true;

                bifrostLine.positionCount = 2;
                previewLine.positionCount = 2;

                var brightMat = Instantiate(ModAPI.FindMaterial("VeryBright"));
                if (brightMat != null)
                {
                    bifrostLine.material = brightMat;
                    bifrostLine.textureMode = LineTextureMode.Tile;
                    if (Mod.Bifrost != null)
                    {
                        bifrostLine.material.mainTexture = Mod.Bifrost;
                        bifrostLine.material.mainTexture.wrapMode = TextureWrapMode.Repeat;
                    }
                }

                var defaultMat = Instantiate(ModAPI.FindMaterial("Sprites-Default"));
                if (defaultMat != null)
                {
                    previewLine.material = defaultMat;
                }

                bifrostLine.sortingLayerName = Layers.Sorting.Top;
                previewLine.sortingLayerName = Layers.Sorting.Top;

                bifrostLine.numCornerVertices = 8;
                bifrostLine.numCapVertices = 8;
                bifrostLine.startColor = new Color(1f, 1f, 1f, 0f);
                bifrostLine.endColor = new Color(1f, 1f, 1f, 0f);
                bifrostLine.startWidth = 0f;
                bifrostLine.endWidth = 0f;

                previewLine.numCornerVertices = 4;
                previewLine.numCapVertices = 4;
                previewLine.startWidth = PreviewWidth;
                previewLine.endWidth = PreviewWidth;
                previewLine.startColor = new Color(0f, 1f, 0f, 1f);
                previewLine.endColor = new Color(0f, 1f, 0f, 1f);

                previewLine.enabled = false;
                bifrostLine.enabled = false;
            }

            public void Teleport(List<Transform> teleportin)
            {
                if (Teleporting || teleportin == null || teleportin.Count == 0)
                    return;

                toTeleport = teleportin.Where(t => t != null).ToList();
                if (toTeleport.Count == 0)
                    return;

                Teleporting = true;
                previewLine.enabled = true;
            }

            public void FixedUpdate()
            {
                if(bifrostLine.enabled)
                {
                    CameraShakeBehaviour.main.Shake(bifrostLine.startWidth / 3, transform.position, 0f);
                }
            }

            public void Update()
            {
                if (!Teleporting || toTeleport == null || toTeleport.Count == 0)
                    return;

                var cam = Camera.main;
                if (cam == null)
                    return;

                Vector3 mousePos = cam.ScreenToWorldPoint(Input.mousePosition);
                mousePos.z = 0f;

                SetPreviewAtX(mousePos.x);

                var overCol = Physics2D.OverlapPoint(mousePos);

                if (overCol != null)
                {
                    previewLine.startColor = Color.red;
                    previewLine.endColor = Color.red;
                }
                else
                {
                    previewLine.startColor = new Color(0f, 1f, 0f, 1f);
                    previewLine.endColor = new Color(0f, 1f, 0f, 1f);
                }

                if (Input.GetMouseButtonDown(0))
                {
                    if (overCol != null)
                    {
                        try { UISoundBehaviour.Main.Error(); } catch { }
                        ModAPI.Notify("Must not be inside of an object!");
                        return;
                    }

                    var hit = Physics2D.Raycast(mousePos, Vector2.down, RayDownDistance);
                    Vector2 targetPoint = hit.collider != null ? hit.point : (Vector2)mousePos;

                    previewLine.enabled = false;
                    StartCoroutine(StartTeleport(targetPoint));
                    return;
                }

                if (Input.GetMouseButtonDown(1) || Input.GetKeyDown(KeyCode.Escape))
                {
                    Teleporting = false;
                    previewLine.enabled = false;
                    toTeleport = null;
                }
            }

            public IEnumerator StartTeleport(Vector2 point)
            {
                Teleporting = false;
                previewLine.enabled = false;
                bifrostLine.enabled = true;

                var roots = GetUniqueRoots(toTeleport);
                if (roots.Count == 0)
                {
                    bifrostLine.enabled = false;
                    yield break;
                }

                Vector3 originCenter = ComputePhysicsCenter(roots);

                StartCoroutine(Mod.ModAPIPlus.PlaySound(originCenter, Mod.Bifrosty));

                SetupBeamAtX(originCenter.x);
                yield return AnimateBeam(0f, BeamMaxWidth, 0f, 1f, BeamInDuration);

                Transform originalParent = transform.parent;
                Transform selfRoot = transform.root;
                bool containsSelfRoot = roots.Contains(selfRoot);
                if (containsSelfRoot)
                {
                    transform.SetParent(null, true);
                }

                var rbCache = new Dictionary<Rigidbody2D, (Vector2 vel, float angVel)>();
                var allRBs = CollectRigidbodies(roots);
                foreach (var rb in allRBs)
                {
                    if (rb == null) continue;
                    rbCache[rb] = (rb.velocity, rb.angularVelocity);
                }

                var deactivated = new List<GameObject>();
                foreach (var r in roots)
                {
                    var go = r.gameObject;
                    if (go != null && go.activeSelf)
                    {
                        go.SetActive(false);
                        deactivated.Add(go);
                    }
                }

                yield return AnimateBeam(BeamMaxWidth, 0f, 0.5f, 0f, BeamOutDuration);
                yield return new WaitForSeconds(BetweenBeamsPause);

                SetupBeamAtX(point.x);
                yield return AnimateBeam(0f, BeamMaxWidth, 0f, 0.5f, BeamInDuration);

                StartCoroutine(Mod.ModAPIPlus.PlaySound(point, Mod.Bifrosty));

                Vector3 delta = (Vector3)point - originCenter;
                ApplyDeltaToRigidbodies(allRBs, delta);

                foreach (var go in deactivated)
                {
                    if (go != null) go.SetActive(true);
                }
                foreach (var kv in rbCache)
                {
                    var rb = kv.Key;
                    if (rb == null) continue;
                    rb.velocity = kv.Value.vel;
                    rb.angularVelocity = kv.Value.angVel;
                }

                if (containsSelfRoot)
                {
                    transform.SetParent(originalParent, true);
                }

                foreach (var r in roots)
                {
                    if (r.TryGetComponent<PersonBehaviour>(out var person))
                    {
                        foreach (var limb1 in person.Limbs)
                            foreach (var limb2 in person.Limbs)
                                Physics2D.IgnoreCollision(limb1.GetComponent<Collider2D>(), limb2.GetComponent<Collider2D>(), true);
                    }
                }

                yield return AnimateBeam(BeamMaxWidth, 0f, 0.5f, 0f, BeamOutDuration);
                bifrostLine.enabled = false;

                toTeleport = null;
            }

            private void SetPreviewAtX(float x)
            {
                const float YExtent = 10000f;
                previewLine.SetPosition(0, new Vector3(x, +YExtent, 0f));
                previewLine.SetPosition(1, new Vector3(x, -YExtent, 0f));
            }

            private void SetupBeamAtX(float x)
            {
                const float YExtent = 10000f;
                bifrostLine.SetPosition(0, new Vector3(x, +YExtent, 0f));
                bifrostLine.SetPosition(1, new Vector3(x, -YExtent, 0f));
                bifrostLine.startWidth = 0f;
                bifrostLine.endWidth = 0f;
                var c0 = bifrostLine.startColor; c0.a = 0f;
                var c1 = bifrostLine.endColor; c1.a = 0f;
                bifrostLine.startColor = c0;
                bifrostLine.endColor = c1;
            }

            private IEnumerator AnimateBeam(float fromWidth, float toWidth, float fromAlpha, float toAlpha, float duration)
            {
                float t = 0f;
                float texOffset = 0f;
                const float scrollSpeed = 3.5f;

                bifrostLine.startWidth = fromWidth;
                bifrostLine.endWidth = fromWidth;
                var sc = bifrostLine.startColor; sc.a = fromAlpha;
                var ec = bifrostLine.endColor; ec.a = fromAlpha;
                bifrostLine.startColor = sc;
                bifrostLine.endColor = ec;

                while (t < duration)
                {
                    t += Time.deltaTime;
                    float k = Mathf.Clamp01(t / duration);
                    float w = Mathf.Lerp(fromWidth, toWidth, k);
                    float a = Mathf.Lerp(fromAlpha, toAlpha, k);

                    bifrostLine.startWidth = w;
                    bifrostLine.endWidth = w;

                    sc.a = a; ec.a = a;
                    bifrostLine.startColor = sc;
                    bifrostLine.endColor = ec;

                    texOffset += Time.deltaTime * scrollSpeed;
                    try
                    {
                        if (bifrostLine.material != null && bifrostLine.material.mainTexture != null)
                        {
                            bifrostLine.material.mainTextureOffset = new Vector2(texOffset * 2, texOffset);
                        }
                    }
                    catch { }

                    yield return null;
                }
            }

            private static List<Transform> GetUniqueRoots(List<Transform> transforms)
            {
                var set = new HashSet<Transform>();
                var list = new List<Transform>();
                if (transforms == null) return list;

                for (int i = 0; i < transforms.Count; i++)
                {
                    var t = transforms[i];
                    if (t == null) continue;
                    var root = t.root;
                    if (root == null) continue;
                    if (set.Add(root))
                    {
                        list.Add(root);
                    }
                }
                return list;
            }

            private static List<Rigidbody2D> CollectRigidbodies(List<Transform> roots)
            {
                var rbs = new List<Rigidbody2D>();
                foreach (var r in roots)
                {
                    if (r == null) continue;
                    rbs.AddRange(r.GetComponentsInChildren<Rigidbody2D>(true));
                }
                return rbs;
            }

            private static Vector3 ComputePhysicsCenter(List<Transform> roots)
            {
                var rbs = CollectRigidbodies(roots);
                if (rbs.Count == 0)
                {
                    return ComputeCenter(roots);
                }

                Vector2 sum = Vector2.zero;
                int count = 0;

                for (int i = 0; i < rbs.Count; i++)
                {
                    var rb = rbs[i];
                    if (rb == null) continue;

                    var col = rb.GetComponent<Collider2D>();
                    if (col != null)
                    {
                        sum += (Vector2)col.bounds.center;
                    }
                    else
                    {
                        sum += rb.position;
                    }
                    count++;
                }

                return count > 0 ? sum / count : Vector2.zero;
            }

            private static void ApplyDeltaToRigidbodies(List<Rigidbody2D> rbs, Vector3 delta)
            {
                if (rbs == null || rbs.Count == 0) return;
                var d2 = (Vector2)delta;

                for (int i = 0; i < rbs.Count; i++)
                {
                    var rb = rbs[i];
                    if (rb == null) continue;

                    rb.position += d2;

                    var t = rb.transform;
                    if (t != null) t.position += delta;
                }
            }

            private static Vector3 ComputeCenter(IEnumerable<Transform> transforms)
            {
                Vector3 sum = Vector3.zero;
                int count = 0;
                foreach (var t in transforms)
                {
                    if (t == null) continue;
                    sum += t.position;
                    count++;
                }
                return count > 0 ? sum / count : Vector3.zero;
            }
        }
    }

    public class ElectricAuraFlight : Power, Messages.IUse
    {
        public bool AuraActive;
        public List<GameObject> GlowObjects = new List<GameObject>();
        public List<ParticleSystem> AuraBoltObjects = new List<ParticleSystem>();
        bool canSwitchAura = true;
        public Color auraColor = new Color(0.3f, 0.3f, 0.5f, 1);
        public float outlineOffset = 0.01f;
        Vector2[] outlineOffsets = new Vector2[]
        {
            new Vector2(-1, 0), new Vector2(1, 0), new Vector2(0, -1), new Vector2(0, 1),
            new Vector2(-1, -1), new Vector2(-1, 1), new Vector2(1, -1), new Vector2(1, 1)
        };

        public bool InFlight;
        public PersonBehaviour person;
        public ParticleSystem FlightParticleSystem;
        float storedGravity;
        float storedArmStrength = 8.5f;
        bool upright = true;

        public static Power SetPower(PersonBehaviour person, LimbBehaviour attachLimb, Sprite icon)
        {
            var power = attachLimb.gameObject.AddComponent<ElectricAuraFlight>();
            power.person = person;
            power.Name = "Electric Aura Flight";
            power.Description =
                "Envelops user in an electrical aura and grants flight.\nActivating toggles both effects.\nUser becomes impervious to electricity and charges objects on impact while active.";
            power.icon = icon;
            power.targetLimb = TargettedLimb.Body;

            foreach (var limb in person.Limbs)
            {
                var newProps = GameObject.Instantiate(limb.PhysicalBehaviour.Properties);
                newProps.Conducting = false;
                limb.PhysicalBehaviour.Properties = newProps;
                limb.PhysicalBehaviour.ForceNoCharge = true;

                if (limb.name == "Head")
                {
                    var glowEye = new GameObject("Eyes");
                    glowEye.transform.SetParent(limb.transform);
                    glowEye.transform.localPosition = Vector3.zero;
                    glowEye.transform.localRotation = Quaternion.identity;
                    glowEye.transform.localScale = Vector3.one;
                    var srEye = glowEye.AddComponent<SpriteRenderer>();
                    srEye.sprite = Mod.Eye;
                    srEye.sortingLayerName = limb.SkinMaterialHandler.renderer.sortingLayerName;
                    srEye.sortingOrder = limb.SkinMaterialHandler.renderer.sortingOrder + 1;
                    srEye.material = ModAPI.FindMaterial("VeryBright");
                    srEye.color = new Color(0, 0.5f, 1, 0f);
                    power.GlowObjects.Add(glowEye);
                }

                power.CreateOutlineGlow(limb.gameObject,
                    limb.GetComponent<SpriteRenderer>().sprite,
                    limb.GetComponent<SpriteRenderer>().sortingLayerName,
                    limb.GetComponent<SpriteRenderer>().sortingOrder - 2,
                    new Color(0, 0.5f, 1, 0f),
                    "AuraOutline");

                var boltPrefab = ModAPI.FindSpawnable("Particle Projector").Prefab.transform.FindChild("bolts").gameObject;
                var boltObj = Instantiate(boltPrefab, limb.transform);
                boltObj.transform.localPosition = Vector2.zero;
                boltObj.transform.localScale = new Vector3(0.3f, 0.3f, 0.3f);
                var main = boltObj.GetComponent<ParticleSystem>().main;
                main.startColor = power.auraColor;
                if (boltObj.transform.childCount > 0)
                {
                    for (int i = 0; i < boltObj.transform.childCount; i++)
                    {
                        var ps = boltObj.transform.GetChild(i).GetComponent<ParticleSystem>();
                        if (ps != null)
                        {
                            var m = ps.main;
                            m.startColor = power.auraColor;
                        }
                    }
                }
                power.AuraBoltObjects.Add(boltObj.GetComponent<ParticleSystem>());

                if (!limb.gameObject.GetComponent<AuraChargeLimb>())
                {
                    limb.gameObject.AddComponent<AuraChargeLimb>().parentPower = power;
                }

                if (!limb.gameObject.GetComponent<FlightImpactLimb>())
                {
                    limb.gameObject.AddComponent<FlightImpactLimb>().flightPower = power;
                }
            }

            return power;
        }

        void CreateOutlineGlow(GameObject limb, Sprite sprite, string sortingLayer, int sortingOrder, Color color, string name)
        {
            foreach (var off in outlineOffsets)
            {
                var glow = new GameObject(name);
                glow.transform.SetParent(limb.transform);
                glow.transform.localPosition = new Vector3(off.x * outlineOffset, off.y * outlineOffset, 0f);
                glow.transform.localRotation = Quaternion.identity;
                glow.transform.localScale = Vector3.one;

                var sr = glow.AddComponent<SpriteRenderer>();
                sr.sprite = sprite;
                sr.sortingLayerName = sortingLayer;
                sr.sortingOrder = sortingOrder;
                sr.material = ModAPI.FindMaterial("VeryBright");
                sr.color = color;

                GlowObjects.Add(glow);
            }
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled) return;

            if (!InFlight || !AuraActive)
            {
                StartFlight();
                EnableAura();
            }
            else
            {
                DisableAura();
                StopFlight();
            }
        }

        void EnableAura()
        {
            if (!canSwitchAura) return;

            RebuildGlowSprites();

            foreach (var ps in AuraBoltObjects)
                ps.Play();

            foreach (var glow in GlowObjects)
                StartCoroutine(ColorOverTime(glow,
                    new Color(auraColor.r, auraColor.g, auraColor.b, 15),
                    new Color(auraColor.r, auraColor.g, auraColor.b, 0)));

            AuraActive = true;
        }

        void DisableAura()
        {
            if (!AuraActive) return;

            foreach (var ps in AuraBoltObjects)
                ps.Stop();

            foreach (var glow in GlowObjects)
                StartCoroutine(ColorOverTime(glow,
                    new Color(auraColor.r, auraColor.g, auraColor.b, 0),
                    new Color(auraColor.r, auraColor.g, auraColor.b, 15)));

            AuraActive = false;
        }

        void RebuildGlowSprites()
        {
            foreach (var g in GlowObjects) Destroy(g);
            GlowObjects.Clear();

            foreach (var limb in person.Limbs)
            {
                CreateOutlineGlow(limb.gameObject,
                    limb.GetComponent<SpriteRenderer>().sprite,
                    limb.GetComponent<SpriteRenderer>().sortingLayerName,
                    limb.GetComponent<SpriteRenderer>().sortingOrder - 1,
                    new Color(auraColor.r, auraColor.g, auraColor.b, 0),
                    "AuraFlame");
            }
        }

        void StartFlight()
        {
            upright = false;
            if (InFlight) return;

            if (FlightParticleSystem) FlightParticleSystem.Play();
            person.OverridePoseIndex = 8;
            InFlight = true;

            foreach (var limb in person.Limbs)
            {
                if (!limb.gameObject.activeSelf) continue;

                if (limb.name.Contains("Arm"))
                {
                    storedArmStrength = limb.BaseStrength;
                    limb.BaseStrength = 0;
                }

                GripBehaviour grip;
                if (limb.TryGetComponent<GripBehaviour>(out grip))
                {
                    if (grip.CurrentlyHolding &&
                        !grip.CurrentlyHolding.gameObject.GetComponent<LFlightHeld>())
                    {
                        var held = grip.CurrentlyHolding.gameObject.AddComponent<LFlightHeld>();
                        held.initialGravity = grip.CurrentlyHolding.rigidbody.gravityScale;
                        grip.CurrentlyHolding.rigidbody.gravityScale = 0;
                    }
                }

                Cape cape;
                if (limb.TryGetComponent<Cape>(out cape))
                {
                    foreach (var part in cape.capePoints)
                    {
                        var rb = part.GetComponent<Rigidbody2D>();
                        rb.drag = 5;
                        rb.gravityScale = 0;
                    }
                }

                DynamicCloth cloth;
                if (limb.TryGetComponent<DynamicCloth>(out cloth))
                {
                    foreach (var part in cloth.capePoints)
                    {
                        var rb = part.GetComponent<Rigidbody2D>();
                        rb.drag = 5;
                        rb.gravityScale = 0;
                    }
                }

                storedGravity = limb.GetComponent<PhysicalBehaviour>().InitialGravityScale;
                limb.GetComponent<Rigidbody2D>().gravityScale = 0;
            }
        }

        void StopFlight()
        {
            InFlight = false;
            person.OverridePoseIndex = -1;
            if (FlightParticleSystem) FlightParticleSystem.Stop();

            foreach (var limb in person.Limbs)
            {
                if (!limb.gameObject.activeSelf) continue;

                if (limb.name.Contains("Arm"))
                    limb.BaseStrength = storedArmStrength;

                GripBehaviour grip;
                if (limb.TryGetComponent<GripBehaviour>(out grip))
                {
                    if (grip.CurrentlyHolding &&
                        grip.CurrentlyHolding.gameObject.TryGetComponent<LFlightHeld>(out var held))
                    {
                        held.OnDrop(grip);
                    }
                }

                Cape cape;
                if (limb.TryGetComponent<Cape>(out cape))
                {
                    foreach (var part in cape.capePoints)
                        part.GetComponent<Rigidbody2D>().gravityScale = 1;
                }

                DynamicCloth cloth;
                if (limb.TryGetComponent<DynamicCloth>(out cloth))
                {
                    foreach (var part in cloth.capePoints)
                    {
                        var rb = part.GetComponent<Rigidbody2D>();
                        rb.drag = 0.25f;
                        rb.gravityScale = 1;
                    }
                }

                limb.GetComponent<Rigidbody2D>().drag = 0;
                limb.GetComponent<Rigidbody2D>().gravityScale = storedGravity;
            }
        }

        void FixedUpdate()
        {
            foreach (var limb in person.Limbs)
            {
                var rb = limb.GetComponent<Rigidbody2D>();
                rb.drag = Mathf.Lerp(rb.drag, InFlight ? (upright ? 1f : 6.5f) : 0f, 0.1f);
            }

            if (InFlight)
            {
                if (person.Braindead)
                {
                    StopFlight();
                    return;
                }

                foreach (var limb in person.Limbs)
                {
                    if (!limb.gameObject.activeSelf) continue;
                    var rb = limb.GetComponent<Rigidbody2D>();
                    if (rb.bodyType == RigidbodyType2D.Static) continue;

                    rb.angularVelocity *= 0.98f;
                    rb.velocity *= 0.98f;

                    if (limb.name.Contains("Body") && upright)
                    {
                        float massFactor = limb.gameObject.GetComponent<PhysicalBehaviour>().rigidbody.mass / 1.5f;
                        float torqueFactor = 10 * Mathf.Clamp(limb.gameObject.GetComponent<PhysicalBehaviour>().Charge, 1f, 5f) * massFactor * massFactor;
                        limb.gameObject.GetComponent<PhysicalBehaviour>().rigidbody.angularVelocity *= 0.5f;
                        rb.AddTorque(Mathf.DeltaAngle(limb.transform.eulerAngles.z, 0f) * torqueFactor);
                    }
                }
            }
        }

        public override void DisablePower()
        {
            if (AuraActive) DisableAura();
            if (InFlight) StopFlight();
            base.DisablePower();
        }

        public void OnDestroy()
        {
            foreach (var ps in AuraBoltObjects)
            {
                if (ps) ps.Stop();
            }
            foreach (var g in GlowObjects)
            {
                if (g) Destroy(g);
            }
        }

        IEnumerator ColorOverTime(GameObject obj, Color target, Color origin)
        {
            canSwitchAura = false;
            float duration = 1f;
            float t = 0f;
            var sr = obj.GetComponent<SpriteRenderer>();
            while (t < duration)
            {
                sr.color = Color.Lerp(origin, target, t / duration);
                t += Time.deltaTime;
                yield return null;
            }
            sr.color = target;
            canSwitchAura = true;
        }

        public class AuraChargeLimb : MonoBehaviour
        {
            public ElectricAuraFlight parentPower;
            public void OnCollisionEnter2D(Collision2D col)
            {
                if (parentPower != null &&
                    parentPower.AuraActive &&
                    col.collider.TryGetComponent<PhysicalBehaviour>(out var phys) &&
                    col.relativeVelocity.magnitude > 3f)
                {
                    phys.charge += 10;
                }
            }
        }

        public class FlightImpactLimb : MonoBehaviour
        {
            public ElectricAuraFlight flightPower;
            bool cooldown;

            public void OnCollisionEnter2D(Collision2D collision)
            {
                if (flightPower == null) return;
                if (flightPower.InFlight &&
                    !cooldown &&
                    collision.rigidbody != null &&
                    collision.rigidbody.mass > 0.01f &&
                    collision.rigidbody.bodyType != RigidbodyType2D.Static &&
                    collision.rigidbody.velocity.magnitude > GetComponent<Rigidbody2D>().velocity.magnitude &&
                    collision.relativeVelocity.magnitude > 15f)
                {
                    flightPower.StopFlight();
                    StartCoroutine(Knockout(Mathf.Clamp(
                        collision.relativeVelocity.magnitude * collision.rigidbody.mass * 0.5f,
                        0.7f,
                        Settings.main.Get<float>("KnockoutTime"))));
                }
            }

            public void FixedUpdate()
            {
                if (cooldown)
                {
                    if (GetComponent<Rigidbody2D>().velocity.magnitude < 3f)
                    {
                        flightPower.StartFlight();
                    }
                }
            }

            IEnumerator Knockout(float time)
            {
                cooldown = true;
                yield return new WaitForSeconds(time * 0.7f);
                flightPower.StartFlight();
                yield return new WaitForSeconds(time * 0.3f);
                cooldown = false;
            }
        }

        [SkipSerialisation]
        public class LFlightHeld : MonoBehaviour, Messages.IOnDrop
        {
            public float initialGravity;
            public void OnDrop(GripBehaviour grip)
            {
                GetComponent<Rigidbody2D>().gravityScale = initialGravity;
                Destroy(this);
            }
        }
    }

    public class Hammer : Summonable, Messages.IOnGripped, Messages.IOnDrop, Mod.ModAPIPlus.IUse2
    {
        bool useable = false;
        bool isHeld = false;
        float OGMass = 0;

        private Vector3[] vertices;

        float dist;

        Vector3 oldPos;

        public LightningToolEntityBehaviour lightningToolEntityBehaviour;

        public PhysicalBehaviour physicalBehaviour;

        public float CooldownTime = 0.1f;

        private float cooldown;

        public List<PersonBehaviour> holders = new List<PersonBehaviour>();

        public Transform target;

        public bool GettingTarget;

        public float otherCooldown = 0f;

        public override void Start()
        {
            base.Start();

            oldPos = transform.position;

            physicalBehaviour = GetComponent<PhysicalBehaviour>();

            lightningToolEntityBehaviour = Instantiate(Resources.Load<GameObject>("Prefabs/LightningToolEntity")).GetComponent<LightningToolEntityBehaviour>();
            
            OGMass = GetComponent<Rigidbody2D>().mass;
            vertices = new Vector3[lightningToolEntityBehaviour.SingleBolt.positionCount];
        }

        public override void OnGripped(GripBehaviour gripper)
        {
            if (!gripper.transform.root.GetComponent<Worthy>())
            {
                useable = false;
                GetComponent<Rigidbody2D>().mass = gripper.GetComponent<Rigidbody2D>().mass * 100;
            }else
            {
                GetComponent<Rigidbody2D>().mass = gripper.GetComponent<Rigidbody2D>().mass * 2;
                useable = true;

                foreach (var limb in gripper.transform.root.GetComponent<PersonBehaviour>().Limbs)
                {
                    if (limb.name.Contains("LowerArm") && limb.GetComponent<HammerSummon>() == null)
                    {
                        HammerSummon.SetPower(transform.root.GetComponent<PersonBehaviour>(), limb, null).EnablePower();
                    }
                }
            }

            holders.Add(gripper.transform.root.GetComponent<PersonBehaviour>());

            base.OnGripped(gripper);
        }

        public void OnDrop(GripBehaviour gripper)
        {
            useable = true;

            holders.Remove(gripper.transform.root.GetComponent<PersonBehaviour>());
        }

        public IEnumerator lightning()
        {
            float coneAngle = 45f; 
            float coneRange = 50f;
            int rayCount = 9;

            PersonBehaviour targetPerson = null;
            Vector2 targetPoint = Vector2.zero;

            Vector2 baseDirection = (transform.position - oldPos).normalized;

            List<(PersonBehaviour person, Vector2 point, float distance)> potentialTargets = new List<(PersonBehaviour, Vector2, float)>();

            for (int r = 0; r < rayCount; r++)
            {
                float angleOffset = Mathf.Lerp(-coneAngle, coneAngle, (float)r / (rayCount - 1));
                float angleInRadians = angleOffset * Mathf.Deg2Rad;

                Vector2 rotatedDirection = new Vector2(
                    baseDirection.x * Mathf.Cos(angleInRadians) - baseDirection.y * Mathf.Sin(angleInRadians),
                    baseDirection.x * Mathf.Sin(angleInRadians) + baseDirection.y * Mathf.Cos(angleInRadians)
                );

                RaycastHit2D[] hits = Physics2D.RaycastAll(transform.position, rotatedDirection, coneRange);

                foreach (var hit in hits)
                {
                    if (hit.collider == null || hit.transform.root == transform.root)
                        continue;

                    bool isHolder = false;
                    if (holders.Count != 0)
                    {
                        foreach (var hold in holders)
                        {
                            if (hit.transform.root == hold.transform)
                            {
                                isHolder = true;
                                break;
                            }
                        }
                    }

                    if (isHolder)
                        continue;

                    PersonBehaviour person = hit.transform.root.GetComponent<PersonBehaviour>();
                    if (person != null && person.Limbs != null && person.Limbs.Length > 1)
                    {
                        Vector2 limbPoint = person.Limbs[1].transform.position;
                        float distannce = Vector2.Distance(transform.position, limbPoint);

                        bool alreadyAdded = false;
                        foreach (var target in potentialTargets)
                        {
                            if (target.person == person)
                            {
                                alreadyAdded = true;
                                break;
                            }
                        }

                        if (!alreadyAdded)
                        {
                            potentialTargets.Add((person, limbPoint, distannce));
                        }
                    }
                }
            }

            if (potentialTargets.Count > 0)
            {
                potentialTargets.Sort((a, b) => a.distance.CompareTo(b.distance));
                targetPerson = potentialTargets[0].person;
                targetPoint = potentialTargets[0].point;
            }

            if (targetPerson == null)
            {
                RaycastHit2D[] raycastHits2D = Physics2D.RaycastAll(transform.position, baseDirection, 5000f);
                RaycastHit2D raycastHit2D;

                if (holders.Count != 0)
                {
                    raycastHit2D = raycastHits2D.FirstOrDefault(a => a.transform.root != null && !holders.Any(h => a.transform.root == h.transform) && a.transform.root != transform.root);
                }
                else
                {
                    raycastHit2D = raycastHits2D.FirstOrDefault(a => a.transform.root != transform.root);
                }

                if (raycastHit2D)
                {
                    targetPoint = raycastHit2D.point;
                }
                else
                {
                    yield break;
                }
            }

            float x = UnityEngine.Random.value * 10000f;
            float distance = Vector2.Distance(transform.position, targetPoint);
            float num = distance * 0.2f;
            cooldown = CooldownTime;
            StartCoroutine(Mod.ModAPIPlus.PlaySound(targetPoint, FindObjectOfType<LightningToolEntityBehaviour>().Thunder.PickRandom()));

            int num2 = vertices.Length;
            for (int j = 0; j < num2; j++)
            {
                float num3 = (float)j / (float)num2;
                float num4 = 1f - Mathf.Abs(2f * num3 - 1f);
                Vector3 vector = (Utils.GetPerlin2Mapped(x, num3 / num * 19f) + (Vector3)UnityEngine.Random.insideUnitCircle * 0.2f) * num4;
                vertices[j] = Vector3.Lerp(transform.position, targetPoint, num3) + num * vector;
            }

            lightningToolEntityBehaviour.SingleBolt.SetPositions(vertices);
#pragma warning disable CS0612 // Type or member is obsolete
            ExplosionCreator.CreateExplosionWithWater(WaterBehaviour.IsPointUnderWater(targetPoint), new ExplosionCreator.ExplosionParameters(8u, targetPoint, 15f, 8f, createFx: true, big: true));
#pragma warning restore CS0612 // Type or member is obsolete

            if (targetPerson != null && targetPerson.Limbs.Length > 1)
            {
                var targetLimb = targetPerson.Limbs[1];
                if (targetLimb != null && targetLimb.PhysicalBehaviour != null)
                {
                    targetLimb.PhysicalBehaviour.Charge += 150f;
                }
            }
            else
            {
                Collider2D col = Physics2D.OverlapPoint(targetPoint);
                if (col != null && Global.main.PhysicalObjectsInWorldByTransform.TryGetValue(col.transform, out var value))
                {
                    value.Charge += 150f;
                }
            }

            for (int i = 0; i < UnityEngine.Random.Range(2, 5); i++)
            {
                lightningToolEntityBehaviour.SingleBolt.enabled = true;
                lightningToolEntityBehaviour.LargeFlashLight.enabled = true;
                yield return new WaitForSeconds(0.032f);
                lightningToolEntityBehaviour.SingleBolt.enabled = false;
                lightningToolEntityBehaviour.LargeFlashLight.enabled = false;
                yield return new WaitForSeconds(UnityEngine.Random.Range(0.032f, 0.3f));
            }
        }

        public override void FixedUpdate()
        {
            dist = Vector2.Distance(transform.position, oldPos);

            oldPos = transform.position;

            base.FixedUpdate();
        }

        public override void Use2()
        {
            if(isHeld)
            {
                StopHold();
            }
            else
            {
                StartHold();
            }
        }

        private void Update()
        {
            lightningToolEntityBehaviour.transform.position = transform.position;

            if (otherCooldown > 0f)
            {
                otherCooldown -= Time.unscaledDeltaTime;
            }


            if (physicalBehaviour.StartedBeingUsedContinuously())
            {
                StartHold();
            }

            if (physicalBehaviour.StoppedBeingUsedContinuously())
            {
                StopHold();
            }

            if (!isHeld)
            {
                return;
            }

            foreach (var collider2D in Physics2D.OverlapCircleAll(transform.position, 1, LayerMask.GetMask("Objects")))
            {
                if (Global.main.PhysicalObjectsInWorldByTransform.TryGetValue(collider2D.transform, out var value) && value.transform.root != transform.root)
                {
                    if(value.transform.root.TryGetComponent<PersonBehaviour>(out var person) && holders.Contains(person))
                    {
                        continue;
                    }

                    value.Charge += 2f * Time.deltaTime;
                }
            }

            if (cooldown > 0f)
            {
                cooldown -= Time.unscaledDeltaTime;
            }
            else if (dist > 1)
            {
                StartCoroutine(lightning());
            }
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            if (otherCooldown > 0f)
            {
                return;
            }

            if (col.collider.name.ToLower().Contains("captain") && col.collider.name.ToLower().Contains("shield") && col.relativeVelocity.magnitude > 5)
            {
                otherCooldown = 1f;

                CameraShakeBehaviour.main.Shake(55 / 5, transform.position);

                var emp = Instantiate(ModAPI.FindSpawnable("EMP Generator").Prefab.GetComponent<EMPBehaviour>().Effect);

                emp.transform.position = transform.position;
                emp.transform.localScale = Vector3.one;
                var main = emp.GetComponent<ParticleSystem>().main;
                main.startColor = new Color(0.8f, 0.8f, 1, 1);
                var n = main.startLifetime;
                n.constantMax *= 0.5f;
                main.simulationSpeed *= 1.5f;
                emp.transform.GetChild(0).GetComponent<ParticleSystem>().startColor = new Color(0.8f, 0.8f, 1, 1);
                StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position , FindObjectOfType<LightningToolEntityBehaviour>().Thunder.PickRandom()));

                Mod.ModAPIPlus.SetPFXColors(ModAPI.CreateParticleEffect(ParticleEffects.BigExplosion, transform.position), new Color(0.8f, 0.8f, 1, 1));
                
                Collider2D[] cols = Physics2D.OverlapCircleAll(transform.position, 10);

                foreach (var coll in cols)
                {
                    if (coll.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        limb.Person.ShockLevel = 55;
                        int rand = UnityEngine.Random.Range(0, Mathf.RoundToInt(100 / (55 / 45)));
                        if (rand == 1)
                        {
                            limb.Person.SeizureTime = rand;
                        }
                    }
                }

                var colliders = Physics2D.OverlapCircleAll(transform.position, 20f);

                foreach (var collider in colliders)
                {
                    if (!collider.attachedRigidbody)
                        continue;

                    if (collider.TryGetComponent<DamagableMachineryBehaviour>(out var da))
                    {
                        da.ForceBreak();
                    }

                    if (collider.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        limb.Damage(25 * (55 / 60) / Vector2.Distance(limb.transform.position, transform.position));

                        collider.attachedRigidbody?.AddForce((collider.transform.position - transform.position).normalized * 40f / Mathf.Clamp(Vector2.Distance(transform.position, transform.position), 0.1f, 100) * (55 / 45));
                    }
                    else if (collider.TryGetComponent<DestroyableBehaviour>(out var dest))
                    {
                        float rand = UnityEngine.Random.Range(0, 10 * Vector2.Distance(collider.transform.position, transform.position));
                        Debug.Log(rand);

                        if (rand <= 5f)
                        {
                            dest.Break();
                        }

                        collider.attachedRigidbody?.AddForce((collider.transform.position - transform.position).normalized * 35f / Mathf.Clamp(Vector2.Distance(transform.position, transform.position), 0.1f, 100) * (55 / 45));

                    }
                    else if (limb == null && !collider.name.Contains("Cape"))
                    {
                        collider.attachedRigidbody?.AddForce((collider.transform.position - transform.position).normalized * 35f / Mathf.Clamp(Vector2.Distance(transform.position, transform.position), 0.1f, 100) * (55 / 45));
                    }

                }
            }
        }

