    public class Summonable : MonoBehaviour, Mod.ModAPIPlus.IUse2, Messages.IOnGripped
    {
        bool summoning = false;
        PhysicalBehaviour phys;
        Hammer.HammerSummon hammerSummoner;

        public float followDistance = 1.5f;
        public float damping = 0.3f;
        public float moveForce = 15f;

        public virtual void Start()
        {
            phys = GetComponent<PhysicalBehaviour>();
        }

        public virtual void SummonToHand(Hammer.HammerSummon summoner)
        {
            if(phys.beingHeldByGripper)
                return;

            StartCoroutine(Mod.ModAPIPlus.PlaySound(transform.position, Mod.Hammer));

            phys.rigidbody.gravityScale = 0;
            hammerSummoner = summoner;
            summoning = true;
        }

        public virtual void FixedUpdate()
        {
            if (!summoning || hammerSummoner == null)
                return;

            if (phys == null)
                phys = GetComponent<PhysicalBehaviour>();
            var rb = phys != null ? phys.rigidbody : null;
            if (rb == null)
                return;

            float angleErrorDeg = Mathf.DeltaAngle(rb.rotation, 0f);
            float angVelDeg = rb.angularVelocity;
            float inertia = Mathf.Max(0.01f, rb.inertia);

            const float kP_up = 10f;
            const float kD_up = 2.2f;

            float desiredAngAccelDeg = (-kP_up * angleErrorDeg) - (kD_up * angVelDeg);
            float torque = desiredAngAccelDeg * Mathf.Deg2Rad * inertia;

            float maxTorque = Mathf.Clamp(inertia * 60f, 10f, 1200f);
            torque = Mathf.Clamp(torque, -maxTorque, maxTorque);
            rb.AddTorque(torque, ForceMode2D.Force);

            Vector2 targetPos = hammerSummoner.transform.position;
            Vector2 toTarget = targetPos - rb.position;
            float distance = toTarget.magnitude;
            float shell = Mathf.Max(0.01f, followDistance);

            if (distance > shell)
            {
                Vector2 dir = toTarget / distance;
                float distExcess = distance - shell;

                const float baseSpeed = 12f;
                const float speedPerUnit = 4.5f;
                const float maxSpeed = 55f;

                float desiredSpeed = Mathf.Min(maxSpeed, baseSpeed + speedPerUnit * distExcess);
                Vector2 desiredVel = dir * desiredSpeed;

                const float velResponse = 9f;
                const float springAccelPerUnit = 28f;
                const float maxAccel = 140f;

                Vector2 accel = (desiredVel - rb.velocity) * velResponse;
                accel += dir * Mathf.Min(60f, springAccelPerUnit * distExcess);

                float accelMag = accel.magnitude;
                if (accelMag > maxAccel)
                    accel *= (maxAccel / accelMag);

                rb.AddForce(accel * rb.mass, ForceMode2D.Force);
            }
            else
            {
                rb.velocity = Vector2.Lerp(rb.velocity, Vector2.zero, Mathf.Clamp01(damping * 0.5f));
            }

            float linDamp = Mathf.Clamp01(damping * 0.12f);
            rb.velocity *= (1f - linDamp);
            rb.angularVelocity *= 0.985f;
        }

        public virtual void Use2()
        {
            if (summoning)
            {
                summoning = false;
                hammerSummoner = null;
                phys.rigidbody.gravityScale = 1;
            }
        }

        public virtual void OnGripped(GripBehaviour gripper)
        {
            summoning = false;
            hammerSummoner = null;
            phys.rigidbody.gravityScale = 1;

            if (gripper.TryGetComponent<Hammer.HammerSummon>(out var hammerSummon))
            {
                hammerSummon.summonable = this;
            }
        }
    }

    public class Summoning : Power, Mod.ModAPIPlus.IUse2
    {
        public PersonBehaviour person;
        public GameObject prefab;
        public string pfxname;
        public List<List<Sprite>> cloneSprite;
        public List<GameObject> clones = new List<GameObject>();
        public Action<GameObject> edit;
        bool weak;

        public float RingRadius = 7;
        public float ArrivalStrength = 10f;
        public float ArrivalMaxSpeed = 15f;
        public float ArrivalStopThreshold = 0.25f;

        public static Summoning SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, GameObject prefab, List<List<Sprite>> cloneSprite, Action<GameObject> edit = null, bool weak = false)
        {
            var power = Limb.gameObject.AddComponent<Summoning>();
            power.Name = "Minions";
            power.Description = "Allows the user to create minions by pressing H on their upper body!";
            power.icon = icon;
            power.prefab = prefab;
            power.pfxname = null;
            power.targetLimb = TargettedLimb.Body;
            power.cloneSprite = cloneSprite;
            power.person = Person;
            power.weak = weak;
            power.edit = edit;
            return power;
        }

        public void Use2()
        {
            if (Enabled && person != null && person.IsAlive())
            {
                var spawnable = ModAPI.FindSpawnable(person.name);
                if (spawnable == null || spawnable.Prefab == null || person.Limbs == null || person.Limbs.Length <= 2)
                    return;

                Vector3 spawnPos = GetSpawnPositionOutsideCamera(person.Limbs[2].transform.position);
                var copy = GameObject.Instantiate(spawnable.Prefab, spawnPos, Quaternion.identity);
                if (copy == null || copy.transform == null || transform == null || transform.root == null)
                    return;
                copy.transform.root.transform.localScale = transform.root.transform.localScale;
                if (clones == null)
                    clones = new List<GameObject>();
                clones.Add(copy);
                var cloneComponent = copy.GetComponentInChildren<Summoning>();
                if (cloneComponent != null)
                    Destroy(cloneComponent);
                var clon = copy.gameObject.AddComponent<ClonedPerson>();
                clon.PersonBehaviour = copy.GetComponent<PersonBehaviour>();
                clon.clone = this;
                clon.ParticlePrefab = !prefab ? null : prefab;
                clon.pfxname = pfxname;
                clon.weak = weak;
                
                clon.InitializeArrival(person, RingRadius, ArrivalStrength, ArrivalMaxSpeed, ArrivalStopThreshold);

                edit?.Invoke(copy);

                Timtam.MakeCustomSkin(copy.GetComponent<PersonBehaviour>(), cloneSprite[UnityEngine.Random.Range(0, cloneSprite.Count)], false, true);
                

                var copyPerson = copy.GetComponent<PersonBehaviour>();
                if (copyPerson != null && copyPerson.Limbs != null && person.Limbs != null)
                {
                    foreach (var limb in copyPerson.Limbs)
                    {
                        foreach (var limbb in person.Limbs)
                        {
                            if (limb != null && limbb != null && limb.Collider != null && limbb.Collider != null)
                                Physics2D.IgnoreCollision(limb.Collider, limbb.Collider, true);
                        }

                        GameObject effect = null;
                        if (prefab != null)
                        {
                            effect = Instantiate(prefab);
                        }
                        else if (!string.IsNullOrEmpty(pfxname))
                        {
                            effect = ModAPI.CreateParticleEffect(pfxname, limb.transform.position);
                        }

                        if (effect != null)
                        {
                            effect.transform.position = limb.transform.position;
                            var ps = effect.GetComponent<ParticleSystem>();
                            if (ps != null) ps.Play();
                            var audio = effect.GetComponent<AudioSource>();
                            if (audio != null) Destroy(audio);
                            var lightFlash = effect.transform.Find("SpriteLightFlash");
                            if (lightFlash != null) Destroy(lightFlash.gameObject);
                        }
                    }
                    
                }

                var clonPerson = clon.GetComponent<PersonBehaviour>();
                if (clonPerson != null && clonPerson.Limbs != null && clones != null)
                    foreach (var limb in clonPerson.GetComponentsInChildren<Collider2D>())
                        if (limb != null && limb != null)
                            foreach (var clone2 in clones)
                                if (clone2 != null)
                                {
                                    var clone2Person = clone2.GetComponent<PersonBehaviour>();
                                    if (clone2Person != null && clone2Person.Limbs != null)
                                        foreach (var limb2 in clone2.GetComponentsInChildren<Collider2D>())
                                            if (limb2 != null && limb2 != null)
                                                Physics2D.IgnoreCollision(limb, limb2, true);
                                }

                foreach (var hat in copyPerson.gameObject.GetComponentsInChildren<HatBehaviour.HasHat>())
                {
                    foreach (var clone2 in clones)
                    {
                        foreach (var hat2 in clone2.gameObject.GetComponentsInChildren<HatBehaviour.HasHat>())
                            Physics2D.IgnoreCollision(hat.hat.GetComponent<Collider2D>(), hat2.hat.GetComponent<Collider2D>(), true);

                        foreach (var col in clone2.gameObject.GetComponentsInChildren<Collider2D>())
                            Physics2D.IgnoreCollision(hat.hat.GetComponent<Collider2D>(), col.GetComponent<Collider2D>(), true);
                    }
                }
            }
        }

        private static Vector3 GetSpawnPositionOutsideCamera(Vector3 fallback)
        {
            var cam = Camera.main;
            if (cam == null || !cam.orthographic)
            {
                return fallback + new Vector3(3f, 3f, 0f);
            }

            Vector3 camPos = cam.transform.position;
            float halfH = cam.orthographicSize;
            float halfW = halfH * cam.aspect;

            float margin = 2.5f;
            int side = UnityEngine.Random.Range(0, 4);
            Vector2 spawn = Vector2.zero;

            switch (side)
            {
                case 0:
                    spawn.x = camPos.x - halfW - margin;
                    spawn.y = UnityEngine.Random.Range(camPos.y - halfH, camPos.y + halfH);
                    break;
                case 1:
                    spawn.x = camPos.x + halfW + margin;
                    spawn.y = UnityEngine.Random.Range(camPos.y - halfH, camPos.y + halfH);
                    break;
                case 2:
                    spawn.y = camPos.y + halfH + margin;
                    spawn.x = UnityEngine.Random.Range(camPos.x - halfW, camPos.x + halfW);
                    break;
                case 3:
                    spawn.y = camPos.y - halfH - margin;
                    spawn.x = UnityEngine.Random.Range(camPos.x - halfW, camPos.x + halfW);
                    break;
            }

            return new Vector3(spawn.x, spawn.y, 0f);
        }

        public class ClonedPerson : MonoBehaviour
        {
            public Summoning clone;
            public PersonBehaviour PersonBehaviour;
            public GameObject ParticlePrefab;
            public string pfxname;
            public bool weak;

            private float angle;

            private bool arrivalInitialized;
            private bool arrived;
            private Vector2 targetCenter;
            private float ringRadius = 3.5f;
            private float moveStrength = 10f;
            private float maxSpeed = 15f;
            private float stopThreshold = 0.25f;

            public void InitializeArrival(PersonBehaviour owner, float radius, float strength, float maxSpd, float stopThresh)
            {
                ringRadius = radius;
                moveStrength = strength;
                maxSpeed = Mathf.Max(0.1f, maxSpd);
                stopThreshold = Mathf.Max(0.05f, stopThresh);

                BuildIgnoreSet(owner, PersonBehaviour);

                Vector2 ownerCenter = ComputeCenter(owner?.Limbs);

                Vector2 chosen;
                if (!TryFindClearRingPoint(ownerCenter, ringRadius, out chosen))
                {
                    float ang = UnityEngine.Random.Range(0f, Mathf.PI * 2f);
                    chosen = ownerCenter + new Vector2(Mathf.Cos(ang), Mathf.Sin(ang)) * ringRadius;
                }

                angle = Mathf.Atan2(chosen.y - ownerCenter.y, chosen.x - ownerCenter.x);
                targetCenter = chosen;

                arrivalInitialized = true;
                arrived = false;
            }

            private readonly HashSet<Collider2D> _ignoreCols = new HashSet<Collider2D>();
            private const float DefaultClearanceRadius = 1.25f;
            private const int MaxClearSearchAttempts = 48;

            private void BuildIgnoreSet(PersonBehaviour owner, PersonBehaviour clone)
            {
                _ignoreCols.Clear();

                if (owner?.Limbs != null)
                {
                    foreach (var l in owner.Limbs)
                    {
                        if (!l) continue;
                        foreach (var c in l.GetComponentsInChildren<Collider2D>(true))
                            if (c) _ignoreCols.Add(c);
                    }
                }

                if (clone?.Limbs != null)
                {
                    foreach (var l in clone.Limbs)
                    {
                        if (!l) continue;
                        foreach (var c in l.GetComponentsInChildren<Collider2D>(true))
                            if (c) _ignoreCols.Add(c);
                    }
                }
            }

            private bool TryFindClearRingPoint(Vector2 center, float radius, out Vector2 result)
            {
                for (int i = 0; i < MaxClearSearchAttempts; i++)
                {
                    float ang = UnityEngine.Random.Range(0f, Mathf.PI * 2f);
                    Vector2 candidate = center + new Vector2(Mathf.Cos(ang), Mathf.Sin(ang)) * radius;
                    if (IsClear(candidate, DefaultClearanceRadius))
                    {
                        result = candidate;
                        return true;
                    }
                }

                int sweepSteps = 36;
                for (int i = 0; i < sweepSteps; i++)
                {
                    float ang = (i / (float)sweepSteps) * Mathf.PI * 2f;
                    Vector2 candidate = center + new Vector2(Mathf.Cos(ang), Mathf.Sin(ang)) * radius;
                    if (IsClear(candidate, DefaultClearanceRadius))
                    {
                        result = candidate;
                        return true;
                    }
                }

                result = Vector2.zero;
                return false;
            }

            private bool IsClear(Vector2 point, float clearanceRadius)
            {
                int mask = LayerMask.GetMask("Objects", "Bounds");
                var hits = Physics2D.OverlapCircleAll(point, clearanceRadius, mask);
                if (hits == null || hits.Length == 0) return true;

                foreach (var h in hits)
                {
                    if (!h) continue;
                    if (_ignoreCols.Contains(h)) continue;
                    if (h.isTrigger) continue;
                    return false;
                }

                return true;
            }

            public void FixedUpdate()
            {
                if (PersonBehaviour == null || clone == null || clone.person == null)
                    return;

                if (arrivalInitialized && !arrived)
                {
                    arrived = MoveLimbsTowardsRingTarget();
                }
            }

            private Vector2 ComputeCenter(IEnumerable<LimbBehaviour> limbs)
            {
                if (limbs == null) return transform.position;
                Vector2 sum = Vector2.zero;
                int count = 0;
                foreach (var l in limbs)
                {
                    if (l == null) continue;
                    sum += (Vector2)l.transform.position;
                    count++;
                }
                return count > 0 ? sum / count : (Vector2)transform.position;
            }

            private bool MoveLimbsTowardsRingTarget()
            {
                if (PersonBehaviour == null || PersonBehaviour.Limbs == null || PersonBehaviour.Limbs.Length == 0)
                    return true;

                Vector2 cloneCenter = ComputeCenter(PersonBehaviour.Limbs);

                foreach (var limb in PersonBehaviour.Limbs)
                {
                    if (limb == null || limb.PhysicalBehaviour == null) continue;
                    var rb = limb.PhysicalBehaviour.rigidbody;
                    if (rb == null || rb.bodyType == RigidbodyType2D.Static) continue;

                    Vector2 desiredPos = targetCenter + ((Vector2)limb.transform.position - cloneCenter);
                    Vector2 toTarget = desiredPos - (Vector2)limb.transform.position;

                    Vector2 desiredVel = toTarget * moveStrength;
                    if (desiredVel.magnitude > maxSpeed)
                        desiredVel = desiredVel.normalized * maxSpeed;

                    rb.velocity = Vector2.Lerp(rb.velocity, desiredVel, 0.2f);
                }

                float dist = Vector2.Distance(cloneCenter, targetCenter);
                if (dist <= stopThreshold)
                {
                    foreach (var limb in PersonBehaviour.Limbs)
                    {
                        if (limb == null || limb.PhysicalBehaviour == null) continue;
                        var rb = limb.PhysicalBehaviour.rigidbody;
                        if (rb == null) continue;
                        rb.velocity *= 0.5f;
                    }
                    return true;
                }

                return false;
            }
        }
    }

    public class UltronTouch : Power, Mod.ModAPIPlus.IUse2
    {
        public UltronBot bot;
        public ParticleSystem Bolt;
        bool Using = false;

        public static UltronTouch SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, UltronBot bott)
        {
            var power = Limb.gameObject.AddComponent<UltronTouch>();
            power.Name = "Body Switch";
            power.Description = "Allows ultron to switch bodies to another bot\n<color=\"yellow\">Use alternate activation key (typically H) on Lower Arm to toggle";
            power.icon = icon;
            power.bot = bott;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            var bolt = Instantiate(ModAPI.FindSpawnable("Particle Projector").Prefab.transform.FindChild("bolts").gameObject);
            bolt.transform.parent = Limb.transform;
            bolt.transform.GetChild(0).gameObject.GetComponent<ParticleSystem>().startColor = Color.red;
            bolt.transform.GetChild(1).gameObject.GetComponent<ParticleSystem>().startColor = Color.red;
            var boltmain = bolt.GetComponent<ParticleSystem>().main;
            boltmain.startColor = Color.yellow;
            bolt.transform.localPosition = Vector2.zero;
            bolt.transform.localScale = new Vector3(0.1f, 0.1f, 0.1f);
            power.Bolt = bolt.GetComponent<ParticleSystem>();
            return power;
        }

        public override void DisablePower()
        {
            base.DisablePower();

            Using = false;
            Bolt.Stop();
        }

        public void FixedUpdate()
        {
            if (bot == null && Enabled || bot.Ultron == false && Enabled)
                DisablePower();
        }

        public void Use2()
        {
            if (!Enabled || bot == null || bot.Ultron == false)
                return;
            if (!Using)
            {
                Using = true;
                Bolt.Play();
            }
            else
            {
                Using = false;
                Bolt.Stop();
            }
        }

        public void OnCollisionEnter2D(Collision2D collision)
        {
            if (Using && Enabled)
            {
                if (collision.transform.root.TryGetComponent<UltronBot>(out var Bot))
                {
                    if (Bot.person.name.Contains("Vision") && Bot.person.IsAlive())
                        return;

                    Bot.Activate(true);
                    Bot.Ultron = true;
                    bot.Inactive = true;
                    bot.Ultron = false;
                    bot.person.Braindead = true;
                    bot.person.Limbs[0].Health = 0;
                    ModAPI.CreateParticleEffect(ParticleEffects.BigZap, bot.person.Limbs[0].transform.position);
                    StartCoroutine(bot.ActivateLine(bot.person.Limbs[0].transform, Bot.person.Limbs[0].transform));
                    ModAPI.Notify("Ultron has transferred to another body!");
                    DisablePower();
                }
            }
        }
    }

    public class UltronBot : MonoBehaviour
    {
        public List<SpriteRenderer> glows = new List<SpriteRenderer>();

        public bool Ultron = false;
        public bool Inactive = false;
        bool attempted;

        public PersonBehaviour person;
        LineRenderer line;

        bool glowsNormally = true;

        public Color normalColor;

        public static UltronBot SetBot(PersonBehaviour Person, List<Sprite> Glows, bool isUltron = false, bool glowsNormally = true, Color normalColor = default)
        {
            var bot = Person.gameObject.AddComponent<UltronBot>();
            bot.normalColor = normalColor == default ? Color.red : normalColor;
            bot.glowsNormally = glowsNormally;
            bot.Ultron = isUltron;
            bot.person = Person;
            bot.line = new GameObject("ultronLine").AddComponent<LineRenderer>();
            bot.line.positionCount = 2;
            bot.line.startWidth = 0.01f;
            bot.line.endWidth = 0.01f;
            bot.line.material = ModAPI.FindMaterial("VeryBright");
            bot.line.startColor = Color.clear;
            bot.line.endColor = Color.clear;
            bot.line.sortingLayerName = Layers.Sorting.Bottom;

            foreach (var limb in Person.Limbs)
            {
                limb.PhysicalBehaviour.ContextMenuOptions.Buttons.Add(new ContextMenuButton(() => !ColorpickerDialogBehaviour.IsOpen, "toggleActive", "<color=\"yellow\">Toggle Active", "<color=\"yellow\">Toggle Active", delegate
                {
                    if (bot.Inactive)
                    {
                        bot.Activate(false);
                    }else
                    {
                        bot.Inactive = true;
                        bot.person.Limbs[0].Health = 0;
                        bot.person.Braindead = true;
                    }
                }));

                foreach (var glow in Glows)
                {
                    string a = glow.name;
                    a = a.Replace("G", "");
                    if (limb.name.Contains(a))
                    {
                        var sr = new GameObject("Glow").AddComponent<SpriteRenderer>();
                        sr.sprite = glow;
                        sr.gameObject.layer = 9;
                        sr.sortingLayerName = limb.GetComponent<SpriteRenderer>().sortingLayerName;
                        sr.sortingOrder = limb.GetComponent<SpriteRenderer>().sortingOrder + 1;
                        sr.color = Color.clear;
                        sr.material = ModAPI.FindMaterial("VeryBright");
                        sr.transform.SetParent(limb.transform, false);

                        bot.glows.Add(sr);
                    }
                }
            }
            return bot;
        }

        public void Activate(bool ultronn = true)
        {
            if (!Inactive)
                return;

            if(ultronn == true)
                Ultron = true;

            person.Braindead = false;
            person.Limbs[0].Health = person.Limbs[0].InitialHealth / 10;
            person.Braindead = false;
            person.BrainDamaged = false;
            person.Heartbeat = 100;
            person.AdrenalineLevel = 1;

            foreach (var limb in person.Limbs)
            {
                foreach (var limb2 in ModAPI.FindSpawnable("Android").Prefab.GetComponent<PersonBehaviour>().Limbs)
                {
                    if (limb.name == limb2.name)
                    {
                        limb.SkinMaterialHandler.renderer.material = limb2.SkinMaterialHandler.renderer.material;
                    }
                }
                limb.CirculationBehaviour.AddLiquid(limb.GetOriginalBloodType(), 10);
                limb.CirculationBehaviour.BloodFlow = 50;
                limb.Numbness = 0;
                person.Heartbeat = 100;

                if (limb.name.Contains("LowerArm") && Ultron)
                {
                    if (limb.TryGetComponent<UltronTouch>(out var toch) && toch != null)
                        toch.EnablePower();
                    else
                        UltronTouch.SetPower(person, limb, null, this).EnablePower();
                }
            }

            Inactive = false;
        }

        public void FixedUpdate()
        {
            foreach (var glow in glows)
            {
                if (person.IsAlive())
                {
                    if (Ultron)
                        glow.color = Color.Lerp(glow.color, new Color(Color.red.r, Color.red.g, Color.red.b, Inactive ? 0 : 0.3f), 0.1f);
                    else
                        glow.color = Color.Lerp(glow.color, new Color(normalColor.r, normalColor.g, normalColor.b, Inactive ? 0 : glowsNormally ? 0.05f : 0), 0.1f);
                }else
                {
                    glow.color = Color.Lerp(glow.color, new Color(Color.red.r, Color.red.g, Color.red.b, 0), 0.1f);
                }

            }

            foreach (var limb in person.Limbs)
            {
                foreach (var limb2 in ModAPI.FindSpawnable("Android").Prefab.GetComponent<PersonBehaviour>().Limbs)
                {
                    if (limb.name == limb2.name)
                    {
                        limb.SkinMaterialHandler.renderer.material = limb2.SkinMaterialHandler.renderer.material;
                        limb.BaseStrength = limb2.BaseStrength;
                        limb.FakeUprightForce = limb2.FakeUprightForce;
                        limb.PhysicalBehaviour.TrueInitialMass = limb2.PhysicalBehaviour.rigidbody.mass;
                        limb.PhysicalBehaviour.rigidbody.mass = limb2.PhysicalBehaviour.rigidbody.mass;
                    }
                }
            }

            if (Ultron)
                if (attempted == false)
                {
                    if (person.Braindead == true)
                    {
                        //if (Settings.main.Get<bool>("UltronSwapping") == false)
                            //return;
                        EnterOtherBot();
                        attempted = true;
                    }
                }
                else if(!person.Braindead && attempted)
                {
                    attempted = false;
                }
        }

        public void EnterOtherBot()
        {
            var bots = FindObjectsOfType<UltronBot>();
            UltronBot otherBot = null;
            foreach (var bot in bots)
            {
                if (bot != this)
                {
                    if (bot.name.Contains("Vision") && !bot.Inactive)
                        continue;
                    otherBot = bot;
                    break;
                }
            }

            if (otherBot != null)
            {
                StartCoroutine(PlaySound(Mod.Swap));
                ModAPI.CreateParticleEffect(ParticleEffects.BigZap, person.Limbs[0].transform.position);
                StartCoroutine(ActivateLine(person.Limbs[0].transform, otherBot.person.Limbs[0].transform));
                otherBot.Activate(true);
                otherBot.Ultron = true;
                ActivateLine(person.Limbs[0].transform, otherBot.person.Limbs[0].transform);
                Inactive = true;
                Ultron = false;
                person.Limbs[0].Health = 0;
                person.Braindead = true;
                ModAPI.Notify("Ultron has transferred to another body!");
            }
            else
            {
                ModAPI.Notify("Ultron cannot transform bodies!");
            }
        }

        public IEnumerator ActivateLine(Transform position1, Transform position2)
        {
            line.SetPosition(0, position1.position);
            line.SetPosition(1, position2.position);
            line.startColor = Color.red;
            line.endColor = Color.red;

            var duration = 1;
            float elapsedTime = 0;
            while (elapsedTime < duration)
            {
                line.SetPosition(0, position1.position);
                line.SetPosition(1, position2.position);
                line.startColor = Color.Lerp(Color.red, Color.clear, (elapsedTime / duration));
                line.endColor = Color.Lerp(Color.red, Color.clear, (elapsedTime / duration));
                elapsedTime += Time.deltaTime;
                yield return null;
            }
            line.startColor = Color.clear;
            line.endColor = Color.clear;
        }

        private IEnumerator PlaySound(AudioClip SoundToPlay)
        {
            var sound = new GameObject();
            sound.name = "SFX";
            sound.transform.position = gameObject.transform.position;
            sound.AddComponent<AudioSource>();
            sound.GetComponent<AudioSource>().playOnAwake = false;
            sound.GetComponent<AudioSource>().clip = SoundToPlay;
            sound.GetComponent<AudioSource>().spatialBlend = 1;
            sound.GetComponent<AudioSource>().volume = 5f;
            sound.AddComponent<AudioDistortionFilter>().distortionLevel = 0.85f;
            sound.AddComponent<AudioSourceTimeScaleBehaviour>();
            sound.GetComponent<AudioSource>().Play();
            sound.AddComponent<OBJDestroyer>();
            yield return new WaitForSeconds(SoundToPlay.length);

            Destroy(sound);
        }
    }

    public class EMPHand : Power, Mod.ModAPIPlus.IUse2
    {
        public ParticleSystem Bolt;
        bool Using = false;

        public static EMPHand SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<EMPHand>();
            power.Name = "EMP Touch";
            power.Description = "Allows the user to disable any electronic devices while touching them\n<color=\"yellow\">Use alternate activation key (typically H) on Lower Arm to toggle claws";
            power.icon = icon;

            if (power.name.Contains("Front"))
            {
                power.targetLimb = TargettedLimb.FrontArm;
            }
            else
            {
                power.targetLimb = TargettedLimb.BackArm;
            }

            var bolt = Instantiate(ModAPI.FindSpawnable("Particle Projector").Prefab.transform.FindChild("bolts").gameObject);
            bolt.transform.parent = Limb.transform;
            bolt.transform.GetChild(0).gameObject.GetComponent<ParticleSystem>().startColor = Color.yellow;
            bolt.transform.GetChild(1).gameObject.GetComponent<ParticleSystem>().startColor = Color.yellow;
            var boltmain = bolt.GetComponent<ParticleSystem>().main;
            boltmain.startColor = Color.yellow;
            bolt.transform.localPosition = Vector2.zero;
            bolt.transform.localScale = new Vector3(0.3f, 0.3f, 0.3f);
            power.Bolt = bolt.GetComponent<ParticleSystem>();
            return power;
        }

        public override void DisablePower()
        {
            base.DisablePower();

            Using = false;
            Bolt.Stop();
        }

        public void Use2()
        {
            if (!Enabled)
                return;
            if (!Using)
            {
                Using = true;
                Bolt.Play();
            }
            else
            {
                Using = false;
                Bolt.Stop();
            }
        }

        public void OnCollisionEnter2D(Collision2D collision)
        {
            if (Using && Enabled)
            {
                if (collision.gameObject.TryGetComponent<PhysicalBehaviour>(out var phys))
                {
                    if (phys.TryGetComponent<DamagableMachineryBehaviour>(out var dam))
                    {
                        if (!dam.Destroyed)
                        {
                            ModAPI.CreateParticleEffect(ParticleEffects.BigZap, phys.transform.position);
                            dam.Health = 0;
                            dam.Break(Vector2.zero);
                        }
                    }
                    else if (phys.transform.root.TryGetComponent<PersonBehaviour>(out var person) && phys.TryGetComponent<LimbBehaviour>(out var limb) && person.Braindead == false)
                    {
                        if(person.name.Contains("Ultron"))
                        {
                            ModAPI.CreateParticleEffect(ParticleEffects.BrokenElectronicsSpark, phys.transform.position);
                            foreach (var limbb in person.Limbs) limbb.Damage(5);

                            if (person.name.Contains("Bot"))
                            {
                                person.Braindead = true;
                                ModAPI.CreateParticleEffect(ParticleEffects.BigZap, phys.transform.position);
                            }
                        }
                    }
                }
            }
        }
    }

    public class VisionBeam : Power, Messages.IUse
    {
        public PersonBehaviour person;

        AudioSource Source;
        bool doingTransition;
        bool Lasering;

        RaycastHit2D hit;
        public LineRenderer line;
        public SpriteRenderer GlowEye;
        public TrailRenderer trail;
        public GameObject RaycastPoint;
        public GameObject RaycastPoint2;
        public float blastRadius = 20f;
        public float maxForce = 10f;
        public float crushRadius = 5f;

        Vector3 offset;

        public static Power SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon, Vector2 offset = default)
        {
            var power = Limb.gameObject.AddComponent<VisionBeam>();
            power.Name = "Vision Beam";
            power.icon = icon;
            power.person = Person;
            power.targetLimb = TargettedLimb.Head;
            power.offset = offset == null ? Vector2.zero : offset;
            Limb.gameObject.GetOrAddComponent<AbilityCycler>().targetPowers = Mod.ModAPIPlus.GetTargettedLimb(Limb.gameObject);
            return power;
        }

        public override void Start()
        {
            line = gameObject.GetOrAddComponent<LineRenderer>();
            line.startColor = Color.yellow;
            line.endColor = Color.yellow;
            line.startWidth = 0.025f;
            line.endWidth = 0.025f;
            line.material = UnityEngine.Object.Instantiate<Material>(ModAPI.FindMaterial("VeryBright"));
            line.material.SetFloat("_GlowIntensity", 0.05f);
            line.material.mainTexture = ModAPI.FindMaterial("Sprites-Default").mainTexture;
            line.sortingOrder = gameObject.GetComponent<SpriteRenderer>().sortingOrder + 1;
            line.sortingLayerID = gameObject.GetComponent<SpriteRenderer>().sortingLayerID;
            line.positionCount = 2;
            line.enabled = false;

            trail = new GameObject("trail").AddComponent<TrailRenderer>();
            trail.transform.parent = transform;
            trail.transform.localPosition = (new Vector3(5f, 2f, 0) * ModAPI.PixelSize) + offset;
            trail.transform.localRotation = Quaternion.identity;
            trail.transform.localScale = Vector3.one;
            trail.gameObject.layer = gameObject.layer;
            trail.time = 0.1f;
            trail.startWidth = 0.02f;
            trail.endWidth = 0.005f;
            trail.material = UnityEngine.Object.Instantiate<Material>(ModAPI.FindMaterial("VeryBright"));
            trail.startColor = new Color(1, 1, 0, 0.2f);
            trail.endColor = new Color(0, 0, 0, 0);
            trail.sortingLayerName = gameObject.GetComponent<SpriteRenderer>().sortingLayerName;
            trail.sortingOrder = gameObject.GetComponent<SpriteRenderer>().sortingOrder + 1;
            trail.enabled = false;

            GlowEye = new GameObject("GlowEye").AddComponent<SpriteRenderer>();
            GlowEye.transform.parent = transform;
            GlowEye.transform.localPosition = Vector2.zero + (Vector2)offset;
            GlowEye.transform.localRotation = Quaternion.identity;
            GlowEye.transform.localScale = Vector3.one;
            GlowEye.sprite = Mod.Vision;
            GlowEye.material = UnityEngine.Object.Instantiate<Material>(ModAPI.FindMaterial("VeryBright"));
            GlowEye.color = Color.clear;
            GlowEye.sortingLayerName = gameObject.GetComponent<SpriteRenderer>().sortingLayerName;
            GlowEye.sortingOrder = gameObject.GetComponent<SpriteRenderer>().sortingOrder + 1;
            GlowEye.gameObject.layer = gameObject.layer;

            Source = gameObject.AddComponent<AudioSource>();
            Source.loop = true;
            Source.clip = Mod.Laser;

            if (!gameObject.GetComponent<AudioSourceTimeScaleBehaviour>())
            {
                gameObject.AddComponent<AudioSourceTimeScaleBehaviour>();
            }

            RaycastPoint = new GameObject("RaycastPoint");
            RaycastPoint.transform.parent = transform;
            RaycastPoint.transform.localPosition = (new Vector2(5, 2) * ModAPI.PixelSize) + (Vector2)offset;
            RaycastPoint.transform.localRotation = Quaternion.identity;
            RaycastPoint2 = new GameObject("RaycastPoint2");
            RaycastPoint2.transform.parent = transform;
            RaycastPoint2.transform.localPosition = (new Vector2(5, 2) * ModAPI.PixelSize) + (Vector2)offset;
            RaycastPoint2.transform.localRotation = Quaternion.identity;
            base.Start();
        }

        public void Use(ActivationPropagation activation)
        {
            if (!Enabled)
                return;

            line.endWidth = 0.025f;

            if (!person.Braindead)
            {
                if (!doingTransition && !Lasering)
                {
                    StartCoroutine(Transition());
                    StartCoroutine(PlaySound(Mod.LaserStart));
                }
                else if (!doingTransition)
                {
                    Source.Stop();
                    StartCoroutine(DoneTransition());
                    StartCoroutine(PlaySound(Mod.LaserEnd));
                }
            }
        }

        public override void DisablePower()
        {
            Source.Stop();
            if (Lasering)
                Use(null);
            base.DisablePower();
        }

        public IEnumerator Transition()
        {
            doingTransition = true;
            StartCoroutine(RendererColorTransition(GlowEye, Color.yellow, Color.clear, 1f));
            yield return new WaitForSeconds(1f);
            line.enabled = true;
            StartCoroutine(RendererColorTransition(line, Color.yellow, Color.clear, 0.1f));
            Source.Play();
            Lasering = true;
            trail.enabled = true;
            doingTransition = false;
        }

        public IEnumerator DoneTransition()
        {
            doingTransition = true;
            Source.Stop();

            StartCoroutine(RendererColorTransition(line, Color.clear, Color.yellow, 0.25f));
            yield return new WaitForSeconds(0.25f);
            StartCoroutine(RendererColorTransition(GlowEye, Color.clear, Color.yellow, 1f));

            line.enabled = false;
            Lasering = false;
            trail.enabled = false;
            doingTransition = false;
        }

        public IEnumerator RendererColorTransition(Renderer renderer, Color newColor, Color OriginalColor, float duration = 0.5f)
        {
            if (renderer.GetType() == typeof(SpriteRenderer))
            {
                var sr = renderer as SpriteRenderer;

                float elapsedTime = 0;
                while (elapsedTime < duration)
                {
                    sr.color = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    elapsedTime += Time.deltaTime;
                    yield return null;
                }
                sr.color = newColor;
            }
            else if (renderer.GetType() == typeof(LineRenderer))
            {
                var l = renderer as LineRenderer;

                float elapsedTime = 0;
                while (elapsedTime < duration)
                {
                    l.startColor = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    l.endColor = Color.Lerp(OriginalColor, newColor, (elapsedTime / duration));
                    elapsedTime += Time.deltaTime;
                    yield return null;
                }
                l.startColor = newColor;
                l.endColor = newColor;

            }
        }

        private IEnumerator PlaySound(AudioClip SoundToPlay)
        {
            var sound = new GameObject();
            sound.name = "SFX";
            sound.transform.position = gameObject.transform.position;
            sound.AddComponent<AudioSource>();
            sound.GetComponent<AudioSource>().playOnAwake = false;
            sound.GetComponent<AudioSource>().clip = SoundToPlay;
            sound.GetComponent<AudioSource>().spatialBlend = 1;
            sound.GetComponent<AudioSource>().volume = 5f;
            sound.AddComponent<AudioDistortionFilter>().distortionLevel = 0.85f;
            sound.AddComponent<AudioSourceTimeScaleBehaviour>();
            sound.GetComponent<AudioSource>().Play();
            sound.AddComponent<OBJDestroyer>();
            yield return new WaitForSeconds(SoundToPlay.length);

            Destroy(sound);
        }

        public void Update()
        {
            if (!Enabled)
                return;

            if (Lasering && person.Braindead)
            {
                DoneTransition();
            }


            if (person.transform.localScale.x > 0)
            {
                hit = Physics2D.Raycast(RaycastPoint2.transform.position, RaycastPoint.transform.right, 200000, LayerMask.GetMask(new string[] { "Objects", "Bounds" }));

            }
            else
            {
                hit = Physics2D.Raycast(RaycastPoint2.transform.position, -RaycastPoint.transform.right, 200000, LayerMask.GetMask(new string[] { "Objects", "Bounds" }));

            }

            if (Lasering)
            {
                line.SetPosition(0, RaycastPoint.transform.position);
                line.SetPosition(1, hit.point);
            }
        }

        public void FixedUpdate()
        {
            if (!Enabled)
                return;

            Vector2 hitPoint = hit.point;

            if (Lasering)
            {
                if (hit.collider != null)
                {
                    Mod.ModAPIPlus.SetPFXColors(ModAPI.CreateParticleEffect("Flash", hit.point), Color.yellow);
                    if (hit.collider.TryGetComponent<LimbBehaviour>(out var limb))
                    {
                        if (limb.Person != GetComponent<LimbBehaviour>().Person)
                        {
                            limb.Damage(limb.Health / 100);
                            limb.PhysicalBehaviour.Temperature += 1f;
                            limb.SkinMaterialHandler.AddDamagePoint(DamageType.Blunt, hit.point, 10);
                            if (hit.collider.TryGetComponent<Rigidbody2D>(out var rb) && hit.collider.GetComponent<SpriteRenderer>())
                            {
                                Vector2 direction = (hit.point - (Vector2)transform.position).normalized;
                                rb.AddForce(direction * maxForce, ForceMode2D.Impulse);
                            }
                        }
                    }
                    else
                    {
                        if (hit.collider.TryGetComponent<Rigidbody2D>(out var rb) && hit.collider.GetComponent<SpriteRenderer>())
                        {
                            Vector2 direction = (hit.point - (Vector2)transform.position).normalized;
                            rb.AddForce(direction * maxForce, ForceMode2D.Impulse);
                        }
                        else if (hit.collider.TryGetComponent<DestroyableBehaviour>(out var dest))
                        {
                            float dist = Vector2.Distance(dest.transform.position, hit.point);
                            if (dist < crushRadius)
                            {
                                dest.Break();
                            }
                        }
                    }
                }

                CameraShakeBehaviour.main.Shake(0.3f, transform.position);
            }
        }
    }

