    public class AbilityCycler : MonoBehaviour, Mod.ModAPIPlus.ISwap
    {
        public TargettedLimb targetPowers;
        public List<Power> powers = new List<Power>();

        public TextMeshProUGUI text;

        float cooldown;

        public void Start()
        {
            foreach (var power in transform.root.GetComponentsInChildren<Power>())
            {
                if (power.targetLimb == targetPowers)
                    if (!powers.Contains(power))
                        powers.Add(power);
            }

            var textTr = Instantiate(FakeNotifDissapearer.Start);
            text = textTr.GetComponentInChildren<TextMeshProUGUI>();
            try
            {
                text.text = powers.FirstOrDefault(p => p.Enabled).Name;
            }
            catch
            {
                text.text = "No Power";
            }

            textTr.GetComponent<GraphicRaycaster>().enabled = false;
            textTr.transform.parent = transform;

            if(transform.root.localScale.x < 0)
                textTr.transform.localScale = new Vector3(-0.4f, 0.4f, 0.4f);
            else
                textTr.transform.localScale = Vector3.one * 0.4f;

            textTr.AddComponent<ExistInDetailView>();
            textTr.gameObject.AddComponent<TextObject>();
        }

        public void UpdateText()
        {
            if(text == null)
                return;

            foreach (var power in transform.root.GetComponentsInChildren<Power>())
            {
                if (power.targetLimb == targetPowers)
                    if (!powers.Contains(power))
                        powers.Add(power);
            }

            try
            {
                text.text = powers.FirstOrDefault(p => p.Enabled).Name;
            }
            catch
            {
                text.text = "No Power";
            }
        }

        public void Swap()
        {
            foreach (var power in transform.root.GetComponentsInChildren<Power>())
            {
                if (power.targetLimb == targetPowers)
                    if (!powers.Contains(power))
                        powers.Add(power);
            }

            try
            {
                powers.First(a => a.Name == "No Power");
            }
            catch
            {
                var noPower = transform.root.GetComponentsInChildren<Power>().FirstOrDefault(a => a.Name == "No Power");
                if (noPower != null)
                {
                    powers.Add(noPower);
                }
            }

            if (powers.Count > 0)
            {
                int currentIndex = powers.FindIndex(p => p.Enabled);

                foreach (var power in powers)
                {
                    power.DisablePower();
                }

                if (currentIndex != -1)
                {
                    int nextIndex = (currentIndex + 1) % powers.Count;
                    powers[nextIndex].EnablePower();
                    FakeNotifDissapearer.CreateNotification(powers[nextIndex].Name, transform.position);

                    Debug.Log(powers[nextIndex].Name);
                    text.text = powers[nextIndex].Name;
                }
                else
                {
                    powers[0].EnablePower();
                    Debug.Log(powers[0].Name);
                    text.text = powers[0].Name;
                    FakeNotifDissapearer.CreateNotification(powers[0].Name, transform.position);
                }
            }
        }

        public class TextObject : MonoBehaviour
        {
            public void Update()
            {
                transform.rotation = Quaternion.identity;
                transform.position = transform.parent.position + new Vector3(0, 0.2f, 0);
            }
        }
    }

    public class HatBehaviour : MonoBehaviour, Messages.IOnGripped, Messages.IOnDrop
    {
        public FixedJoint2D joint;
        public bool canWear = false;
        public Sprite WearSprite;
        public Sprite UnwearSprite;
        public string OriginalObjectName;
        public string LimbName;

        public UnityEvent OnWear = new UnityEvent();
        public UnityEvent OnUnwear = new UnityEvent();

        public static HatBehaviour CreateHat(LimbBehaviour targetLimb, Sprite sprite, PhysicalProperties properties, Sprite HatHead = null)
        {
            var Hat = ModAPI.CreatePhysicalObject("Hat", sprite);
            Hat.GetComponent<PhysicalBehaviour>().Properties = properties;
            var hatbeh = HatBehaviour.AddHatStuff(targetLimb, Hat, HatHead);
            Destroy(Hat.GetComponent<BoxCollider2D>());
            Timtam.CreateCollider(Hat.GetComponent<SpriteRenderer>());
            return hatbeh;
        }

        public static HatBehaviour AddHatStuff(LimbBehaviour limb, GameObject hat, Sprite unweared = null)
        {
            var hatBehaviour = hat.AddComponent<HatBehaviour>();

            hatBehaviour.LimbName = limb.name;
            hatBehaviour.joint = hat.gameObject.AddComponent<FixedJoint2D>();
            hat.transform.localScale = limb.Person.transform.localScale;
            hat.transform.position = limb.transform.position;
            hat.transform.rotation = limb.transform.rotation;
            hat.gameObject.layer = 10;
            hatBehaviour.joint.connectedBody = limb.GetComponent<Rigidbody2D>();
            hatBehaviour.joint.autoConfigureConnectedAnchor = false;
            hatBehaviour.GetComponent<Rigidbody2D>().mass = 0.01f;
            hat.GetComponent<PhysicalBehaviour>().HoldingPositions = new Vector3[1];
            hat.GetComponent<PhysicalBehaviour>().HoldingPositions[0] = new Vector3(0, 0, 0);
            hat.GetComponent<SpriteRenderer>().sortingLayerName = limb.GetComponent<SpriteRenderer>().sortingLayerName;
            hat.GetComponent<SpriteRenderer>().sortingOrder = limb.GetComponent<SpriteRenderer>().sortingOrder + 1;
            hatBehaviour.OriginalObjectName = limb.Person.name;
            hatBehaviour.WearSprite = limb.GetComponent<SpriteRenderer>().sprite;
            hatBehaviour.UnwearSprite = unweared;
            limb.GetComponent<SpriteRenderer>().sprite = hatBehaviour.WearSprite;
            hat.GetComponent<PhysicalBehaviour>().colliders = hat.GetComponents<Collider2D>();
            //hat.AddComponent<DrawColliderzs>(); timtam smells if u see this
            hat.AddComponent<Undraggable>();
            foreach (var limbb in limb.Person.Limbs)
            {
                Physics2D.IgnoreCollision(limbb.GetComponent<Collider2D>(), hat.GetComponent<Collider2D>(), true);
            }

            return hatBehaviour;
        }

        public static HatBehaviour AddHatStuffNoLimb(string limbName, GameObject hat)
        {
            var hatBehaviour = hat.AddComponent<HatBehaviour>();

            hatBehaviour.LimbName = limbName;
            hat.gameObject.layer = 10;
            hatBehaviour.GetComponent<Rigidbody2D>().mass = 0.01f;
            hat.GetComponent<PhysicalBehaviour>().HoldingPositions = new Vector3[1];
            hat.GetComponent<PhysicalBehaviour>().HoldingPositions[0] = new Vector3(0, 0, 0);
            hat.GetComponent<PhysicalBehaviour>().colliders = hat.GetComponents<Collider2D>();
            hatBehaviour.canWear = true;
            return hatBehaviour;
        }

        public void Update()
        {
            if (joint && Time.timeScale < 0.1f)
            {
                transform.position = joint.connectedBody.transform.position;

                transform.rotation = joint.connectedBody.transform.rotation;
            }
        }

        public void FixedUpdate()
        {
            if (joint && joint.connectedBody == null)
                Destroy(gameObject);

            if (joint && joint.connectedBody != null)
            {
                if (!joint.connectedBody.gameObject.activeInHierarchy)
                {
                    Destroy(joint);
                    canWear = true;
                }
            }

            if (joint)
            {
                foreach (var limbb in joint.connectedBody.GetComponent<LimbBehaviour>().Person.Limbs)
                {
                    Physics2D.IgnoreCollision(limbb.GetComponent<Collider2D>(), GetComponent<Collider2D>(), true);
                }
            }

            if (canWear == false)
            {
                GetComponent<Rigidbody2D>().mass = 0.01f;
            }
            else
            {
                GetComponent<Rigidbody2D>().mass = 0.1f;
            }
        }

        public void OnGripped(GripBehaviour gripper)
        {
            Destroy(GetComponent<Undraggable>());
            if (joint.connectedBody.gameObject.GetComponent<LimbBehaviour>().Person.name == OriginalObjectName && UnwearSprite != null)
                joint.connectedBody.gameObject.GetComponent<SpriteRenderer>().sprite = UnwearSprite;
            GetComponent<PhysicalBehaviour>().Selectable = true;
            if (joint)
            {
                OnUnwear.Invoke();
                transform.position = joint.connectedBody.transform.position;
                transform.rotation = joint.connectedBody.transform.rotation;
            }
            Destroy(joint.GetComponent<HasHat>() ? joint.GetComponent<HasHat>() : null);
            Destroy(joint);
        }

        public void OnDrop(GripBehaviour gripper)
        {
            canWear = true;
            Collider2D[] collider2Ds = new Collider2D[10];
            Physics2D.OverlapCollider(GetComponent<Collider2D>(), new ContactFilter2D() { useTriggers = false, useLayerMask = false }, collider2Ds);
            bool foundHead = false;
            foreach (var hit in collider2Ds)
                if (hit.name.Contains(LimbName) && hit.TryGetComponent<LimbBehaviour>(out var limb))
                {
                    foundHead = true;
                    StartCoroutine(Wear(limb));
                    transform.localScale = joint.connectedBody.transform.root.localScale;
                    transform.position = joint.connectedBody.transform.position;
                    transform.rotation = joint.connectedBody.transform.rotation;
                    break;
                }
            if (!foundHead)
                StartCoroutine(ReenableCollision(joint.connectedBody.GetComponent<LimbBehaviour>().Person.Limbs.ToList()));
        }

        public IEnumerator ReenableCollision(List<LimbBehaviour> limbs)
        {
            yield return new WaitForSeconds(1f);
            foreach (var limb in limbs)
            {
                Physics2D.IgnoreCollision(limb.GetComponent<Collider2D>(), GetComponent<Collider2D>(), false);
            }
        }

        public void OnCollisionEnter2D(Collision2D col)
        {
            if (col.gameObject.TryGetComponent<LimbBehaviour>(out var limb) && canWear == true && joint == null)
                if (limb.name == LimbName)
                    StartCoroutine(Wear(limb));

            if (col.gameObject.GetComponent<HatBehaviour>())
                Physics2D.IgnoreCollision(col.collider, GetComponent<Collider2D>());
        }

        public IEnumerator Wear(LimbBehaviour limb)
        {
            yield return new WaitForEndOfFrame();
            foreach (var limbb in limb.Person.Limbs)
            {
                Physics2D.IgnoreCollision(limbb.GetComponent<Collider2D>(), GetComponent<Collider2D>(), true);
            }
            if (limb.Person.name == OriginalObjectName && WearSprite != null)
                limb.GetComponent<SpriteRenderer>().sprite = WearSprite;
            yield return null;
            transform.localScale = limb.Person.transform.localScale;
            transform.position = limb.transform.position;
            transform.rotation = limb.transform.rotation;
            joint = gameObject.AddComponent<FixedJoint2D>();
            joint.connectedBody = limb.GetComponent<Rigidbody2D>();
            gameObject.AddComponent<Undraggable>();
            GetComponent<PhysicalBehaviour>().Selectable = false;
            GetComponent<Rigidbody2D>().mass = 0.001f;
            GetComponent<SpriteRenderer>().sortingLayerName = limb.GetComponent<SpriteRenderer>().sortingLayerName;
            GetComponent<SpriteRenderer>().sortingOrder = limb.GetComponent<SpriteRenderer>().sortingOrder + 1;
            limb.gameObject.AddComponent<HasHat>().hat = this;
            canWear = false;
            OnWear.Invoke();
        }

        [SkipSerialisation]
        public class HasHat : MonoBehaviour
        {
            public HatBehaviour hat;
        }
    }

    public class AlternateMouseActivator : MonoBehaviour
    {
        public void Update()
        {
            if (InputSystem.Down("NovaKeyActivation"))
            {
                HashSet<GameObject> activatedThirdChildren = new HashSet<GameObject>();

                if (SelectionController.Main.CurrentlyUnderMouse != null)
                {
                    var underMouse = SelectionController.Main.CurrentlyUnderMouse;
                    if (underMouse.TryGetComponent<LimbBehaviour>(out var limb) && limb.name.Contains("LowerLeg"))
                    {
                        Transform thirdChild = underMouse.transform.parent.GetChild(2);
                        if (activatedThirdChildren.Add(thirdChild.gameObject) && !SelectionController.Main.SelectedObjects.Contains(thirdChild.GetComponent<PhysicalBehaviour>()))
                        {
                            foreach (var comp in thirdChild.GetComponentsInChildren<MonoBehaviour>())
                            {
                                if (comp is Mod.ModAPIPlus.IUse2 us)
                                {
                                    us.Use2();
                                }
                            }
                        }
                    }

                    foreach (var comp in underMouse.GetComponents<MonoBehaviour>())
                    {
                        if (comp is Mod.ModAPIPlus.IUse2 us &&
                            !(underMouse.TryGetComponent<LimbBehaviour>(out var lb) && lb.name.Contains("LowerLeg")))
                        {
                            us.Use2();
                        }
                    }
                }

                foreach (var hit in SelectionController.Main.SelectedObjects)
                {
                    if (hit.TryGetComponent<LimbBehaviour>(out var limb) && limb.name.Contains("LowerLeg"))
                    {
                        Transform thirdChild = hit.transform.parent.GetChild(2);
                        if (activatedThirdChildren.Add(thirdChild.gameObject) && !SelectionController.Main.SelectedObjects.Contains(thirdChild.GetComponent<PhysicalBehaviour>()))
                        {
                            foreach (var comp in thirdChild.GetComponentsInChildren<MonoBehaviour>())
                            {
                                if (comp is Mod.ModAPIPlus.IUse2 us)
                                {
                                    us.Use2();
                                }
                            }
                        }
                    }

                    foreach (var comp in hit.GetComponents<MonoBehaviour>())
                    {
                        if (comp is Mod.ModAPIPlus.IUse2 us &&
                            !(hit.TryGetComponent<LimbBehaviour>(out var lb) && lb.name.Contains("LowerLeg")) && hit != SelectionController.Main.CurrentlyUnderMouse)
                        {
                            us.Use2();
                        }
                    }
                }
            }

            if (InputSystem.Down("NovaSwapActivation"))
            {
                HashSet<GameObject> activatedThirdChildren = new HashSet<GameObject>();

                if (SelectionController.Main.CurrentlyUnderMouse != null)
                {
                    var underMouse = SelectionController.Main.CurrentlyUnderMouse;
                    if (underMouse.TryGetComponent<LimbBehaviour>(out var limb) && limb.name.Contains("LowerLeg"))
                    {
                        Transform thirdChild = underMouse.transform.parent.GetChild(2);
                        if (activatedThirdChildren.Add(thirdChild.gameObject) && !SelectionController.Main.SelectedObjects.Contains(thirdChild.GetComponent<PhysicalBehaviour>()))
                        {
                            foreach (var comp in thirdChild.GetComponentsInChildren<MonoBehaviour>())
                            {
                                if (comp is Mod.ModAPIPlus.ISwap us)
                                {
                                    us.Swap();
                                }
                            }
                        }
                    }

                    foreach (var comp in underMouse.GetComponents<MonoBehaviour>())
                    {
                        if (comp is Mod.ModAPIPlus.ISwap us &&
                            !(underMouse.TryGetComponent<LimbBehaviour>(out var lb) && lb.name.Contains("LowerLeg")))
                        {
                            us.Swap();
                        }
                    }
                }

                foreach (var hit in SelectionController.Main.SelectedObjects)
                {
                    if (hit.TryGetComponent<LimbBehaviour>(out var limb) && limb.name.Contains("LowerLeg"))
                    {
                        Transform thirdChild = hit.transform.parent.GetChild(2);
                        if (activatedThirdChildren.Add(thirdChild.gameObject) && !SelectionController.Main.SelectedObjects.Contains(thirdChild.GetComponent<PhysicalBehaviour>()))
                        {
                            foreach (var comp in thirdChild.GetComponentsInChildren<MonoBehaviour>())
                            {
                                if (comp is Mod.ModAPIPlus.ISwap us)
                                {
                                    us.Swap();
                                }
                            }
                        }
                    }

                    foreach (var comp in hit.GetComponents<MonoBehaviour>())
                    {
                        if (comp is Mod.ModAPIPlus.ISwap us &&
                            !(hit.TryGetComponent<LimbBehaviour>(out var lb) && lb.name.Contains("LowerLeg")) && hit != SelectionController.Main.CurrentlyUnderMouse)
                        {
                            us.Swap();
                        }
                    }
                }
            }
        }
    }

    public class Teleport : Power, Messages.IUse
    {
        public Teleportation teleportation;

        public static Power SetPower(PersonBehaviour Person, LimbBehaviour Limb, Sprite icon)
        {
            var power = Limb.gameObject.AddComponent<Teleport>();
            power.Name = "Teleportation";
            power.Description = "Activate the user's Head to allow them to teleport to the location of your mouse cursor when left click is pressed";
            power.icon = icon;

            power.targetLimb = TargettedLimb.Head;
            var teleportthing = new GameObject("teleportHandler" + UnityEngine.Random.Range(0, 200000));
            teleportthing.AddComponent<Teleportation>().person = Person;

            power.teleportation = teleportthing.GetComponent<Teleportation>();
            return power;
        }

        public override void Start()
        {
            foreach (var limb in GetComponent<LimbBehaviour>().Person.Limbs)
            {
                if (limb.HasJoint)
                {
                    limb.Joint.autoConfigureConnectedAnchor = false;
                }
            }
            base.Start();
        }

        public void Use(ActivationPropagation activation)
        {
            if (Enabled)
                teleportation.Use();
        }

        public class Teleportation : MonoBehaviour
        {
            public bool teleporting;
            public PersonBehaviour person;
            public GameObject Smoke;

            public void Start()
            {
                Smoke = Instantiate(ModAPI.FindSpawnable("Particle Projector").Prefab.transform.GetChild(0).gameObject);
                var pfx = Smoke.GetComponent<ParticleSystem>();
                pfx.playOnAwake = false;
                pfx.Stop();
                pfx.gravityModifier = 0;
                pfx.startSpeed = 0;
                pfx.startColor = new Color(0, 0.28f, 0, 0.102f);
            }

            public void Use()
            {
                ModAPI.CreateParticleEffect("Flash", person.Limbs[2].transform.position);
                Smoke.GetComponent<ParticleSystem>().Play();
                person.gameObject.SetActive(false);

                var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Summoning)");

                foreach (var status in limbStatusObjects)
                {
                    foreach (var limb in person.Limbs)
                    {
                        if (status.GetComponent<LimbStatusBehaviour>().limb == limb)
                        {
                            status.GetComponent<LimbStatusBehaviour>().enabled = false;
                            var color = status.GetComponent<SpriteRenderer>().color;
                            status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 0);
                            var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                            status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 0);
                        }
                    }
                }

                teleporting = true;
            }

            public void Update()
            {
                Vector3 mouseScreenPosition = Input.mousePosition;
                Smoke.transform.position = Camera.main.ScreenToWorldPoint(new Vector3(mouseScreenPosition.x, mouseScreenPosition.y, Camera.main.nearClipPlane));

                if (Input.GetKey(KeyCode.Mouse0) && teleporting)
                {
                    teleporting = false;
                    Smoke.GetComponent<ParticleSystem>().Stop();
                    CameraShakeBehaviour.main.Shake(1, person.Limbs[0].transform.position);
                    Vector3 mouseWorldPosition = Camera.main.ScreenToWorldPoint(new Vector3(mouseScreenPosition.x, mouseScreenPosition.y, Camera.main.nearClipPlane));

                    foreach (var limb in person.Limbs)
                    {
                        Vector3 newPosition = new Vector3(mouseWorldPosition.x, mouseWorldPosition.y, limb.transform.position.z);
                        limb.transform.position = newPosition;
                    }
                    person.gameObject.SetActive(true);
                    ModAPI.CreateParticleEffect("Flash", person.Limbs[2].transform.position).transform.localScale = new Vector3(2, 2, 2);
                    foreach (var limb in person.Limbs)
                    {
                        foreach (var limb2 in person.Limbs)
                        {
                            foreach (AudioSource aud in limb.GetComponents<AudioSource>())
                                aud.Stop();
                            Physics2D.IgnoreCollision(limb.GetComponent<Collider2D>(), limb2.GetComponent<Collider2D>());
                        }
                    }

                    var limbStatusObjects = Resources.FindObjectsOfTypeAll<GameObject>().Where(obj => obj.name == "Limb status(Summoning)");

                    foreach (var status in limbStatusObjects)
                    {
                        foreach (var limb in person.Limbs)
                        {
                            if (status.GetComponent<LimbStatusBehaviour>().limb == limb)
                            {
                                status.GetComponent<LimbStatusBehaviour>().enabled = true;
                                var color = status.GetComponent<SpriteRenderer>().color;
                                status.GetComponent<SpriteRenderer>().color = new Color(color.r, color.g, color.b, 1);
                                var color2 = status.transform.GetChild(0).GetComponent<SpriteRenderer>().color;
                                status.transform.GetChild(0).GetComponent<SpriteRenderer>().color = new Color(color2.r, color2.g, color2.b, 1);
                            }
                        }
                    }
                }
            }

        }
    }

    public class WebWireFixer : MonoBehaviour
    {
        public float OGDistance;
        public float OGStrength;
        public SpringJoint2D springJoint;

        public void Start()
        {
            OGDistance = springJoint ? springJoint.distance : 0;
            OGStrength = springJoint ? springJoint.frequency : 1;
        }

        public void Update()
        {
            if (!springJoint)
                return;

            float currentDistance = Vector2.Distance(transform.position, springJoint.connectedAnchor);

            if (springJoint.connectedBody)
                currentDistance = Vector2.Distance(transform.position, springJoint.connectedBody.transform.TransformPoint(springJoint.connectedAnchor));

            if (currentDistance < OGDistance)
            {
                springJoint.frequency = 0.0001f;
            }
            else
                springJoint.frequency = OGStrength;
        }
    }

    public class FakeNotifDissapearer : MonoBehaviour
    {
        private float fadeSpeed = 0.8f;
        private float lastAlpha = 1f;
        public static GameObject Start;

        public static void CreateNotification(string text, Vector2 pos)
        {
            var notif = Instantiate(Start);
            notif.GetComponent<GraphicRaycaster>().enabled = false;
            notif.GetComponentInChildren<TextMeshProUGUI>().text = text;
            notif.AddComponent<FakeNotifDissapearer>();
            notif.transform.position = pos;
        }

        public void Update()
        {
            var sr = GetComponentInChildren<TextMeshProUGUI>();
            var sa = GetComponent<SpriteRenderer>();

            Color targetColor = new Color(1, 1, 1, 0);

            if (sr)
            {
                if (sr.color.a > 0.01f)
                {
                    // Use unscaledDeltaTime to ignore timescale
                    sr.color = Color.Lerp(sr.color, targetColor, fadeSpeed * Time.unscaledDeltaTime * 10f);
                    lastAlpha = sr.color.a;
                }
                else
                {
                    Destroy(gameObject);
                }
            }
            else
            {
                if (sa.color.a > 0.01f)
                {
                    // Use unscaledDeltaTime to ignore timescale
                    sa.color = Color.Lerp(sa.color, targetColor, fadeSpeed * Time.unscaledDeltaTime * 10f);
                    lastAlpha = sa.color.a;
                }
                else
                {
                    Destroy(gameObject);
                }
            }


        }
    }

